import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import { ChevronRight } from 'lucide-react';
import { cn } from '@/lib/utils';
import { fadeInUp } from '../lib/animation-variants';

/**
 * Consistent page header with breadcrumbs, title, subtitle, and optional action buttons.
 *
 * @param {string}  title
 * @param {string}  [subtitle]
 * @param {Array<{label:string, to?:string}>} [breadcrumbs]
 * @param {React.ReactNode} [actions] ΓÇô Right-side buttons / controls
 */
export default function PageHeader({ title, subtitle, breadcrumbs, actions, className }) {
  return (
    <motion.div
      {...fadeInUp}
      className={cn('mb-6 flex flex-col gap-2 sm:flex-row sm:items-end sm:justify-between sm:gap-4', className)}
    >
      <div>
        {breadcrumbs && breadcrumbs.length > 0 && (
          <nav className="mb-2 flex items-center gap-1 text-xs uppercase tracking-[0.2em] text-muted-foreground">
            {breadcrumbs.map((crumb, i) => (
              <span key={i} className="flex items-center gap-1">
                {i > 0 && <ChevronRight className="h-3.5 w-3.5 shrink-0" />}
                {crumb.to ? (
                  <Link to={crumb.to} className="hover:text-foreground transition-colors">
                    {crumb.label}
                  </Link>
                ) : (
                  <span className="text-foreground font-medium">{crumb.label}</span>
                )}
              </span>
            ))}
          </nav>
        )}
        <h1 className="text-2xl font-semibold tracking-tight text-foreground sm:text-3xl">{title}</h1>
        {subtitle && <p className="mt-1 text-sm text-muted-foreground max-w-2xl">{subtitle}</p>}
      </div>

      {actions && <div className="flex flex-wrap items-center gap-2 pt-2 sm:pt-0">{actions}</div>}
    </motion.div>
  );
}

import { motion, useMotionValue, useTransform, animate } from 'framer-motion';
import { useEffect } from 'react';
import { cn } from '@/lib/utils';
import { staggerItem } from '../lib/animation-variants';

/**
 * Enterprise stat card with animated counter and accent stripe.
 *
 * @param {string}  title       ΓÇô Short label
 * @param {number}  value       ΓÇô Numeric value (animates from 0)
 * @param {string}  [subtitle]  ΓÇô Description text
 * @param {React.ElementType} [icon] ΓÇô Lucide icon component
 * @param {'default'|'success'|'warning'|'danger'|'info'} [variant]
 * @param {string}  [prefix]    ΓÇô e.g. "Γé╣"
 * @param {string}  [suffix]    ΓÇô e.g. "%"
 * @param {boolean} [loading]
 */
export default function StatCard({
  title,
  value,
  subtitle,
  icon: Icon,
  variant = 'default',
  prefix = '',
  suffix = '',
  loading = false,
  className,
}) {
  const motionValue = useMotionValue(0);
  const rounded = useTransform(motionValue, (v) => Math.round(v));

  useEffect(() => {
    if (loading || value === undefined || value === null) return;
    const num = typeof value === 'number' ? value : Number(value) || 0;
    const controls = animate(motionValue, num, {
      duration: 1.2,
      ease: [0.25, 0.46, 0.45, 0.94],
    });
    return controls.stop;
  }, [value, loading, motionValue]);

  const accentColors = {
    default: 'from-primary/30 via-primary/10 to-transparent',
    success: 'from-emerald-400/30 via-emerald-400/10 to-transparent',
    warning: 'from-amber-400/30 via-amber-400/10 to-transparent',
    danger: 'from-rose-400/30 via-rose-400/10 to-transparent',
    info: 'from-sky-400/30 via-sky-400/10 to-transparent',
  };

  const barColors = {
    default: 'from-primary to-secondary',
    success: 'from-emerald-400 to-emerald-600',
    warning: 'from-amber-400 to-amber-600',
    danger: 'from-rose-400 to-rose-600',
    info: 'from-sky-400 to-sky-600',
  };

  const iconBgColors = {
    default: 'bg-primary/15 text-primary',
    success: 'bg-emerald-500/15 text-emerald-600',
    warning: 'bg-amber-500/15 text-amber-600',
    danger: 'bg-rose-500/15 text-rose-600',
    info: 'bg-sky-500/15 text-sky-600',
  };

  return (
    <motion.div
      variants={staggerItem}
      className={cn(
        'relative overflow-hidden rounded-2xl border border-border bg-card p-5 shadow-sm transition-shadow duration-300 hover:shadow-lg',
        className
      )}
    >
      {/* accent haze */}
      <div className={cn('absolute inset-0 bg-gradient-to-br', accentColors[variant])} />

      <div className="relative flex items-start justify-between gap-3">
        <div className="min-w-0 flex-1">
          <p className="text-xs font-semibold uppercase tracking-[0.22em] text-muted-foreground truncate">{title}</p>
          {loading ? (
            <div className="mt-2 h-8 w-20 rounded-lg bg-muted animate-shimmer" />
          ) : (
            <p className="mt-2 text-3xl font-bold tracking-tight text-foreground">
              {prefix}
              <motion.span>{rounded}</motion.span>
              {suffix}
            </p>
          )}
          {subtitle && <p className="mt-1 text-xs text-muted-foreground">{subtitle}</p>}
        </div>

        {Icon && (
          <div className={cn('flex h-11 w-11 items-center justify-center rounded-2xl', iconBgColors[variant])}>
            <Icon className="h-5 w-5" />
          </div>
        )}
      </div>

      <div className="relative mt-4 h-1.5 w-full overflow-hidden rounded-full bg-muted">
        <div className={cn('h-full w-2/3 rounded-full bg-gradient-to-r', barColors[variant])} />
      </div>
    </motion.div>
  );
}

import { useState } from 'react';
import { Outlet, Navigate, useLocation } from 'react-router-dom';
import { useSelector } from 'react-redux';
import Sidebar from './Sidebar';
import Navbar from './Navbar';
import { AnimatePresence } from 'framer-motion';
import { motion } from 'framer-motion';

export default function DashboardLayout({ allowedRoles }) {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const location = useLocation();
  const { user, isAuthenticated } = useSelector((state) => state.auth);

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user?.role)) {
    return <Navigate to="/unauthorized" replace />;
  }

  const toggleSidebar = () => {
    setIsSidebarOpen(prev => !prev);
  };

  return (
    <div className="flex h-screen overflow-hidden doccure-shell">
      <Sidebar isOpen={isSidebarOpen} />

      <div className="flex flex-col flex-1 w-full overflow-hidden">
        <Navbar toggleSidebar={toggleSidebar} />

        <main className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 relative">
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -15 }}
              transition={{ duration: 0.2 }}
              className="w-full max-w-7xl mx-auto space-y-6"
            >
              <Outlet />
            </motion.div>
          </AnimatePresence>
        </main>
      </div>
    </div>
  );
}

import { NavLink, Outlet, useNavigate, Link } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { useState } from 'react';
import { motion } from 'framer-motion';
import {
  LayoutDashboard, Users, UserCog, Stethoscope, Calendar, CreditCard,
  BedDouble, Building2, MapPin, Award, Settings, ShieldCheck,
  LogOut, Menu, X, Bell, User, ChevronRight, Heart,
  ClipboardList, FlaskConical, Pill, NotepadText, Activity,
  FileBarChart, Clock, PanelLeftClose, PanelLeft
} from 'lucide-react';
import { logout } from '../../store/authSlice.js';
import { STAFF_MANAGEMENT_ROLES, getEmployeeHomeRoute, getRoleLabel } from '../../auth/constants.js';
import { pageVariants } from '../../lib/animation-variants.js';
import { ScrollArea } from '../ui/scroll-area.jsx';
import { Avatar, AvatarFallback, AvatarImage } from '../ui/avatar.jsx';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu";
import ThemeToggle from '../ThemeToggle.jsx';

const buildNavItems = (role, homeRoute) => {
  const canManageUsers = STAFF_MANAGEMENT_ROLES.includes(role);
  const canAccessGovernance = ['superadmin', 'admin'].includes(role);
  const canManageDoctors = ['superadmin', 'admin'].includes(role);

  const sections = [];

  // Dashboard section
  sections.push({
    label: 'Overview',
    items: [{ to: homeRoute, label: `Dashboard`, icon: LayoutDashboard }],
  });

  // Role-specific sections
  if (role === 'receptionist') {
    sections.push({
      label: 'Front Desk',
      items: [
        { to: '/employee/receptionist/register-patient', label: 'Register Patient', icon: Users },
        { to: '/employee/receptionist/appointments', label: 'Book Appointment', icon: Calendar },
        { to: '/employee/receptionist/queue', label: 'Today Queue', icon: Clock },
        { to: '/employee/receptionist/patients', label: 'Search Patients', icon: Users },
        { to: '/employee/billing', label: 'Billing', icon: CreditCard },
      ],
    });
  }

  if (role === 'labTechnician') {
    sections.push({
      label: 'Diagnostics',
      items: [
        { to: '/employee/lab-technician/orders', label: 'Lab Orders', icon: FlaskConical },
        { to: '/employee/lab-technician/processing', label: 'Processing Queue', icon: Activity },
        { to: '/employee/lab-technician/completed', label: 'Ready Reports', icon: FileBarChart },
      ],
    });
  }

  if (role === 'pharmacist') {
    sections.push({
      label: 'Pharmacy',
      items: [
        { to: '/employee/pharmacist/orders', label: 'Pharmacy Orders', icon: Pill },
        { to: '/employee/pharmacist/inventory', label: 'Inventory', icon: ClipboardList },
        { to: '/employee/pharmacist/history', label: 'Order History', icon: Clock },
      ],
    });
  }

  if (role === 'nurse') {
    sections.push({
      label: 'Nursing Station',
      items: [
        { to: '/employee/nurse/patients', label: 'Assigned Patients', icon: Users },
        { to: '/employee/nurse/ward-board', label: 'Ward Board', icon: BedDouble },
        { to: '/employee/nurse/tasks', label: 'Tasks', icon: ClipboardList },
        { to: '/employee/nurse/vitals', label: 'Vitals', icon: Activity },
        { to: '/employee/nurse/notes', label: 'Notes', icon: NotepadText },
        { to: '/employee/nurse/handover', label: 'Handover', icon: ChevronRight },
      ],
    });
  }

  if (canManageUsers) {
    sections.push({
      label: 'Staff',
      items: [{ to: '/employee/manage-roles', label: 'Manage Roles', icon: UserCog }],
    });
  }

  if (canManageDoctors) {
    sections.push({
      label: 'Clinical',
      items: [
        { to: '/employee/doctors', label: 'Doctors', icon: Stethoscope },
        { to: '/employee/doctor-availability', label: 'Doctor Availability', icon: Calendar },
        ...(canAccessGovernance ? [{ to: '/employee/patients', label: 'Patients', icon: Users }] : []),
        ...(canAccessGovernance ? [{ to: '/employee/billing', label: 'Billing', icon: CreditCard }] : []),
      ],
    });
  }

  if (canAccessGovernance) {
    sections.push({
      label: 'Operations',
      items: [
        { to: '/employee/wards', label: 'Wards', icon: BedDouble },
        { to: '/employee/beds', label: 'Beds', icon: BedDouble },
        { to: '/employee/admissions', label: 'Admissions', icon: Users },
        { to: '/employee/departments', label: 'Departments', icon: Building2 },
        { to: '/employee/specializations', label: 'Specializations', icon: Stethoscope },
        { to: '/employee/locations', label: 'Locations', icon: MapPin },
        { to: '/employee/awards', label: 'Awards', icon: Award },
      ],
    });
    sections.push({
      label: 'System',
      items: [
        { to: '/employee/audit', label: 'Audit History', icon: ShieldCheck },
        { to: '/employee/settings', label: 'Settings', icon: Settings },
      ],
    });
  }

  // Common
  sections.push({
    label: 'Account',
    items: [
      { to: '/employee/profile', label: 'Profile', icon: User },
      { to: '/employee/notifications', label: 'Notifications', icon: Bell },
    ],
  });

  return sections;
};

const sidebarLinkClass = ({ isActive }) =>
  `group flex items-center gap-2.5 rounded-lg px-3 py-2 text-sm transition-all ${
    isActive
      ? 'bg-sidebar-primary text-sidebar-primary-foreground font-semibold shadow-sm'
      : 'text-sidebar-foreground/70 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground'
  }`;

export default function EmployeeAppLayout() {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const user = useSelector((state) => state.auth.user);
  const homeRoute = getEmployeeHomeRoute(user?.role);
  const navSections = buildNavItems(user?.role, homeRoute);
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  const handleLogout = () => {
    dispatch(logout());
    localStorage.removeItem('mediflow_auth');
    navigate('/employee/login');
  };

  const SidebarInner = ({ isMobile = false }) => (
    <div className="flex h-full flex-col">
      {/* Logo */}
      <div className="flex items-center justify-between px-4 py-5 border-b border-sidebar-border">
        <Link to={homeRoute} className="flex items-center gap-2">
          <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-sidebar-primary">
            <Heart className="h-4 w-4 text-sidebar-primary-foreground" />
          </div>
          {(!collapsed || isMobile) && (
            <div>
              <p className="text-sm font-bold text-sidebar-foreground">MediFlow</p>
              <p className="text-[9px] uppercase tracking-[0.15em] text-sidebar-foreground/50">Staff Portal</p>
            </div>
          )}
        </Link>
        {!isMobile && (
          <button
            onClick={() => setCollapsed(!collapsed)}
            className="hidden lg:flex items-center justify-center h-7 w-7 rounded-md hover:bg-sidebar-accent text-sidebar-foreground/50 hover:text-sidebar-foreground transition-colors"
          >
            {collapsed ? <PanelLeft className="h-4 w-4" /> : <PanelLeftClose className="h-4 w-4" />}
          </button>
        )}
      </div>

      {/* Profile block */}
      {(!collapsed || isMobile) && (
        <div className="mx-4 mt-4 rounded-2xl border border-sidebar-border bg-sidebar-accent/50 p-4">
          <div className="flex items-center gap-3">
            <Avatar className="h-11 w-11 border border-sidebar-border">
              <AvatarImage src={user?.profileImage || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name || 'Employee'}`} />
              <AvatarFallback>{user?.name?.charAt(0) || 'E'}</AvatarFallback>
            </Avatar>
            <div>
              <p className="text-sm font-semibold text-sidebar-foreground">{user?.name || 'Employee'}</p>
              <p className="text-xs text-sidebar-foreground/60">{user?.employeeId ? `ID: ${user.employeeId}` : getRoleLabel(user?.role)}</p>
            </div>
          </div>
        </div>
      )}

      {/* Nav sections */}
      <ScrollArea className="flex-1 py-4 px-3">
        {navSections.map((section) => (
          <div key={section.label} className="mb-4">
            {(!collapsed || isMobile) && (
              <p className="mb-1.5 px-3 text-[10px] font-semibold uppercase tracking-[0.15em] text-sidebar-foreground/40">
                {section.label}
              </p>
            )}
            <div className="space-y-0.5">
              {section.items.map((item) => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  className={sidebarLinkClass}
                  onClick={isMobile ? () => setMobileOpen(false) : undefined}
                  title={collapsed ? item.label : undefined}
                >
                  <item.icon className="h-4 w-4 shrink-0" />
                  {(!collapsed || isMobile) && <span>{item.label}</span>}
                </NavLink>
              ))}
            </div>
          </div>
        ))}
      </ScrollArea>

      {/* User info + logout */}
      <div className="border-t border-sidebar-border px-3 py-3">
        <button
          onClick={handleLogout}
          className="flex w-full items-center gap-2.5 rounded-lg px-3 py-2 text-sm text-sidebar-foreground/60 transition-colors hover:bg-red-500/10 hover:text-red-400"
          title="Sign out"
        >
          <LogOut className="h-4 w-4 shrink-0" />
          {(!collapsed || isMobile) && <span>Sign Out</span>}
        </button>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen doccure-shell">
      {/* Desktop sidebar */}
      <aside
        className={`hidden lg:flex flex-col border-r border-sidebar-border bg-sidebar transition-all duration-300 ${
          collapsed ? 'w-[68px]' : 'w-[260px]'
        }`}
      >
        <SidebarInner />
      </aside>

      {/* Mobile sidebar overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 z-50 lg:hidden">
          <div className="absolute inset-0 bg-black/50" onClick={() => setMobileOpen(false)} />
          <motion.aside
            initial={{ x: -280 }}
            animate={{ x: 0 }}
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            className="absolute left-0 top-0 bottom-0 z-50 w-[260px] flex flex-col bg-sidebar shadow-2xl"
          >
            <SidebarInner isMobile />
          </motion.aside>
        </div>
      )}

      {/* Main area */}
      <div className="flex min-h-screen flex-1 flex-col">
        {/* Top header */}
        <header className="sticky top-0 z-30 border-b border-border bg-card/90 backdrop-blur-xl">
          <div className="flex items-center justify-between px-4 py-4 sm:px-6">
            <div className="flex items-center gap-3">
              <button
                type="button"
                onClick={() => setMobileOpen(!mobileOpen)}
                className="flex items-center justify-center h-10 w-10 rounded-xl border border-border bg-card hover:bg-muted transition-colors lg:hidden"
              >
                <Menu className="h-5 w-5" />
              </button>
              <div>
                <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">{getRoleLabel(user?.role)} Workspace</p>
                <h2 className="text-base font-semibold text-foreground">{user?.name || 'Employee'}</h2>
              </div>
            </div>
            <div className="hidden md:flex items-center gap-3">
              <input
                type="search"
                placeholder="Search staff, patients, or modules"
                className="h-10 w-[280px] rounded-full border border-border bg-card px-4 text-sm text-foreground shadow-sm placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring/30"
              />
            </div>
            <div className="flex items-center gap-2">
              <ThemeToggle />
              <NavLink
                to="/employee/notifications"
                className="flex items-center justify-center h-10 w-10 rounded-xl border border-border bg-card hover:bg-muted transition-colors"
              >
                <Bell className="h-4 w-4 text-muted-foreground" />
              </NavLink>
              <DropdownMenu>
                <DropdownMenuTrigger className="flex items-center gap-2 rounded-full border border-border bg-card px-2 py-1.5 shadow-sm outline-none">
                  <Avatar className="h-7 w-7">
                    <AvatarImage src={user?.profileImage || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name || 'Employee'}`} />
                    <AvatarFallback>{user?.name?.charAt(0) || 'E'}</AvatarFallback>
                  </Avatar>
                  <span className="hidden text-sm font-semibold text-foreground sm:inline">{user?.name || 'Employee'}</span>
                  <ChevronRight className="h-4 w-4 text-muted-foreground" />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-48">
                  <DropdownMenuItem className="cursor-pointer p-0">
                    <NavLink to="/employee/profile" className="w-full px-2 py-1.5">Profile</NavLink>
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem
                    className="cursor-pointer text-destructive focus:bg-destructive/10 focus:text-destructive"
                    onClick={handleLogout}
                  >
                    Sign out
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </header>

        <motion.main
          variants={pageVariants}
          initial="initial"
          animate="animate"
          className="flex-1 px-4 py-6 sm:px-6 lg:px-8"
        >
          <Outlet />
        </motion.main>
      </div>
    </div>
  );
}

import { NavLink, Outlet, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { motion } from 'framer-motion';
import {
  LayoutDashboard, Calendar, FileText, Pill, FlaskConical, ClipboardList,
  CreditCard, Clock, User, Bell, LogOut, Heart, ChevronRight, Menu, X,
} from 'lucide-react';
import { useEffect, useState } from 'react';
import { logout } from '../../store/authSlice.js';
import { pageVariants } from '../../lib/animation-variants.js';
import { Avatar, AvatarFallback, AvatarImage } from '../ui/avatar.jsx';
import logoImg from '../../assets/logo.png';
import ThemeToggle from '../ThemeToggle.jsx';
import { userApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "../ui/dropdown-menu";

const NAV_ITEMS = [
  { to: '/patient/dashboard', label: 'Dashboard', icon: LayoutDashboard, desc: 'Overview and care status' },
  { to: '/patient/book-appointment', label: 'Book Appointment', icon: Calendar, desc: 'New visit booking' },
  { to: '/patient/appointments', label: 'Appointments', icon: Calendar, desc: 'Visits and scheduling' },
  { to: '/patient/prescriptions', label: 'Prescriptions', icon: FileText, desc: 'Active medicines' },
  { to: '/patient/medicine-orders', label: 'Medicine Orders', icon: Pill, desc: 'Pharmacy orders' },
  { to: '/patient/lab-tests', label: 'Lab Tests', icon: FlaskConical, desc: 'Ordered tests' },
  { to: '/patient/lab-reports', label: 'Lab Reports', icon: ClipboardList, desc: 'Released reports' },
  { to: '/patient/bills', label: 'Bills & Payments', icon: CreditCard, desc: 'Invoices and payments' },
  { to: '/patient/history', label: 'Medical History', icon: Clock, desc: 'Timeline of care' },
  { to: '/patient/profile', label: 'Profile', icon: User, desc: 'Personal details' },
  { to: '/patient/notifications', label: 'Notifications', icon: Bell, desc: 'Care alerts' },
];

const navLinkClass = ({ isActive }) =>
  `group flex w-full items-center gap-3 rounded-full px-4 py-2.5 text-sm transition-all ${
    isActive
      ? 'bg-primary text-primary-foreground font-semibold shadow-sm'
      : 'text-muted-foreground hover:bg-muted hover:text-foreground'
  }`;

export default function PatientPortalLayout() {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const user = useSelector((state) => state.auth.user);
  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
  const [resetOpen, setResetOpen] = useState(false);
  const [resetStep, setResetStep] = useState('notice');
  const [resetForm, setResetForm] = useState({ newPassword: '', confirmPassword: '', loading: false });

  const handleLogout = () => {
    dispatch(logout());
    localStorage.removeItem('mediflow_auth');
    navigate('/patient/login');
  };

  useEffect(() => {
    if (user?.mustResetPassword) {
      setResetOpen(true);
      setResetStep('notice');
    }
  }, [user?.mustResetPassword]);

  const handleForceReset = async (event) => {
    event.preventDefault();
    if (resetForm.newPassword.length < 6) {
      toast.error('Password must be at least 6 characters.');
      return;
    }
    if (resetForm.newPassword !== resetForm.confirmPassword) {
      toast.error('Passwords do not match.');
      return;
    }
    setResetForm((prev) => ({ ...prev, loading: true }));
    try {
      await userApi.changePassword({ newPassword: resetForm.newPassword });
      toast.success('Password updated. Please sign in again.');
      handleLogout();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to update password.');
    } finally {
      setResetForm((prev) => ({ ...prev, loading: false }));
    }
  };

  const SidebarContent = () => (
    <div className="flex h-full min-h-0 flex-col">
      {/* Brand (removed as requested) */}

      {/* Nav links */}
      <nav className="flex-1 min-h-0 space-y-1 overflow-y-auto pr-1 pb-3 overflow-x-hidden">
        {NAV_ITEMS.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={navLinkClass}
            onClick={() => setMobileSidebarOpen(false)}
          >
            <item.icon className="h-4 w-4 shrink-0" />
            <span className="min-w-0 truncate">{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* Logout */}
      <div className="mt-4 pt-4 border-t border-border">
        <button
          type="button"
          onClick={handleLogout}
          className="flex w-full items-center gap-3 rounded-full px-4 py-2.5 text-sm text-muted-foreground transition-colors hover:bg-destructive/10 hover:text-destructive"
        >
          <LogOut className="h-4 w-4" />
          Sign Out
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen doccure-shell">
      {/* Top header */}
      <header className="sticky top-0 z-30 border-b border-border bg-card/90 backdrop-blur-xl">
        <div className="mx-auto flex max-w-[1400px] items-center justify-between px-4 py-4 sm:px-6">
          <div className="flex items-center gap-3">
            <button
              type="button"
              onClick={() => setMobileSidebarOpen(!mobileSidebarOpen)}
              className="flex items-center justify-center h-10 w-10 rounded-xl border border-border bg-card hover:bg-muted transition-colors lg:hidden"
            >
              {mobileSidebarOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
            </button>
            <div className="flex items-center gap-2.5">
              <img src={logoImg} alt="Hospital logo" className="h-9 w-auto" />
              <div>
                <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">MediFlow Hospital</p>
                <h2 className="text-base font-semibold text-foreground">Patient Portal</h2>
              </div>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-3">
            <div className="relative">
              <input
                type="search"
                placeholder="Search appointments, bills, or doctors"
                className="h-10 w-[260px] rounded-full border border-border bg-card px-4 text-sm text-foreground shadow-sm placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring/30"
              />
            </div>
          </div>

          <div className="flex items-center gap-2">
            <ThemeToggle />
            <NavLink
              to="/patient/notifications"
              className="relative flex items-center justify-center h-10 w-10 rounded-xl border border-border bg-card hover:bg-muted transition-colors"
            >
              <Bell className="h-4 w-4 text-muted-foreground" />
            </NavLink>
            <DropdownMenu>
              <DropdownMenuTrigger className="flex items-center gap-2 rounded-full border border-border bg-card px-2 py-1.5 shadow-sm max-w-[220px] outline-none">
                <Avatar className="h-7 w-7">
                  <AvatarImage src={user?.profileImage || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name || 'Patient'}`} />
                  <AvatarFallback>{user?.name?.charAt(0) || 'P'}</AvatarFallback>
                </Avatar>
                <span className="hidden text-sm font-semibold text-foreground sm:inline truncate">{user?.name || 'Patient'}</span>
                <ChevronRight className="h-4 w-4 text-muted-foreground" />
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-48">
                <DropdownMenuItem className="cursor-pointer p-0">
                  <NavLink to="/patient/profile" className="w-full px-2 py-1.5">Profile</NavLink>
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem className="cursor-pointer text-destructive focus:bg-destructive/10 focus:text-destructive" onClick={handleLogout}>
                  Sign out
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>
      </header>

      <div className="mx-auto flex max-w-[1400px] flex-col gap-6 px-4 py-6 sm:px-6 lg:flex-row">
        {/* Desktop sidebar */}
        <aside className="hidden lg:flex lg:flex-col w-[280px] rounded-3xl border border-border bg-card p-5 shadow-sm sticky top-[88px] h-[calc(100vh-120px)] overflow-hidden">
          <div className="doccure-card-soft p-4 mb-5">
            <div className="flex items-center gap-3">
              <Avatar className="h-12 w-12 border border-border">
                <AvatarImage src={user?.profileImage || `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.name || 'Patient'}`} />
                <AvatarFallback>{user?.name?.charAt(0) || 'P'}</AvatarFallback>
              </Avatar>
              <div>
                <p className="text-sm font-semibold text-foreground truncate">{user?.name || 'Patient'}</p>
                <p className="text-xs text-muted-foreground">{user?.patientId ? `ID: ${user.patientId}` : 'Patient ID pending'}</p>
              </div>
            </div>
            <div className="mt-4 flex flex-wrap gap-2">
              <span className="doccure-chip">Care plan</span>
              <span className="doccure-chip">Lab updates</span>
            </div>
            <NavLink
              to="/patient/book-appointment"
              className="mt-4 inline-flex w-full items-center justify-center rounded-full bg-primary px-4 py-2 text-sm font-semibold text-primary-foreground shadow-sm transition hover:brightness-110"
            >
              Book appointment
            </NavLink>
          </div>
          <SidebarContent />
        </aside>

        {/* Mobile sidebar overlay */}
        {mobileSidebarOpen && (
          <div className="fixed inset-0 z-40 lg:hidden">
            <div className="absolute inset-0 bg-black/40" onClick={() => setMobileSidebarOpen(false)} />
            <motion.aside
              initial={{ x: -280 }}
              animate={{ x: 0 }}
              exit={{ x: -280 }}
              transition={{ type: 'spring', stiffness: 300, damping: 30 }}
              className="absolute left-0 top-0 bottom-0 z-50 w-[280px] flex flex-col bg-card p-4 shadow-xl border-r border-border overflow-hidden"
            >
              <SidebarContent />
            </motion.aside>
          </div>
        )}

        {/* Main content */}
        <motion.main variants={pageVariants} initial="initial" animate="animate" className="flex-1 min-w-0">
          <Outlet />
        </motion.main>
      </div>

      {resetOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <div className="w-full max-w-md rounded-2xl bg-card p-6 shadow-2xl">
            {resetStep === 'notice' ? (
              <>
                <h3 className="text-xl font-semibold text-foreground">Password update required</h3>
                <p className="mt-2 text-sm text-muted-foreground">
                  For security, please set a new password before continuing to the portal.
                </p>
                <div className="mt-6 flex gap-3">
                  <button
                    type="button"
                    className="flex-1 rounded-xl border border-border px-4 py-2.5 text-sm font-semibold text-foreground hover:bg-muted"
                    onClick={() => setResetStep('form')}
                  >
                    Set new password
                  </button>
                  <button
                    type="button"
                    className="flex-1 rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground"
                    onClick={() => setResetStep('form')}
                  >
                    Continue
                  </button>
                </div>
              </>
            ) : (
              <form onSubmit={handleForceReset} className="space-y-4">
                <h3 className="text-xl font-semibold text-foreground">Create a new password</h3>
                <div>
                  <label className="mb-1.5 block text-sm font-medium text-foreground">New password</label>
                  <input
                    type="password"
                    value={resetForm.newPassword}
                    onChange={(e) => setResetForm((prev) => ({ ...prev, newPassword: e.target.value }))}
                    className="w-full rounded-xl border border-border bg-card px-4 py-2.5 text-sm text-foreground outline-none focus:border-primary"
                  />
                </div>
                <div>
                  <label className="mb-1.5 block text-sm font-medium text-foreground">Confirm password</label>
                  <input
                    type="password"
                    value={resetForm.confirmPassword}
                    onChange={(e) => setResetForm((prev) => ({ ...prev, confirmPassword: e.target.value }))}
                    className="w-full rounded-xl border border-border bg-card px-4 py-2.5 text-sm text-foreground outline-none focus:border-primary"
                  />
                </div>
                <button
                  type="submit"
                  disabled={resetForm.loading}
                  className="w-full rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground disabled:opacity-60"
                >
                  {resetForm.loading ? 'Updating...' : 'Update password'}
                </button>
              </form>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Link, NavLink } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X } from 'lucide-react';
import logoImg from '../../assets/logo.png';
import { PUBLIC_NAV_ITEMS } from '../../patient/constants.js';

const navLinkClass = ({ isActive }) =>
  isActive
    ? 'text-primary font-semibold relative after:absolute after:bottom-0 after:left-0 after:w-full after:h-0.5 after:bg-primary after:rounded-full'
    : 'text-muted-foreground hover:text-foreground transition-colors relative';

export default function PublicSiteNavbar() {
  const { isAuthenticated, sessionType, user } = useSelector((state) => state.auth);
  const portalRoute =
    sessionType === 'patient' && user?.role === 'patient'
      ? '/patient/dashboard'
      : '/patient/login';
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <>
      <motion.header
        initial={false}
        animate={scrolled ? 'solid' : 'transparent'}
        variants={{
          transparent: { backgroundColor: 'rgba(255,255,255,0.6)', backdropFilter: 'blur(8px)' },
          solid: { backgroundColor: 'rgba(255,255,255,0.92)', backdropFilter: 'blur(20px)' },
        }}
        transition={{ duration: 0.3 }}
        className="sticky top-0 z-50 border-b border-border/50"
      >
        <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-3 sm:px-6">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-2.5 group">
            <motion.img
              src={logoImg}
              alt="MediFlow"
              className="h-9 w-auto"
              whileHover={{ scale: 1.05 }}
              transition={{ type: 'spring', stiffness: 400, damping: 20 }}
            />
            <div>
              <span className="text-lg font-bold bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent">
                MediFlow
              </span>
              <span className="hidden sm:block text-[10px] uppercase tracking-[0.2em] text-muted-foreground -mt-0.5">
                Healthcare Platform
              </span>
            </div>
          </Link>

          {/* Desktop nav */}
          <nav className="hidden md:flex items-center gap-6 text-sm">
            {PUBLIC_NAV_ITEMS.map((item) => (
              <NavLink key={item.to} to={item.to} className={navLinkClass} end={item.to === '/'}>
                {item.label}
              </NavLink>
            ))}
            <NavLink to={portalRoute} className={navLinkClass}>
              {isAuthenticated && sessionType === 'patient' ? 'My Portal' : 'Patient Login'}
            </NavLink>
            <NavLink
              to="/patient/register"
              className="rounded-full bg-primary px-5 py-2 text-sm font-semibold text-primary-foreground shadow-sm transition-all hover:shadow-md hover:brightness-110 active:scale-[0.97]"
            >
              Register
            </NavLink>
          </nav>

          {/* Mobile hamburger */}
          <button
            type="button"
            onClick={() => setMobileOpen(!mobileOpen)}
            className="md:hidden flex items-center justify-center h-10 w-10 rounded-xl hover:bg-muted transition-colors"
            aria-label="Toggle menu"
          >
            {mobileOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </button>
        </div>
      </motion.header>

      {/* Mobile menu overlay */}
      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, y: -8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -8 }}
            transition={{ duration: 0.2 }}
            className="fixed inset-x-0 top-[57px] z-40 border-b border-border bg-background/95 backdrop-blur-xl md:hidden"
          >
            <nav className="flex flex-col gap-1 px-4 py-4">
              {PUBLIC_NAV_ITEMS.map((item) => (
                <NavLink
                  key={item.to}
                  to={item.to}
                  onClick={() => setMobileOpen(false)}
                  className={({ isActive }) =>
                    `rounded-xl px-4 py-3 text-sm font-medium transition-colors ${
                      isActive ? 'bg-primary/10 text-primary' : 'text-foreground hover:bg-muted'
                    }`
                  }
                  end={item.to === '/'}
                >
                  {item.label}
                </NavLink>
              ))}
              <NavLink
                to={portalRoute}
                onClick={() => setMobileOpen(false)}
                className="rounded-xl px-4 py-3 text-sm font-medium text-foreground hover:bg-muted"
              >
                {isAuthenticated && sessionType === 'patient' ? 'My Portal' : 'Patient Login'}
              </NavLink>
              <NavLink
                to="/patient/register"
                onClick={() => setMobileOpen(false)}
                className="mt-2 rounded-xl bg-primary px-4 py-3 text-center text-sm font-semibold text-primary-foreground"
              >
                Register
              </NavLink>
            </nav>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

