    try {
      const data = await bedApi.getAdmissionCandidates({ search: searchValue || undefined });
      setCandidates(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load admission candidates.');
    }
  };

  useEffect(() => {
    loadWards();
  }, []);

  useEffect(() => {
    loadBeds();
  }, [search, filterWard, filterStatus]);

  useEffect(() => {
    if (showAdmitForm) {
      loadCandidates(candidateSearch);
    }
  }, [showAdmitForm, candidateSearch]);

  const openCreate = () => {
    setEditingBed(null);
    setBedForm(initialBedForm);
    setShowBedForm(true);
  };

  const openEdit = (bed) => {
    setEditingBed(bed);
    setBedForm({
      wardId: bed.wardId?._id || '',
      bedNumber: bed.bedNumber || '',
      status: bed.status || 'available',
      customPriceOverride: bed.customPriceOverride ?? '',
    });
    setShowBedForm(true);
  };

  const openAdmit = (bed) => {
    setSelectedBed(bed);
    setAdmissionForm({ patientId: '', prescriptionId: '' });
    setShowAdmitForm(true);
    setCandidateSearch('');
  };

  const submitBed = async (event) => {
    event.preventDefault();
    setSaving(true);
    const payload = {
      ...bedForm,
      customPriceOverride: bedForm.customPriceOverride === '' ? undefined : Number(bedForm.customPriceOverride),
    };

    try {
      if (editingBed) {
        await bedApi.update(editingBed._id, payload);
        toast.success('Bed updated successfully.');
      } else {
        await bedApi.add(payload);
        toast.success('Bed created successfully.');
      }
      setShowBedForm(false);
      setBedForm(initialBedForm);
      setEditingBed(null);
      await loadBeds();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save bed.');
    } finally {
      setSaving(false);
    }
  };

  const submitAdmission = async (event) => {
    event.preventDefault();
    if (!selectedBed) return;

    try {
      await bedApi.assign(selectedBed._id, admissionForm);
      toast.success('Patient admitted successfully.');
      setShowAdmitForm(false);
      setSelectedBed(null);
      await loadBeds();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to admit patient.');
    }
  };

  const discharge = async (bed) => {
    try {
      await bedApi.discharge(bed._id);
      toast.success('Patient discharged successfully.');
      await loadBeds();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to discharge patient.');
    }
  };

  const updateStatus = async (bed, status) => {
    try {
      await bedApi.update(bed._id, { status });
      toast.success('Bed status updated.');
      await loadBeds();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update bed status.');
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="flex flex-col gap-4 rounded-2xl bg-card p-8 shadow-sm md:flex-row md:items-center md:justify-between">
        <div>
          <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Inpatient Operations</p>
          <h2 className="mt-2 text-3xl font-semibold text-foreground">Bed management</h2>
          <p className="mt-2 max-w-3xl text-muted-foreground">
            Manage beds by ward, update operational status, assign patients to available beds, and discharge admitted patients safely.
          </p>
        </div>
        <Button onClick={openCreate}>
          <Plus className="mr-2 h-4 w-4" />
          Add Bed
        </Button>
      </div>

      <div className="flex flex-col gap-3 lg:flex-row">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <input type="text" value={search} onChange={(event) => setSearch(event.target.value)} placeholder="Search bed number or ward" className="w-full rounded-2xl border border-border bg-card py-3 pl-9 pr-4 text-sm outline-none focus:border-primary" />
        </div>
        <select value={filterWard} onChange={(event) => setFilterWard(event.target.value)} className="rounded-2xl border border-border bg-card px-4 py-3 text-sm outline-none focus:border-primary">
          <option value="">All wards</option>
          {wards.map((ward) => (
            <option key={ward._id} value={ward._id}>
              {ward.name}
            </option>
          ))}
        </select>
        <select value={filterStatus} onChange={(event) => setFilterStatus(event.target.value)} className="rounded-2xl border border-border bg-card px-4 py-3 text-sm outline-none focus:border-primary">
          <option value="">All statuses</option>
          <option value="available">Available</option>
          <option value="occupied">Occupied</option>
          <option value="maintenance">Maintenance</option>
          <option value="reserved">Reserved</option>
        </select>
        <Button type="button" variant="outline" onClick={loadBeds}>
          <RefreshCw className="h-4 w-4" />
        </Button>
      </div>

      <article className="overflow-hidden rounded-2xl bg-card shadow-sm">
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="border-b border-border bg-muted/50 text-left text-muted-foreground">
                <th className="px-4 py-3 font-medium">Bed</th>
                <th className="px-4 py-3 font-medium">Ward</th>
                <th className="px-4 py-3 font-medium">Status</th>
                <th className="px-4 py-3 font-medium">Patient</th>
                <th className="px-4 py-3 font-medium">Effective Price</th>
                <th className="px-4 py-3 font-medium">Actions</th>
              </tr>
            </thead>
            <tbody>
              {beds.length === 0 && (
                <tr>
                  <td colSpan={6} className="px-4 py-10 text-center text-muted-foreground">No beds found for the selected filters.</td>
                </tr>
              )}
              {beds.map((bed) => (
                <tr key={bed._id} className="border-b border-slate-100 last:border-b-0">
                  <td className="px-4 py-3">
                    <p className="font-medium text-foreground">{bed.bedNumber}</p>
                    <p className="text-xs text-muted-foreground capitalize">{bed.type}</p>
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">
                    {bed.wardId?.name || bed.ward} {bed.wardId?.wardNumber ? `ΓÇó ${bed.wardId.wardNumber}` : ''}
                  </td>
                  <td className="px-4 py-3">
                    <span className="rounded-full bg-muted px-2.5 py-1 text-xs font-semibold capitalize text-foreground">{bed.status}</span>
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">
                    {bed.patient ? (
                      <>
                        <p>{bed.patient.name}</p>
                        <p className="text-xs text-muted-foreground">{bed.patient.patientId || 'No patient ID'}</p>
                      </>
                    ) : (
                      'Vacant'
                    )}
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">Γé╣{Number(bed.effectivePrice || 0).toLocaleString()}</td>
                  <td className="px-4 py-3">
                    <div className="flex flex-wrap gap-2">
                      <Button size="sm" variant="outline" onClick={() => openEdit(bed)}>Edit</Button>
                      {bed.status === 'available' && <Button size="sm" onClick={() => openAdmit(bed)}>Admit</Button>}
                      {bed.status === 'occupied' && <Button size="sm" variant="destructive" onClick={() => discharge(bed)}>Discharge</Button>}
                      {bed.status !== 'occupied' && bed.status !== 'maintenance' && <Button size="sm" variant="outline" onClick={() => updateStatus(bed, 'maintenance')}>Maintenance</Button>}
                      {bed.status !== 'occupied' && bed.status !== 'reserved' && <Button size="sm" variant="outline" onClick={() => updateStatus(bed, 'reserved')}>Reserve</Button>}
                      {bed.status !== 'occupied' && bed.status !== 'available' && <Button size="sm" variant="outline" onClick={() => updateStatus(bed, 'available')}>Mark Available</Button>}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </article>

      {showBedForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <form onSubmit={submitBed} className="w-full max-w-2xl rounded-2xl bg-card p-6 shadow-2xl">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold text-foreground">{editingBed ? 'Edit Bed' : 'Add Bed'}</h3>
              <button type="button" onClick={() => setShowBedForm(false)} className="text-muted-foreground hover:text-foreground">Γ£ò</button>
            </div>
            <div className="mt-5 grid gap-4 md:grid-cols-2">
              <Field label="Ward">
                <select value={bedForm.wardId} onChange={(event) => setBedForm((current) => ({ ...current, wardId: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required>
                  <option value="">Select ward</option>
                  {wards.map((ward) => (
                    <option key={ward._id} value={ward._id}>
                      {ward.name} ({ward.wardNumber})
                    </option>
                  ))}
                </select>
              </Field>
              <Field label="Bed number">
                <input type="text" value={bedForm.bedNumber} onChange={(event) => setBedForm((current) => ({ ...current, bedNumber: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
              </Field>
              <Field label="Status">
                <select value={bedForm.status} onChange={(event) => setBedForm((current) => ({ ...current, status: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary">
                  <option value="available">Available</option>
                  <option value="reserved">Reserved</option>
                  <option value="maintenance">Maintenance</option>
                </select>
              </Field>
              <Field label="Custom price override">
                <input type="number" min="0" value={bedForm.customPriceOverride} onChange={(event) => setBedForm((current) => ({ ...current, customPriceOverride: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
              </Field>
            </div>
            <div className="mt-6 flex gap-3">
              <Button type="button" variant="outline" className="flex-1" onClick={() => setShowBedForm(false)}>Cancel</Button>
              <Button type="submit" className="flex-1" disabled={saving}>{saving ? 'Saving...' : editingBed ? 'Save Changes' : 'Create Bed'}</Button>
            </div>
          </form>
        </div>
      )}

      {showAdmitForm && selectedBed && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <form onSubmit={submitAdmission} className="w-full max-w-3xl rounded-2xl bg-card p-6 shadow-2xl">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold text-foreground">Admit patient to Bed {selectedBed.bedNumber}</h3>
              <button type="button" onClick={() => setShowAdmitForm(false)} className="text-muted-foreground hover:text-foreground">Γ£ò</button>
            </div>

            <div className="mt-4">
              <input type="text" value={candidateSearch} onChange={(event) => setCandidateSearch(event.target.value)} placeholder="Search patient by name, ID, phone, or email" className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
            </div>

            <div className="mt-4 max-h-[320px] space-y-3 overflow-y-auto">
              {candidates.map((candidate) => (
                <button
                  key={candidate.id}
                  type="button"
                  disabled={candidate.isCurrentlyAdmitted}
                  onClick={() => setAdmissionForm({ patientId: candidate.id, prescriptionId: candidate.admissionRecommendation?.prescriptionId || '' })}
                  className={`w-full rounded-xl border p-4 text-left ${candidate.isCurrentlyAdmitted ? 'cursor-not-allowed border-border bg-muted opacity-70' : admissionForm.patientId === candidate.id ? 'border-slate-900 bg-muted/50' : 'border-border hover:border-border'}`}
                >
                  <div className="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
                    <div>
                      <p className="font-medium text-foreground">{candidate.name}</p>
                      <p className="mt-1 text-sm text-muted-foreground">
                        {candidate.patientId || 'No patient ID'} ΓÇó {candidate.phone || 'No phone'}
                      </p>
                      <p className="mt-1 text-sm text-muted-foreground">
                        {candidate.isCurrentlyAdmitted ? 'Already admitted' : 'Not currently admitted'}
                      </p>
                    </div>
                    {candidate.admissionRecommendation && (
                      <div className="rounded-xl bg-amber-50 px-3 py-2 text-xs text-foreground">
                        <p className="font-semibold">Doctor recommendation visible</p>
                        <p className="mt-1">{candidate.admissionRecommendation.doctor?.name || 'Doctor'} recommended admission.</p>
                      </div>
                    )}
                  </div>
                  {candidate.admissionRecommendation?.admissionRecommendationNotes && (
                    <p className="mt-3 text-sm text-muted-foreground">{candidate.admissionRecommendation.admissionRecommendationNotes}</p>
                  )}
                </button>
              ))}
              {candidates.length === 0 && <p className="text-sm text-muted-foreground">No admission candidates found.</p>}
            </div>

            <div className="mt-6 flex gap-3">
              <Button type="button" variant="outline" className="flex-1" onClick={() => setShowAdmitForm(false)}>Cancel</Button>
              <Button type="submit" className="flex-1" disabled={!admissionForm.patientId}>Confirm Admission</Button>
            </div>
          </form>
        </div>
      )}
    </motion.section>
  );
}

function Field({ children, className = '', label }) {
  return (
    <div className={className}>
      <label className="mb-2 block text-sm font-medium text-foreground">{label}</label>
      {children}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Button } from '../../components/ui/button';
import { departmentApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { Plus, RefreshCw, Search, UserCheck, UserX } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialForm = {
  name: '',
  description: '',
  code: '',
  icon: '',
  image: '',
  isFeatured: false,
  featureOrder: '',
};

export default function DepartmentManagement() {
  const [departments, setDepartments] = useState([]);
  const [search, setSearch] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [form, setForm] = useState(initialForm);
  const [saving, setSaving] = useState(false);

  const loadDepartments = async () => {
    setLoading(true);
    try {
      const data = await departmentApi.getAll({
        search,
        isActive: filterStatus || undefined,
      });
      setDepartments(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load departments.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadDepartments();
  }, [search, filterStatus]);

  const resetForm = () => {
    setForm(initialForm);
    setEditingItem(null);
    setShowForm(false);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      if (editingItem) {
        await departmentApi.update(editingItem._id, form);
        toast.success('Department updated successfully.');
      } else {
        await departmentApi.create(form);
        toast.success('Department created successfully.');
      }
      resetForm();
      loadDepartments();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save department.');
    } finally {
      setSaving(false);
    }
  };

  const handleToggle = async (item) => {
    try {
      await departmentApi.toggleActive(item._id);
      toast.success(`${item.name} has been ${item.isActive ? 'deactivated' : 'activated'}.`);
      loadDepartments();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update department.');
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="flex flex-col gap-4 rounded-2xl bg-card p-8 shadow-sm md:flex-row md:items-center md:justify-between">
        <div>
          <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Master Data</p>
          <h2 className="mt-2 text-3xl font-semibold text-foreground">Departments</h2>
          <p className="mt-2 max-w-3xl text-muted-foreground">
            Manage the core clinical departments that future doctor management, public discovery, booking, and reporting modules depend on.
          </p>
        </div>
        <Button
          onClick={() => {
            setEditingItem(null);
            setForm(initialForm);
            setShowForm(true);
          }}
        >
          <Plus className="mr-2 h-4 w-4" />
          Add Department
        </Button>
      </div>

      <div className="flex flex-col gap-3 lg:flex-row">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <input
            type="text"
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            placeholder="Search by department name"
            className="w-full rounded-2xl border border-border bg-card py-3 pl-9 pr-4 text-sm outline-none focus:border-primary"
          />
        </div>
        <select
          value={filterStatus}
          onChange={(event) => setFilterStatus(event.target.value)}
          className="rounded-2xl border border-border bg-card px-4 py-3 text-sm outline-none focus:border-primary"
        >
          <option value="">All Statuses</option>
          <option value="true">Active</option>
          <option value="false">Inactive</option>
        </select>
        <Button type="button" variant="outline" onClick={loadDepartments}>
          <RefreshCw className="h-4 w-4" />
        </Button>
      </div>

      <article className="overflow-hidden rounded-2xl bg-card shadow-sm">
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="border-b border-border bg-muted/50 text-left text-muted-foreground">
                <th className="px-4 py-3 font-medium">Name</th>
                <th className="px-4 py-3 font-medium">Code</th>
                <th className="px-4 py-3 font-medium">Featured</th>
                <th className="px-4 py-3 font-medium">Description</th>
                <th className="px-4 py-3 font-medium">Status</th>
                <th className="px-4 py-3 font-medium">Updated</th>
                <th className="px-4 py-3 font-medium">Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading && (
                <tr>
                  <td colSpan={7} className="px-4 py-10 text-center text-muted-foreground">Loading departments...</td>
                </tr>
              )}
              {!loading && departments.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-4 py-10 text-center text-muted-foreground">No departments found.</td>
                </tr>
              )}
              {departments.map((item) => (
                <tr key={item._id} className="border-b border-slate-100 last:border-b-0">
                  <td className="px-4 py-3 font-medium text-foreground">{item.name}</td>
                  <td className="px-4 py-3 font-mono text-xs text-muted-foreground">{item.code || 'ΓÇö'}</td>
                  <td className="px-4 py-3">
                    {item.isFeatured ? (
                      <span className="rounded-full bg-amber-100 px-2.5 py-1 text-xs font-semibold text-amber-800">
                        Featured #{item.featureOrder || 0}
                      </span>
                    ) : (
                      <span className="text-muted-foreground">ΓÇö</span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">{item.description || 'ΓÇö'}</td>
                  <td className="px-4 py-3">
                    <span className={`rounded-full px-2.5 py-1 text-xs font-semibold ${item.isActive ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>
                      {item.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-muted-foreground">{new Date(item.updatedAt).toLocaleDateString()}</td>
                  <td className="px-4 py-3">
                    <div className="flex flex-wrap gap-2">
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => {
                          setEditingItem(item);
                          setForm({
                            name: item.name || '',
                            description: item.description || '',
                            code: item.code || '',
                            icon: item.icon || '',
                            image: item.image || '',
                            isFeatured: item.isFeatured || false,
                            featureOrder: item.featureOrder ?? '',
                          });
                          setShowForm(true);
                        }}
                      >
                        Edit
                      </Button>
                      <Button type="button" variant={item.isActive ? 'destructive' : 'outline'} size="sm" onClick={() => handleToggle(item)}>
                        {item.isActive ? <UserX className="mr-1 h-3 w-3" /> : <UserCheck className="mr-1 h-3 w-3" />}
                        {item.isActive ? 'Deactivate' : 'Activate'}
                      </Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </article>

      {showForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <form onSubmit={handleSubmit} className="w-full max-w-2xl rounded-2xl bg-card p-6 shadow-2xl">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold text-foreground">{editingItem ? 'Edit Department' : 'Add Department'}</h3>
              <button type="button" onClick={resetForm} className="text-muted-foreground hover:text-foreground">Γ£ò</button>
            </div>

            <div className="mt-5 grid gap-4 md:grid-cols-2">
              <Field label="Department Name">
                <input type="text" value={form.name} onChange={(e) => setForm((c) => ({ ...c, name: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
              </Field>
              <Field label="Code">
                <input type="text" value={form.code} onChange={(e) => setForm((c) => ({ ...c, code: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
              </Field>
              <Field label="Icon Placeholder">
                <input type="text" value={form.icon} onChange={(e) => setForm((c) => ({ ...c, icon: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
              </Field>
              <Field label="Display Image URL">
                <input type="text" value={form.image} onChange={(e) => setForm((c) => ({ ...c, image: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
              </Field>
              <Field label="Feature Order">
                <input type="number" value={form.featureOrder} onChange={(e) => setForm((c) => ({ ...c, featureOrder: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
              </Field>
            </div>

            <Field label="Description" className="mt-4">
              <textarea value={form.description} onChange={(e) => setForm((c) => ({ ...c, description: e.target.value }))} className="min-h-[120px] w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
            </Field>

            <label className="mt-4 flex items-center gap-3 rounded-2xl border border-border px-4 py-3 text-sm text-foreground">
              <input type="checkbox" checked={form.isFeatured} onChange={(e) => setForm((c) => ({ ...c, isFeatured: e.target.checked }))} />
              Show this department in featured public content
            </label>

            <div className="mt-6 flex gap-3">
              <Button type="button" variant="outline" className="flex-1" onClick={resetForm}>Cancel</Button>
              <Button type="submit" className="flex-1" disabled={saving}>{saving ? 'Saving...' : editingItem ? 'Save Changes' : 'Create Department'}</Button>
            </div>
          </form>
        </div>
      )}
    </motion.section>
  );
}

function Field({ children, className = '', label }) {
  return (
    <div className={className}>
      <label className="mb-2 block text-sm font-medium text-foreground">{label}</label>
      {children}
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { availabilityApi, doctorApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { Button } from '../../components/ui/button.jsx';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card.jsx';
import { Calendar, Trash2 } from 'lucide-react';

const DAYS_OF_WEEK = [
  'Monday',
  'Tuesday',
  'Wednesday',
  'Thursday',
  'Friday',
  'Saturday',
  'Sunday',
];

const toMinutes = (value = '00:00') => {
  if (!value) return 0;
  const trimmed = `${value}`.trim();
  const match = trimmed.match(/^(\d{1,2}):(\d{2})\s*([AaPp][Mm])?$/);
  if (!match) return 0;
  let hours = Number(match[1]);
  const minutes = Number(match[2]);
  const meridiem = match[3]?.toLowerCase();
  if (meridiem) {
    if (meridiem === 'pm' && hours < 12) hours += 12;
    if (meridiem === 'am' && hours === 12) hours = 0;
  }
  return hours * 60 + minutes;
};

const formatTime = (minutes) => {
  const h = Math.floor(minutes / 60).toString().padStart(2, '0');
  const m = (minutes % 60).toString().padStart(2, '0');
  return `${h}:${m}`;
};

const countSlots = (start, end, duration) => {
  if (!duration || duration <= 0) return 0;
  const diff = toMinutes(end) - toMinutes(start);
  if (diff <= 0) return 0;
  return Math.floor(diff / duration);
};

const initialForm = {
  dayOfWeek: 'Monday',
  startTime: '09:00',
  endTime: '13:00',
  slotDuration: 15,
};

export default function DoctorAvailabilityManagement() {
  const [doctors, setDoctors] = useState([]);
  const [selectedDoctorId, setSelectedDoctorId] = useState('');
  const [availabilities, setAvailabilities] = useState([]);
  const [form, setForm] = useState(initialForm);
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [breakEnabled, setBreakEnabled] = useState(false);
  const [breakStart, setBreakStart] = useState('13:00');
  const [breakEnd, setBreakEnd] = useState('14:00');

  useEffect(() => {
    const loadDoctors = async () => {
      try {
        const data = await doctorApi.getAdminAll({ isActive: true });
        setDoctors(Array.isArray(data) ? data : []);
        if (Array.isArray(data) && data.length && !selectedDoctorId) {
          setSelectedDoctorId(data[0].id || data[0]._id);
        }
      } catch (error) {
        toast.error(error.response?.data?.message || 'Unable to load doctors.');
      }
    };
    loadDoctors();
  }, []);

  useEffect(() => {
    const loadAvailability = async () => {
      if (!selectedDoctorId) {
        setAvailabilities([]);
        return;
      }
      try {
        const data = await availabilityApi.getByDoctor(selectedDoctorId);
        setAvailabilities(Array.isArray(data) ? data : []);
      } catch (error) {
        toast.error(error.response?.data?.message || 'Unable to load availability.');
        setAvailabilities([]);
      }
    };
    loadAvailability();
  }, [selectedDoctorId]);

  const grouped = useMemo(() => {
    const map = new Map();
    availabilities.forEach((item) => {
      const list = map.get(item.dayOfWeek) || [];
      list.push(item);
      map.set(item.dayOfWeek, list);
    });
    // sort ranges per day
    map.forEach((list, key) => {
      list.sort((a, b) => toMinutes(a.startTime) - toMinutes(b.startTime));
      map.set(key, list);
    });
    return map;
  }, [availabilities]);

  const daySummaries = useMemo(() => {
    const summaries = new Map();
    DAYS_OF_WEEK.forEach((day) => {
      const ranges = grouped.get(day) || [];
      let totalSlots = 0;
      const breaks = [];
      let overlap = false;
      ranges.forEach((range, idx) => {
        totalSlots += countSlots(range.startTime, range.endTime, range.slotDuration);
        const currentEnd = toMinutes(range.endTime);
        const next = ranges[idx + 1];
        if (next) {
          const nextStart = toMinutes(next.startTime);
          if (nextStart < currentEnd) {
            overlap = true;
          }
          if (nextStart > currentEnd) {
            breaks.push({ start: currentEnd, end: nextStart });
          }
        }
      });
      summaries.set(day, { totalSlots, breaks, overlap });
    });
    return summaries;
  }, [grouped]);

  const handleSave = async (event) => {
    event.preventDefault();
    if (!selectedDoctorId) {
      toast.error('Select a doctor to manage availability.');
      return;
    }
    const startMinutes = toMinutes(form.startTime);
    const endMinutes = toMinutes(form.endTime);
    const breakStartMinutes = toMinutes(breakStart);
    const breakEndMinutes = toMinutes(breakEnd);

    if (breakEnabled) {
      if (!(breakStartMinutes > startMinutes && breakEndMinutes < endMinutes && breakStartMinutes < breakEndMinutes)) {
        toast.error('Break time must fall within the availability range.');
        return;
      }
    }

    setLoading(true);
    try {
      if (editingId && !breakEnabled) {
        await availabilityApi.update(editingId, form);
        toast.success('Availability updated.');
      } else {
        if (editingId) {
          await availabilityApi.remove(editingId);
        }
        const payloads = breakEnabled
          ? [
              { ...form, endTime: breakStart },
              { ...form, startTime: breakEnd },
            ]
          : [form];

        for (const payload of payloads) {
          await availabilityApi.create({
            ...payload,
            doctorId: selectedDoctorId,
          });
        }
        toast.success(breakEnabled ? 'Availability split with break.' : 'Availability added.');
      }
      setForm(initialForm);
      setEditingId(null);
      setBreakEnabled(false);
      const data = await availabilityApi.getByDoctor(selectedDoctorId);
      setAvailabilities(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to save availability.');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (item) => {
    setEditingId(item._id);
    setForm({
      dayOfWeek: item.dayOfWeek,
      startTime: item.startTime,
      endTime: item.endTime,
      slotDuration: item.slotDuration,
    });
    setBreakEnabled(false);
  };

  const handleDelete = async (id) => {
    if (!id) return;
    setLoading(true);
    try {
      await availabilityApi.remove(id);
      toast.success('Availability deleted.');
      const data = await availabilityApi.getByDoctor(selectedDoctorId);
      setAvailabilities(Array.isArray(data) ? data : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to delete availability.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Doctor Availability</p>
        <h2 className="mt-2 text-3xl font-semibold text-foreground">Manage schedules and slot windows</h2>
        <p className="mt-2 max-w-3xl text-muted-foreground">
          Configure weekly availability ranges for each doctor. Multiple ranges per day are supported. Existing appointments will remain intact.
        </p>
      </div>

      <Card className="border-border rounded-2xl">
        <CardHeader>
          <CardTitle className="text-lg">Select doctor</CardTitle>
        </CardHeader>
        <CardContent className="grid gap-4 md:grid-cols-2">
          <div>
            <label className="mb-2 block text-sm font-medium text-foreground">Doctor</label>
            <select
              value={selectedDoctorId}
              onChange={(event) => setSelectedDoctorId(event.target.value)}
              className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
            >
              <option value="">Select doctor</option>
              {doctors.map((doctor) => (
                <option key={doctor.id || doctor._id} value={doctor.id || doctor._id}>
                  {doctor.userId?.name || 'Doctor'} ΓÇó {doctor.departmentId?.name || 'Department'}
                </option>
              ))}
            </select>
          </div>
        </CardContent>
      </Card>

      <Card className="border-border rounded-2xl">
        <CardHeader>
          <CardTitle className="text-lg">{editingId ? 'Edit availability' : 'Add availability range'}</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSave} className="grid gap-4 md:grid-cols-4">
            <div>
              <label className="mb-2 block text-sm font-medium text-foreground">Day</label>
              <select
                value={form.dayOfWeek}
                onChange={(event) => setForm((current) => ({ ...current, dayOfWeek: event.target.value }))}
                className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                required
              >
                {DAYS_OF_WEEK.map((day) => (
                  <option key={day} value={day}>{day}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="mb-2 block text-sm font-medium text-foreground">Start time</label>
              <input
                type="time"
                value={form.startTime}
                onChange={(event) => setForm((current) => ({ ...current, startTime: event.target.value }))}
                className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                required
              />
            </div>
            <div>
              <label className="mb-2 block text-sm font-medium text-foreground">End time</label>
              <input
                type="time"
                value={form.endTime}
                onChange={(event) => setForm((current) => ({ ...current, endTime: event.target.value }))}
                className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                required
              />
            </div>
            <div>
              <label className="mb-2 block text-sm font-medium text-foreground">Slot duration (min)</label>
              <input
                type="number"
                min="5"
                value={form.slotDuration}
                onChange={(event) => setForm((current) => ({ ...current, slotDuration: Number(event.target.value) }))}
                className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                required
              />
            </div>
            <div className="md:col-span-4 rounded-2xl border border-border p-4">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-semibold text-foreground">Lunch / Rest break</p>
                  <p className="text-xs text-muted-foreground">Split the range to exclude a break window.</p>
                </div>
                <label className="flex items-center gap-2 text-sm text-foreground">
                  <input
                    type="checkbox"
                    checked={breakEnabled}
                    onChange={(event) => {
                      const checked = event.target.checked;
                      setBreakEnabled(checked);
                      if (checked) {
                        const startMinutes = toMinutes(form.startTime);
                        const endMinutes = toMinutes(form.endTime);
                        const mid = Math.floor((startMinutes + endMinutes) / 2);
                        const nextHour = Math.min(mid + 60, endMinutes - 15);
                        setBreakStart(formatTime(mid));
                        setBreakEnd(formatTime(nextHour));
                      }
                    }}
                    className="h-4 w-4 rounded border-border text-primary focus:ring-primary"
                  />
                  Add break
                </label>
              </div>
              {breakEnabled && (
                <div className="mt-3 grid gap-4 md:grid-cols-2">
                  <div>
                    <label className="mb-2 block text-sm font-medium text-foreground">Break start</label>
                    <input
                      type="time"
                      value={breakStart}
                      onChange={(event) => setBreakStart(event.target.value)}
                      className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                      required
                    />
                  </div>
                  <div>
                    <label className="mb-2 block text-sm font-medium text-foreground">Break end</label>
                    <input
                      type="time"
                      value={breakEnd}
                      onChange={(event) => setBreakEnd(event.target.value)}
                      className="w-full rounded-2xl border border-border bg-card px-4 py-3 text-foreground outline-none focus:border-primary"
                      required
                    />
                  </div>
                </div>
              )}
            </div>
            <div className="md:col-span-4 flex flex-wrap gap-3">
              <Button type="submit" disabled={loading || !selectedDoctorId}>
                <Calendar className="mr-2 h-4 w-4" />
                {editingId ? 'Update range' : 'Add range'}
              </Button>
              {editingId && (
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => {
                    setEditingId(null);
                    setForm(initialForm);
                  }}
                >
                  Cancel edit
                </Button>
              )}
            </div>
          </form>
        </CardContent>
      </Card>

      <div className="grid gap-4 lg:grid-cols-2">
        {DAYS_OF_WEEK.map((day) => (
          <Card key={day} className="border-border rounded-2xl">
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="text-base">{day}</CardTitle>
                <span className="rounded-full bg-muted px-3 py-1 text-xs font-semibold text-muted-foreground">
                  {daySummaries.get(day)?.totalSlots || 0} slots
                </span>
              </div>
            </CardHeader>
            <CardContent className="space-y-3">
              {(grouped.get(day) || []).map((item) => (
                <div key={item._id} className="flex items-center justify-between rounded-xl border border-border p-3">
                  <div>
                    <p className="font-semibold text-foreground">{item.startTime} - {item.endTime}</p>
                    <p className="text-xs text-muted-foreground">Slot: {item.slotDuration} mins</p>
                  </div>
                  <div className="flex gap-2">
                    <Button size="sm" variant="outline" onClick={() => handleEdit(item)}>Edit</Button>
                    <Button size="sm" variant="destructive" onClick={() => handleDelete(item._id)}>
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
              {(daySummaries.get(day)?.breaks || []).length > 0 && (
                <div className="rounded-xl border border-dashed border-border px-3 py-2">
                  <p className="text-xs font-semibold uppercase tracking-[0.18em] text-muted-foreground">Breaks</p>
                  <div className="mt-2 flex flex-wrap gap-2">
                    {daySummaries.get(day).breaks.map((brk) => (
                      <span
                        key={`${day}-${brk.start}-${brk.end}`}
                        className="rounded-full bg-amber-500/15 px-3 py-1 text-xs font-semibold text-amber-600"
                      >
                        {formatTime(brk.start)} - {formatTime(brk.end)}
                      </span>
                    ))}
                  </div>
                </div>
              )}
              {daySummaries.get(day)?.overlap && (
                <div className="rounded-xl border border-red-500/30 bg-red-500/10 px-3 py-2 text-xs font-semibold text-red-500">
                  Overlapping ranges detected ΓÇö please adjust timings.
                </div>
              )}
              {(grouped.get(day) || []).length === 0 && (
                <p className="text-sm text-muted-foreground">No availability set.</p>
              )}
            </CardContent>
          </Card>
        ))}
      </div>
    </section>
  );
}

import { useEffect, useMemo, useState } from 'react';
