  departmentId: '',
  specializationIds: [],
  hospitalLocations: [],
  qualifications: '',
  experienceYears: '',
  consultationFee: '',
  consultationFeeVideo: '',
  consultationFeePhone: '',
  about: '',
  expertise: '',
  profileImage: '',
  articles: [],
  media: [],
  locationFees: [],
  isActive: true,
  isPublished: false,
  isFeatured: false,
  featureOrder: '',
};

