function BoardList({ title, items, dateKey, secondaryKey }) {
  return (
    <article className="rounded-xl border border-border p-4">
      <div className="flex items-center gap-2">
        <CalendarDays className="h-4 w-4 text-[#ee4c35]" />
        <h4 className="font-semibold text-foreground">{title}</h4>
      </div>
      <div className="mt-4 space-y-3">
        {items.length === 0 && <p className="text-sm text-muted-foreground">No activity recorded.</p>}
        {items.slice(0, 6).map((item) => (
          <div key={item.id} className="rounded-[1rem] bg-muted/50 p-3">
            <p className="font-medium text-foreground">{item.name || item.patient?.name || item.patientName || 'Patient activity'}</p>
            {secondaryKey && <p className="mt-1 text-sm text-muted-foreground">{item[secondaryKey] || 'ΓÇö'}</p>}
            <p className="mt-1 text-xs text-muted-foreground">{new Date(item[dateKey]).toLocaleString()}</p>
          </div>
        ))}
      </div>
    </article>
  );
}

function RelatedSection({ children, title }) {
  return (
    <section>
      <h4 className="text-lg font-semibold text-foreground">{title}</h4>
      <div className="mt-4">{children}</div>
    </section>
  );
}

function RelatedList({ title, items, renderItem }) {
  return (
    <div className="mt-4">
      <p className="text-sm font-medium text-foreground">{title}</p>
      <div className="mt-2 space-y-2">
        {items.length === 0 && <p className="text-sm text-muted-foreground">No records yet.</p>}
        {items.slice(0, 5).map((item) => (
          <div key={item._id} className="rounded-[1rem] border border-border p-3 text-sm text-muted-foreground">
            {renderItem(item)}
          </div>
        ))}
      </div>
    </div>
  );
}

function InfoPills({ items, emptyLabel }) {
  if (!items?.length) {
    return <p className="mt-2 text-sm text-muted-foreground">{emptyLabel}</p>;
  }

  return (
    <div className="mt-2 flex flex-wrap gap-2">
      {items.map((item) => (
        <span key={item} className="rounded-full bg-muted px-3 py-2 text-sm text-foreground">
          {item}
        </span>
      ))}
    </div>
  );
}

function DetailCard({ label, value }) {
  return (
    <article className="rounded-xl border border-border p-4">
      <p className="text-sm text-muted-foreground">{label}</p>
      <p className="mt-2 text-sm font-medium text-foreground">{value || 'ΓÇö'}</p>
    </article>
  );
}

function Field({ children, className = '', label }) {
  return (
    <div className={className}>
      <label className="mb-2 block text-sm font-medium text-foreground">{label}</label>
      {children}
    </div>
  );
}

function splitList(value) {
  return value
    .split(',')
    .map((item) => item.trim())
    .filter(Boolean);
}

function formatDate(value) {
  if (!value) return 'ΓÇö';
  return new Date(value).toLocaleDateString();
}

function formatEmergencyContact(contact) {
  if (!contact?.name && !contact?.phone) return 'ΓÇö';
  return [contact.name, contact.phone, contact.relation].filter(Boolean).join(' ΓÇó ');
}

function formatInsurance(patient) {
  if (!patient.insuranceProvider && !patient.insuranceNumber) return 'ΓÇö';
  return [patient.insuranceProvider, patient.insuranceNumber].filter(Boolean).join(' ΓÇó ');
}

import { useEffect, useMemo, useState } from 'react';
import { Button } from '../../components/ui/button';
import { departmentApi, specializationApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { Plus, RefreshCw, Search, UserCheck, UserX } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialForm = {
  name: '',
  departmentId: '',
  description: '',
};

export default function SpecializationManagement() {
  const [specializations, setSpecializations] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [search, setSearch] = useState('');
  const [filterDepartment, setFilterDepartment] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [form, setForm] = useState(initialForm);
  const [saving, setSaving] = useState(false);

  const loadData = async () => {
    setLoading(true);
    try {
      const [specializationData, departmentData] = await Promise.all([
        specializationApi.getAll({
          search,
          departmentId: filterDepartment || undefined,
          isActive: filterStatus || undefined,
        }),
        departmentApi.getAll(),
      ]);
      setSpecializations(Array.isArray(specializationData) ? specializationData : []);
      setDepartments(Array.isArray(departmentData) ? departmentData.filter((item) => item.isActive) : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load specializations.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [search, filterDepartment, filterStatus]);

  const resetForm = () => {
    setForm(initialForm);
    setEditingItem(null);
    setShowForm(false);
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      if (editingItem) {
        await specializationApi.update(editingItem._id, form);
        toast.success('Specialization updated successfully.');
      } else {
        await specializationApi.create(form);
        toast.success('Specialization created successfully.');
      }
      resetForm();
      loadData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to save specialization.');
    } finally {
      setSaving(false);
    }
  };

  const handleToggle = async (item) => {
    try {
      await specializationApi.toggleActive(item._id);
      toast.success(`${item.name} has been ${item.isActive ? 'deactivated' : 'activated'}.`);
      loadData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update specialization.');
    }
  };

  const departmentOptions = useMemo(() => departments, [departments]);

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="flex flex-col gap-4 rounded-2xl bg-card p-8 shadow-sm md:flex-row md:items-center md:justify-between">
        <div>
          <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Master Data</p>
          <h2 className="mt-2 text-3xl font-semibold text-foreground">Specializations</h2>
          <p className="mt-2 max-w-3xl text-muted-foreground">
            Manage doctor-facing specialization records and keep them mapped cleanly to departments for later doctor discovery and filtering.
          </p>
        </div>
        <Button
          onClick={() => {
            setEditingItem(null);
            setForm(initialForm);
            setShowForm(true);
          }}
        >
          <Plus className="mr-2 h-4 w-4" />
          Add Specialization
        </Button>
      </div>

      <div className="flex flex-col gap-3 lg:flex-row">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <input
            type="text"
            value={search}
            onChange={(event) => setSearch(event.target.value)}
            placeholder="Search by specialization name"
            className="w-full rounded-2xl border border-border bg-card py-3 pl-9 pr-4 text-sm outline-none focus:border-primary"
          />
        </div>
        <select
          value={filterDepartment}
          onChange={(event) => setFilterDepartment(event.target.value)}
          className="rounded-2xl border border-border bg-card px-4 py-3 text-sm outline-none focus:border-primary"
        >
          <option value="">All Departments</option>
          {departmentOptions.map((dept) => (
            <option key={dept._id} value={dept._id}>{dept.name}</option>
          ))}
        </select>
        <select
          value={filterStatus}
          onChange={(event) => setFilterStatus(event.target.value)}
          className="rounded-2xl border border-border bg-card px-4 py-3 text-sm outline-none focus:border-primary"
        >
          <option value="">All Statuses</option>
          <option value="true">Active</option>
          <option value="false">Inactive</option>
        </select>
        <Button type="button" variant="outline" onClick={loadData}>
