                  <th className="px-4 py-3 font-medium">Actions</th>
                </tr>
              </thead>
              <tbody>
                {loading && (
                  <tr>
                    <td colSpan={6} className="px-4 py-10 text-center text-muted-foreground">Loading wards...</td>
                  </tr>
                )}
                {!loading && wards.length === 0 && (
                  <tr>
                    <td colSpan={6} className="px-4 py-10 text-center text-muted-foreground">No wards found.</td>
                  </tr>
                )}
                {wards.map((ward) => (
                  <tr key={ward._id} className="border-b border-slate-100 last:border-b-0">
                    <td className="px-4 py-3">
                      <button type="button" className="text-left" onClick={() => setSelectedWardId(ward._id)}>
                        <p className="font-medium text-foreground">{ward.name}</p>
                        <p className="text-xs text-muted-foreground">{ward.wardNumber}</p>
                      </button>
                    </td>
                    <td className="px-4 py-3 capitalize text-muted-foreground">{ward.wardType}</td>
                    <td className="px-4 py-3 text-muted-foreground">
                      {ward.bedSummary?.totalBeds || 0}/{ward.bedCount || 0}
                    </td>
                    <td className="px-4 py-3 text-muted-foreground">Γé╣{Number(ward.defaultPrice || 0).toLocaleString()}</td>
                    <td className="px-4 py-3">
                      <span className={`rounded-full px-2.5 py-1 text-xs font-semibold ${ward.isActive ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>
                        {ward.isActive ? 'Active' : 'Inactive'}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex flex-wrap gap-2">
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          onClick={() => {
                            setEditingItem(ward);
                            setForm({
                              name: ward.name || '',
                              wardNumber: ward.wardNumber || '',
                              wardType: ward.wardType || 'general',
                              floor: ward.floor || '',
                              block: ward.block || '',
                              bedCount: ward.bedCount ?? '',
                              defaultPrice: ward.defaultPrice ?? '',
                              hospitalLocationId: ward.hospitalLocationId?._id || '',
                            });
                            setShowForm(true);
                          }}
                        >
                          Edit
                        </Button>
                        <Button type="button" variant={ward.isActive ? 'destructive' : 'outline'} size="sm" onClick={() => toggleActive(ward)}>
                          {ward.isActive ? <UserX className="mr-1 h-3 w-3" /> : <UserCheck className="mr-1 h-3 w-3" />}
                          {ward.isActive ? 'Deactivate' : 'Activate'}
                        </Button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </article>

        <article className="rounded-2xl bg-card p-6 shadow-sm">
          {!selectedWardDetail && <div className="py-24 text-center text-muted-foreground">Select a ward to review its occupancy and bed setup.</div>}
          {selectedWardDetail && (
            <div className="space-y-5">
              <div>
                <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Ward Detail</p>
                <h3 className="mt-2 text-2xl font-semibold text-foreground">{selectedWardDetail.ward.name}</h3>
                <p className="mt-1 text-sm text-muted-foreground">
                  {selectedWardDetail.ward.wardNumber} ΓÇó {selectedWardDetail.ward.wardType}
                  {selectedWardDetail.ward.floor ? ` ΓÇó Floor ${selectedWardDetail.ward.floor}` : ''}
                  {selectedWardDetail.ward.block ? ` ΓÇó Block ${selectedWardDetail.ward.block}` : ''}
                </p>
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <StatCard label="Default price" value={`Γé╣${Number(selectedWardDetail.ward.defaultPrice || 0).toLocaleString()}`} />
                <StatCard label="Configured beds" value={selectedWardDetail.ward.bedCount || 0} />
                <StatCard label="Available beds" value={selectedWardDetail.ward.bedSummary?.availableBeds || 0} />
                <StatCard label="Occupied beds" value={selectedWardDetail.ward.bedSummary?.occupiedBeds || 0} />
