import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Navigate, useLocation, useNavigate } from 'react-router-dom';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { Shield, Loader2, User, Stethoscope, Heart, FlaskConical, Pill, ClipboardList, Settings, Building2 } from 'lucide-react';
import { EMPLOYEE_ROLE_OPTIONS, getEmployeeHomeRoute } from '../../auth/constants.js';
import { loginEmployee } from '../../services/authService.js';
import { loginSuccess } from '../../store/authSlice.js';

const roleIcons = {
  superadmin: Shield,
  admin: Settings,
  subadmin: Building2,
  doctor: Stethoscope,
  nurse: Heart,
  receptionist: ClipboardList,
  labTechnician: FlaskConical,
  pharmacist: Pill,
};

export default function EmployeeLogin() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const { isAuthenticated, sessionType, user } = useSelector((state) => state.auth);
  const [formData, setFormData] = useState({ identifier: '', password: '', role: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [cooldownUntil, setCooldownUntil] = useState(0);
  const [cooldownNow, setCooldownNow] = useState(Date.now());

  if (isAuthenticated && sessionType === 'employee') {
    return <Navigate to={getEmployeeHomeRoute(user?.role)} replace />;
  }

  const updateField = (field, value) => setFormData((c) => ({ ...c, [field]: value }));

  useEffect(() => {
    if (!cooldownUntil) return;
    const timer = setInterval(() => setCooldownNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, [cooldownUntil]);

  const cooldownSeconds = Math.max(0, Math.ceil((cooldownUntil - cooldownNow) / 1000));

  const startCooldown = (err) => {
    if (err?.response?.status !== 429) return;
    const retryHeader = err.response?.headers?.['retry-after'];
    const retrySeconds = retryHeader ? Number(retryHeader) : 30;
    const safeSeconds = Number.isFinite(retrySeconds) && retrySeconds > 0 ? retrySeconds : 30;
    setCooldownUntil(Date.now() + safeSeconds * 1000);
    toast.error(`Too many requests. Try again in ${safeSeconds}s.`);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!formData.role) { toast.error('Select your role.'); return; }
    setIsLoading(true);
    try {
      const auth = await loginEmployee(formData.identifier, formData.password, formData.role);
      dispatch(loginSuccess(auth));
      localStorage.setItem('mediflow_auth', JSON.stringify(auth));
      toast.success(`Signed in as ${auth.user.role}.`);
      const fallback = location.state?.from?.pathname?.startsWith('/employee')
        ? location.state.from.pathname
        : getEmployeeHomeRoute(auth.user.role);
      navigate(fallback, { replace: true });
    } catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Invalid credentials.');
      }
    } finally { setIsLoading(false); }
  };

  return (
    <main className="relative flex min-h-screen items-center justify-center overflow-hidden bg-[oklch(0.10_0.02_260)] px-4 py-12">
      {/* Animated background blobs */}
      <div className="pointer-events-none absolute inset-0">
        <div className="absolute -top-40 -left-40 h-[500px] w-[500px] rounded-full bg-primary/5 blur-3xl animate-float" />
        <div className="absolute -bottom-40 -right-40 h-[400px] w-[400px] rounded-full bg-secondary/5 blur-3xl animate-float delay-300" />
      </div>

      <motion.section
        initial={{ opacity: 0, y: 24 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="relative z-10 w-full max-w-md"
      >
        <div className="rounded-3xl border border-white/10 bg-white/5 p-8 shadow-2xl backdrop-blur-xl">
          {/* Header */}
          <div className="mb-7">
            <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-primary/20">
              <Shield className="h-5 w-5 text-primary" />
            </div>
            <p className="mt-4 text-xs font-semibold uppercase tracking-[0.2em] text-white/50">Hospital System</p>
            <h1 className="mt-1 text-3xl font-bold text-white">Staff Sign In</h1>
            <p className="mt-2 text-sm text-white/60">
              Select your role and enter your credentials to access the employee portal.
            </p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Role selector as grid cards */}
            <div>
              <label className="mb-2 block text-sm font-medium text-white/80">Select Role</label>
              <div className="grid grid-cols-4 gap-2">
                {EMPLOYEE_ROLE_OPTIONS.map((role) => {
                  const Icon = roleIcons[role.value] || User;
                  const isSelected = formData.role === role.value;
                  return (
                    <button
                      key={role.value}
                      type="button"
                      onClick={() => updateField('role', role.value)}
                      className={`flex flex-col items-center gap-1.5 rounded-xl px-2 py-3 text-center transition-all ${
                        isSelected
                          ? 'bg-primary text-primary-foreground shadow-lg shadow-primary/30 scale-[1.02]'
                          : 'bg-white/5 text-white/60 hover:bg-white/10 hover:text-white/90'
                      }`}
                    >
                      <Icon className="h-4 w-4" />
                      <span className="text-[10px] font-medium leading-tight">{role.label}</span>
                    </button>
                  );
                })}
              </div>
            </div>

            <div>
              <label htmlFor="emp-id" className="mb-1.5 block text-sm font-medium text-white/80">Email or Employee ID</label>
              <input
                id="emp-id" type="text" value={formData.identifier}
                onChange={(e) => updateField('identifier', e.target.value)}
                placeholder="name@hospital.com or EMP-1001" required
                className="w-full rounded-xl border border-white/10 bg-white/5 px-4 py-2.5 text-sm text-white outline-none transition-colors placeholder:text-white/30 focus:border-primary focus:ring-2 focus:ring-primary/20"
              />
            </div>

            <div>
              <label htmlFor="emp-pw" className="mb-1.5 block text-sm font-medium text-white/80">Password</label>
              <input
                id="emp-pw" type="password" value={formData.password}
                onChange={(e) => updateField('password', e.target.value)} required
                className="w-full rounded-xl border border-white/10 bg-white/5 px-4 py-2.5 text-sm text-white outline-none transition-colors placeholder:text-white/30 focus:border-primary focus:ring-2 focus:ring-primary/20"
              />
            </div>

            <button
              type="submit" disabled={isLoading || cooldownSeconds > 0}
              className="flex w-full items-center justify-center gap-2 rounded-xl bg-primary px-4 py-3 text-sm font-semibold text-primary-foreground shadow-lg shadow-primary/20 transition-all hover:shadow-xl hover:brightness-110 disabled:opacity-60 disabled:cursor-not-allowed active:scale-[0.98]"
            >
              {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
              {isLoading ? 'Signing in...' : cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Sign In'}
            </button>
          </form>

          <div className="mt-6 text-center text-xs text-white/40">
            Patient or public visitor?{' '}
            <a href="/patient/login" className="font-medium text-primary hover:underline">Use the patient portal</a>
          </div>
        </div>
      </motion.section>
    </main>
  );
}

import { useEffect, useState } from 'react';
import { useSelector } from 'react-redux';
import { Navigate } from 'react-router-dom';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useDispatch } from 'react-redux';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';
import { Heart, Phone, Mail, KeyRound, HelpCircle, ArrowLeft, Loader2 } from 'lucide-react';
import {
  findAccountForHelp,
  forgotPassword,
  loginPatient,
  loginWithOtp,
  loginWithPhonePin,
  resetPassword,
  sendLoginOtp,
} from '../../services/authService.js';
import { loginSuccess } from '../../store/authSlice.js';
import { getEmployeeHomeRoute } from '../../auth/constants.js';

const initialResetState = {
  phone: '', pin: '', email: '', password: '', otp: '',
  firstName: '', lastName: '', dob: '',
  foundAccountEmail: '', obfuscatedEmail: '', newPassword: '', newPin: '',
};

const viewMeta = {
  phone: { icon: Phone, title: 'Sign in with PIN', subtitle: 'Enter your registered mobile number and 4-digit PIN.' },
  password: { icon: Mail, title: 'Sign in with Password', subtitle: 'Use your email or patient ID and password.' },
  otp: { icon: KeyRound, title: 'Verify OTP', subtitle: 'Enter the 6-digit code sent to your email.' },
  help: { icon: HelpCircle, title: 'Find My Account', subtitle: 'We\'ll look up your account using your personal details.' },
  reset: { icon: KeyRound, title: 'Reset Credentials', subtitle: 'Set a new password or PIN using the recovery code.' },
};

export default function PatientLogin() {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useDispatch();
  const { isAuthenticated, sessionType, user } = useSelector((state) => state.auth);
  const [view, setView] = useState('phone');
  const [isLoading, setIsLoading] = useState(false);
  const [form, setForm] = useState(initialResetState);
  const [cooldownUntil, setCooldownUntil] = useState(0);
  const [cooldownNow, setCooldownNow] = useState(Date.now());

  const updateField = (field, value) => {
    const digitOnlyFields = ['phone', 'pin', 'otp', 'newPin'];
    const cleanedValue = digitOnlyFields.includes(field) ? value.replace(/\D/g, '') : value;
    setForm((c) => ({ ...c, [field]: cleanedValue }));
  };

  useEffect(() => {
    if (!cooldownUntil) return;
    const timer = setInterval(() => setCooldownNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, [cooldownUntil]);

  const cooldownSeconds = Math.max(0, Math.ceil((cooldownUntil - cooldownNow) / 1000));

  const startCooldown = (err) => {
    if (err?.response?.status !== 429) return;
    const retryHeader = err.response?.headers?.['retry-after'];
    const retrySeconds = retryHeader ? Number(retryHeader) : 30;
    const safeSeconds = Number.isFinite(retrySeconds) && retrySeconds > 0 ? retrySeconds : 30;
    setCooldownUntil(Date.now() + safeSeconds * 1000);
    toast.error(`Too many requests. Try again in ${safeSeconds}s.`);
  };

  if (isAuthenticated) {
    if (sessionType === 'patient' && user?.role === 'patient') return <Navigate to="/patient/dashboard" replace />;
    return <Navigate to={getEmployeeHomeRoute(user?.role)} replace />;
  }

  const completeLogin = ({ user, token, sessionType }) => {
    dispatch(loginSuccess({ user, token, sessionType }));
    localStorage.setItem('mediflow_auth', JSON.stringify({ user, token, sessionType }));
    toast.success(`Welcome back, ${user.name}!`);
    const fallback = location.state?.from?.pathname?.startsWith('/patient') ? location.state.from.pathname : '/patient';
    navigate(fallback, { replace: true });
  };

  const handlePhoneLogin = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!/^\d{10}$/.test(form.phone)) { toast.error('Enter a valid 10-digit phone number.'); return; }
    if (!/^\d{4}$/.test(form.pin)) { toast.error('Enter a valid 4-digit PIN.'); return; }
    setIsLoading(true);
    try { completeLogin(await loginWithPhonePin(form.phone, form.pin)); }
    catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Login failed.');
      }
    }
    finally { setIsLoading(false); }
  };

  const handlePasswordLogin = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!form.email || !form.password) { toast.error('Email and password are required.'); return; }
    setIsLoading(true);
    try { completeLogin(await loginPatient(form.email, form.password)); }
    catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Login failed.');
      }
    }
    finally { setIsLoading(false); }
  };

  const handleSendLoginOtp = async () => {
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!form.email) { toast.error('Enter your email first.'); return; }
    setIsLoading(true);
    try { await sendLoginOtp(form.email); toast.success('OTP sent.'); setView('otp'); }
    catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Unable to send OTP.');
      }
    }
    finally { setIsLoading(false); }
  };

  const handleOtpLogin = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!form.email || !form.otp) { toast.error('Email and OTP are required.'); return; }
    setIsLoading(true);
    try { completeLogin(await loginWithOtp(form.email, form.otp)); }
    catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'OTP login failed.');
      }
    }
    finally { setIsLoading(false); }
  };

  const handleFindAccount = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!form.firstName || !form.lastName || !form.dob) { toast.error('All fields are required.'); return; }
    setIsLoading(true);
    try {
      const account = await findAccountForHelp(form.firstName, form.lastName, form.dob);
      updateField('foundAccountEmail', account.email);
      updateField('obfuscatedEmail', account.obfuscatedEmail);
      await forgotPassword(account.email);
      toast.success(`Recovery code sent to ${account.obfuscatedEmail}.`);
      setView('reset');
    } catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Account not found.');
      }
    }
    finally { setIsLoading(false); }
  };

  const handleResetCredentials = async (e) => {
    e.preventDefault();
    if (cooldownSeconds > 0) { toast.error(`Please wait ${cooldownSeconds}s before retrying.`); return; }
    if (!form.foundAccountEmail || !form.otp || (!form.newPassword && !form.newPin)) {
      toast.error('OTP and a new password or PIN are required.'); return;
    }
    setIsLoading(true);
    try {
      await resetPassword(form.foundAccountEmail, form.otp, form.newPassword, form.newPin);
      toast.success('Credentials updated. Please sign in.');
      setForm(initialResetState); setView('phone');
    } catch (err) {
      startCooldown(err);
      if (err?.response?.status !== 429) {
        toast.error(err.response?.data?.message || 'Reset failed.');
      }
    }
    finally { setIsLoading(false); }
  };

  const meta = viewMeta[view];
  const ViewIcon = meta.icon;

  return (
    <section className="flex min-h-[calc(100vh-160px)] items-center justify-center px-4 py-12 sm:px-6">
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
        className="w-full max-w-md"
      >
        <div className="rounded-3xl border border-border bg-card p-8 shadow-xl shadow-primary/5">
          {/* Header */}
          <div className="mb-7 flex items-start gap-4">
            <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-primary/10">
              <ViewIcon className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-xs font-semibold uppercase tracking-[0.15em] text-muted-foreground">Patient Portal</p>
              <h1 className="mt-1 text-2xl font-bold text-foreground">{meta.title}</h1>
              <p className="mt-1 text-sm text-muted-foreground">{meta.subtitle}</p>
            </div>
          </div>

          <div className="mb-6 rounded-xl bg-muted/50 px-4 py-3 text-xs text-muted-foreground">
            This sign-in is for patients. Hospital staff should use the{' '}
            <Link to="/employee/login" className="font-medium text-primary hover:underline">employee portal</Link>.
          </div>

          {/* Forms */}
          <AnimatePresence mode="wait">
            <motion.div key={view} initial={{ opacity: 0, x: 12 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -12 }} transition={{ duration: 0.2 }}>
              {view === 'phone' && (
                <form onSubmit={handlePhoneLogin} className="space-y-4">
                  <Field id="patient-phone" label="Mobile Number" type="tel" placeholder="10-digit phone number" maxLength={10} value={form.phone} onChange={(v) => updateField('phone', v)} />
                  <Field id="patient-pin" label="4-digit PIN" type="password" placeholder="Enter PIN" maxLength={4} value={form.pin} onChange={(v) => updateField('pin', v)} />
                  <SubmitButton loading={isLoading} disabled={cooldownSeconds > 0}>
                    {cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Login with PIN'}
                  </SubmitButton>
                </form>
              )}

              {view === 'password' && (
                <form onSubmit={handlePasswordLogin} className="space-y-4">
                  <Field id="patient-email" label="Email or Patient ID" type="text" placeholder="name@example.com or PAT-123456" value={form.email} onChange={(v) => updateField('email', v)} />
                  <Field id="patient-password" label="Password" type="password" placeholder="Enter password" value={form.password} onChange={(v) => updateField('password', v)} />
                  <SubmitButton loading={isLoading} disabled={cooldownSeconds > 0}>
                    {cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Login with Password'}
                  </SubmitButton>
                  <button type="button" onClick={handleSendLoginOtp} className="w-full rounded-xl border border-border px-4 py-2.5 text-sm font-medium text-foreground transition-colors hover:bg-muted">
                    Send OTP Instead
                  </button>
                </form>
              )}

              {view === 'otp' && (
                <form onSubmit={handleOtpLogin} className="space-y-4">
                  <Field id="patient-otp" label="6-digit OTP" type="text" placeholder="Enter OTP" maxLength={6} value={form.otp} onChange={(v) => updateField('otp', v)} />
                  <SubmitButton loading={isLoading} disabled={cooldownSeconds > 0}>
                    {cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Verify and Login'}
                  </SubmitButton>
                </form>
              )}

              {view === 'help' && (
                <form onSubmit={handleFindAccount} className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <Field id="patient-first-name" label="First Name" type="text" value={form.firstName} onChange={(v) => updateField('firstName', v)} />
                    <Field id="patient-last-name" label="Last Name" type="text" value={form.lastName} onChange={(v) => updateField('lastName', v)} />
                  </div>
                  <Field id="patient-dob" label="Date of Birth" type="date" value={form.dob} onChange={(v) => updateField('dob', v)} />
                  <SubmitButton loading={isLoading} disabled={cooldownSeconds > 0}>
                    {cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Find My Account'}
                  </SubmitButton>
                </form>
              )}

              {view === 'reset' && (
                <form onSubmit={handleResetCredentials} className="space-y-4">
                  <div className="rounded-xl bg-muted/50 px-4 py-3 text-sm text-muted-foreground">
                    Recovery code sent to {form.obfuscatedEmail || 'your email'}.
                  </div>
                  <Field id="reset-otp" label="OTP" type="text" maxLength={6} value={form.otp} onChange={(v) => updateField('otp', v)} />
                  <Field id="reset-password" label="New Password" type="password" value={form.newPassword} onChange={(v) => updateField('newPassword', v)} />
                  <Field id="reset-pin" label="New PIN" type="password" maxLength={4} value={form.newPin} onChange={(v) => updateField('newPin', v)} />
                  <SubmitButton loading={isLoading} disabled={cooldownSeconds > 0}>
                    {cooldownSeconds > 0 ? `Try again in ${cooldownSeconds}s` : 'Reset Credentials'}
                  </SubmitButton>
                </form>
              )}
            </motion.div>
          </AnimatePresence>

          {/* View switchers */}
          <div className="mt-5 flex flex-wrap gap-2 text-sm">
            {view !== 'phone' && (
              <button type="button" onClick={() => setView('phone')} className="flex items-center gap-1 text-primary hover:underline">
                <ArrowLeft className="h-3 w-3" /> PIN Login
              </button>
            )}
            {view !== 'password' && view !== 'otp' && view !== 'help' && view !== 'reset' && (
              <button type="button" onClick={() => setView('password')} className="text-primary hover:underline">Password Login</button>
            )}
            {view !== 'help' && view !== 'reset' && (
              <button type="button" onClick={() => setView('help')} className="text-muted-foreground hover:text-foreground">Need help?</button>
            )}
          </div>

          {/* Register link */}
          <div className="mt-6 border-t border-border pt-5 text-sm text-muted-foreground">
            New patient?{' '}
            <Link to="/patient/register" className="font-semibold text-primary hover:underline">Create an account</Link>
          </div>
        </div>
      </motion.div>
    </section>
  );
}

function Field({ id, label, type, placeholder, maxLength, pattern, value, onChange, required }) {
  return (
    <div>
      <label htmlFor={id} className="mb-1.5 block text-sm font-medium text-foreground">{label}</label>
      <input
        id={id} type={type} value={value} placeholder={placeholder} maxLength={maxLength} pattern={pattern}
        onChange={(e) => onChange(e.target.value)} required={required}
        className="w-full rounded-xl border border-border bg-background px-4 py-2.5 text-sm text-foreground outline-none transition-colors focus:border-primary focus:ring-2 focus:ring-primary/20"
      />
    </div>
  );
}

function SubmitButton({ children, loading, disabled }) {
  return (
    <button
      type="submit" disabled={loading || disabled}
      className="flex w-full items-center justify-center gap-2 rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-sm transition-all hover:shadow-md hover:brightness-110 disabled:opacity-60 disabled:cursor-not-allowed active:scale-[0.98]"
    >
      {loading && <Loader2 className="h-4 w-4 animate-spin" />}
      {loading ? 'Please wait...' : children}
    </button>
  );
}

import { useState } from 'react';
import { Link, Navigate, useNavigate } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { UserPlus, Loader2 } from 'lucide-react';
import { loginSuccess } from '../../store/authSlice.js';
import { registerPatient } from '../../services/authService.js';
import { getEmployeeHomeRoute } from '../../auth/constants.js';

const initialForm = { name: '', dob: '', email: '', phone: '', password: '', pin: '' };

export default function PatientRegister() {
  const navigate = useNavigate();
  const dispatch = useDispatch();
  const { isAuthenticated, sessionType, user } = useSelector((state) => state.auth);
  const [formData, setFormData] = useState(initialForm);
  const [isLoading, setIsLoading] = useState(false);
  const updateField = (field, value) => setFormData((c) => ({ ...c, [field]: value }));

  if (isAuthenticated) {
    if (sessionType === 'patient' && user?.role === 'patient') return <Navigate to="/patient/dashboard" replace />;
    return <Navigate to={getEmployeeHomeRoute(user?.role)} replace />;
  }

  const handleRegister = async (e) => {
    e.preventDefault();
    if (!formData.password && !formData.pin) { toast.error('Choose a password, a PIN, or both.'); return; }
    setIsLoading(true);
    try {
      const auth = await registerPatient(formData);
      dispatch(loginSuccess(auth));
      localStorage.setItem('mediflow_auth', JSON.stringify(auth));
      toast.success('Account created successfully.');
      navigate('/patient', { replace: true });
    } catch (err) { toast.error(err.response?.data?.message || 'Registration failed.'); }
    finally { setIsLoading(false); }
  };

  return (
    <section className="flex min-h-[calc(100vh-160px)] items-center justify-center px-4 py-12 sm:px-6">
      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }} className="w-full max-w-xl">
        <div className="rounded-3xl border border-border bg-card p-8 shadow-xl shadow-primary/5">
          {/* Header */}
          <div className="mb-7 flex items-start gap-4">
            <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-primary/10">
              <UserPlus className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="text-xs font-semibold uppercase tracking-[0.15em] text-muted-foreground">Patient Registration</p>
              <h1 className="mt-1 text-2xl font-bold text-foreground">Create your account</h1>
              <p className="mt-1 text-sm text-muted-foreground">Access appointments, bills, prescriptions, lab reports, and more.</p>
            </div>
          </div>

          <div className="mb-6 rounded-xl bg-muted/50 px-4 py-3 text-xs text-muted-foreground">
            Staff access is managed through the <Link to="/employee/login" className="font-medium text-primary hover:underline">employee portal</Link>.
          </div>

          <form onSubmit={handleRegister} className="space-y-4">
            <div className="grid gap-4 sm:grid-cols-2">
              <Field id="register-name" label="Full Name" type="text" value={formData.name} onChange={(v) => updateField('name', v)} required />
              <Field id="register-dob" label="Date of Birth" type="date" value={formData.dob} onChange={(v) => updateField('dob', v)} required />
            </div>
            <Field id="register-email" label="Email" type="email" value={formData.email} onChange={(v) => updateField('email', v)} required />
            <div className="grid gap-4 sm:grid-cols-2">
              <Field id="register-phone" label="Phone Number" type="tel" maxLength={10} pattern="[0-9]{10}" value={formData.phone} onChange={(v) => updateField('phone', v)} required />
              <Field id="register-pin" label="4-digit PIN" type="password" maxLength={4} pattern="[0-9]{4}" value={formData.pin} onChange={(v) => updateField('pin', v)} />
            </div>
            <Field id="register-password" label="Password" type="password" value={formData.password} onChange={(v) => updateField('password', v)} />

            <button
              type="submit" disabled={isLoading}
              className="flex w-full items-center justify-center gap-2 rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-sm transition-all hover:shadow-md hover:brightness-110 disabled:opacity-60 disabled:cursor-not-allowed active:scale-[0.98]"
            >
              {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
              {isLoading ? 'Creating account...' : 'Create Account'}
            </button>
          </form>

          <div className="mt-6 border-t border-border pt-5 text-sm text-muted-foreground">
            Already have an account?{' '}
            <Link to="/patient/login" className="font-semibold text-primary hover:underline">Sign in</Link>
          </div>
        </div>
      </motion.div>
    </section>
  );
}

function Field({ id, label, type, placeholder, maxLength, pattern, value, onChange, required }) {
  return (
    <div>
      <label htmlFor={id} className="mb-1.5 block text-sm font-medium text-foreground">{label}</label>
      <input
        id={id} type={type} value={value} placeholder={placeholder} maxLength={maxLength} pattern={pattern}
        onChange={(e) => onChange(e.target.value)} required={required}
        className="w-full rounded-xl border border-border bg-background px-4 py-2.5 text-sm text-foreground outline-none transition-colors focus:border-primary focus:ring-2 focus:ring-primary/20"
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '../../components/ui/dialog.jsx';
import { StatusBadge, DataTable, LoadingSkeleton, ErrorState } from '../../components';
import { appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { Calendar, Clock, Play, Eye, Stethoscope, AlertTriangle, FileText } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function DoctorAppointments() {
  const navigate = useNavigate();
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [startingConsultation, setStartingConsultation] = useState(null);
  const [quickViewOpen, setQuickViewOpen] = useState(false);
  const [quickViewData, setQuickViewData] = useState(null);
  const [quickViewLoading, setQuickViewLoading] = useState(false);

  useEffect(() => {
    fetchTodayAppointments();
  }, []);

  const fetchTodayAppointments = async () => {
    try {
      setLoading(true);
      setError(null);
      const response = await appointmentApi.getDoctorToday();
      const normalized = Array.isArray(response) ? response : response?.data || [];
      setTodayAppointments(Array.isArray(normalized) ? normalized : []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch appointments');
      toast.error('Failed to load appointments');
    } finally {
      setLoading(false);
    }
  };

  const handleStartConsultation = async (appointmentId) => {
    try {
      setStartingConsultation(appointmentId);
      await appointmentApi.startConsultation(appointmentId);
      toast.success('Consultation started');
      fetchTodayAppointments();
      // Redirect to patient summary
      navigate(`/doctor/appointments/${appointmentId}/summary`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to start consultation');
    } finally {
      setStartingConsultation(null);
    }
  };

  const openQuickView = async (appointment) => {
    try {
      setQuickViewLoading(true);
      setQuickViewOpen(true);
      const summary = await appointmentApi.getPatientSummary(appointment.patientId?._id || appointment.patientId);
      setQuickViewData({ appointment, summary });
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to load patient quick view');
      setQuickViewData(null);
    } finally {
      setQuickViewLoading(false);
    }
  };

  const closeQuickView = () => {
    setQuickViewOpen(false);
    setQuickViewData(null);
  };

  const buildTriageFlags = (summary) => {
    const patient = summary?.patient;
    const flags = [];
    if (!patient) return flags;
    if (patient.allergies?.length) flags.push({ label: 'Allergy risk', tone: 'bg-orange-500/10 text-orange-600' });
    if (patient.chronicDiseases?.length) flags.push({ label: 'Chronic conditions', tone: 'bg-amber-500/10 text-amber-600' });
    if (patient.latestVitals) {
      const { temperature, spo2, pulse, bloodPressure } = patient.latestVitals;
      const highTemp = temperature && Number(temperature) >= 100;
      const lowSpo2 = spo2 && Number(spo2) < 94;
      const highPulse = pulse && Number(pulse) > 100;
      const highBp = bloodPressure && bloodPressure.split('/').some((val) => Number(val) >= 140);
      if (highTemp || lowSpo2 || highPulse || highBp) {
        flags.push({ label: 'Vitals need review', tone: 'bg-red-500/10 text-red-600' });
      }
    }
    return flags;
  };

  const isImageReport = (url = '') => /\.(png|jpe?g|gif|webp)$/i.test(url);

  const columns = [
    {
      key: 'slot',
      label: 'Time',
      sortable: true,
      render: (slot) => (
        <div className="flex items-center gap-2">
          <Clock className="h-4 w-4 text-muted-foreground" />
          {slot}
        </div>
      ),
    },
    {
      key: 'patientId',
      label: 'Patient',
      sortable: true,
      render: (patient) => (
        <div className="flex flex-col">
          <span className="font-medium">{patient?.name || 'N/A'}</span>
          <span className="text-xs text-muted-foreground">{patient?.phone || 'N/A'}</span>
        </div>
      ),
    },
    {
      key: 'patientProfileId',
      label: 'Age / Gender',
      render: (profile) => (
        <div className="text-sm">
          {profile?.age ? `${profile.age}y` : 'N/A'} / {profile?.gender || 'N/A'}
        </div>
      ),
    },
    {
      key: 'consultationMode',
      label: 'Mode',
      render: (mode) => (
        <span className="text-xs px-2 py-1 rounded-full bg-primary/10 text-primary">
          {mode || 'In-person'}
        </span>
      ),
    },
    {
      key: 'status',
      label: 'Status',
      render: (status) => <StatusBadge status={status} />,
    },
    {
      key: '_id',
      label: 'Actions',
      render: (_, row) => (
        <div className="flex gap-2">
          {['booked', 'confirmed', 'arrived', 'checked-in'].includes(row.status) && (
            <Button
              size="sm"
              variant="default"
              onClick={() => handleStartConsultation(row._id)}
              disabled={startingConsultation === row._id}
              className="text-xs"
            >
              <Play className="h-3 w-3 mr-1" />
              {startingConsultation === row._id ? 'Starting...' : 'Start'}
            </Button>
          )}
          <Button
            size="sm"
            variant="outline"
            onClick={() => openQuickView(row)}
            className="text-xs"
          >
            <Stethoscope className="h-3 w-3 mr-1" /> Quick view
          </Button>
          <Button
            size="sm"
            variant="outline"
            onClick={() => navigate(`/doctor/appointments/${row._id}/summary`)}
            className="text-xs"
          >
            <Eye className="h-3 w-3 mr-1" /> View
          </Button>
        </div>
      ),
    },
  ];

  if (loading) return <LoadingSkeleton />;

  const _completed = todayAppointments.filter((a) => a.status === 'completed').length;
  const _inProgress = todayAppointments.filter((a) =>
    ['arrived', 'checked-in', 'inConsultation'].includes(a.status)
  ).length;
  const _pending = todayAppointments.filter((a) =>
    ['booked', 'confirmed'].includes(a.status)
  ).length;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Today's Appointments</h2>
          <p className="text-muted-foreground">
            {new Date().toLocaleDateString('en-US', {
              weekday: 'long',
              year: 'numeric',
              month: 'long',
              day: 'numeric',
            })}
          </p>
        </div>
        <Button variant="outline" onClick={fetchTodayAppointments}>
          <Calendar className="mr-2 h-4 w-4" /> Refresh
        </Button>
      </div>

      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card className="bg-background/50">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total Appointments</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{todayAppointments.length}</div>
          </CardContent>
        </Card>
        <Card className="bg-background/50">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pending</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-blue-600">{_pending}</div>
          </CardContent>
        </Card>
        <Card className="bg-background/50">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Completed</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">{_completed}</div>
          </CardContent>
        </Card>
      </div>

      {error && <ErrorState error={error} onRetry={fetchTodayAppointments} />}

      {/* Appointments Table */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calendar className="h-5 w-5" /> Appointments Queue ({todayAppointments.length})
          </CardTitle>
        </CardHeader>
        <CardContent>
          {todayAppointments.length === 0 ? (
            <div className="text-center py-12">
              <Calendar className="mx-auto h-12 w-12 text-muted-foreground/50 mb-4" />
              <p className="text-muted-foreground">No appointments scheduled for today</p>
            </div>
          ) : (
            <DataTable
              data={todayAppointments}
              columns={columns}
              keyField="_id"
            />
          )}
        </CardContent>
      </Card>

      <Dialog open={quickViewOpen} onOpenChange={closeQuickView}>
        <DialogContent className="h-[100dvh] max-w-2xl rounded-none sm:rounded-l-3xl sm:rounded-r-none sm:ml-auto sm:mr-0 sm:w-[42rem] sm:max-w-[42rem]">
          <DialogHeader>
            <DialogTitle>Patient chart drawer</DialogTitle>
            <DialogDescription>Full chart snapshot with labs and prescription history.</DialogDescription>
          </DialogHeader>
          {quickViewLoading && (
            <div className="py-10 text-center text-muted-foreground">Loading patient summaryΓÇª</div>
          )}
          {!quickViewLoading && quickViewData && (
            <div className="space-y-5 overflow-y-auto pr-2">
              <div className="rounded-xl border border-border p-4">
                <p className="text-xs uppercase tracking-[0.18em] text-muted-foreground">Patient</p>
                <p className="mt-2 text-lg font-semibold text-foreground">
                  {quickViewData.summary?.patient?.name || 'Patient'}
                </p>
                <p className="text-sm text-muted-foreground">
                  {quickViewData.summary?.patient?.patientId || 'No ID'} ΓÇó {quickViewData.summary?.patient?.age || 'ΓÇö'}y ΓÇó {quickViewData.summary?.patient?.gender || 'ΓÇö'}
                </p>
              </div>

              <div className="flex flex-wrap gap-2">
                {buildTriageFlags(quickViewData.summary).map((flag) => (
                  <span key={flag.label} className={`rounded-full px-3 py-1 text-xs font-semibold ${flag.tone}`}>
                    {flag.label}
                  </span>
                ))}
                {buildTriageFlags(quickViewData.summary).length === 0 && (
                  <span className="rounded-full bg-emerald-500/10 px-3 py-1 text-xs font-semibold text-emerald-600">
                    No high-risk flags detected
                  </span>
                )}
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="rounded-xl border border-border p-4">
                  <p className="text-sm font-semibold text-foreground flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4" /> Allergies & Conditions
                  </p>
                  <p className="mt-2 text-sm text-muted-foreground">
                    Allergies: {quickViewData.summary?.patient?.allergies?.length ? quickViewData.summary.patient.allergies.join(', ') : 'None reported'}
                  </p>
                  <p className="mt-1 text-sm text-muted-foreground">
                    Chronic: {quickViewData.summary?.patient?.chronicDiseases?.length ? quickViewData.summary.patient.chronicDiseases.join(', ') : 'None listed'}
                  </p>
                </div>
                <div className="rounded-xl border border-border p-4">
                  <p className="text-sm font-semibold text-foreground flex items-center gap-2">
                    <FileText className="h-4 w-4" /> Latest vitals
                  </p>
                  {quickViewData.summary?.patient?.latestVitals ? (
                    <div className="mt-2 text-sm text-muted-foreground space-y-1">
                      <p>BP: {quickViewData.summary.patient.latestVitals.bloodPressure || 'ΓÇö'}</p>
                      <p>Pulse: {quickViewData.summary.patient.latestVitals.pulse || 'ΓÇö'}</p>
                      <p>Temp: {quickViewData.summary.patient.latestVitals.temperature || 'ΓÇö'}</p>
                      <p>SpO2: {quickViewData.summary.patient.latestVitals.spo2 || 'ΓÇö'}</p>
                    </div>
                  ) : (
                    <p className="mt-2 text-sm text-muted-foreground">No vitals recorded yet.</p>
                  )}
                </div>
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <div className="rounded-xl border border-border p-4">
                  <p className="text-sm font-semibold text-foreground">Lab orders needing attention</p>
                  <div className="mt-2 space-y-2">
                    {(quickViewData.summary?.recentLabOrders || []).map((order) => (
                      <div key={order._id} className="flex flex-wrap items-center justify-between gap-2 rounded-lg bg-muted/50 px-3 py-2 text-sm">
                        <span>{order.orderNumber || 'Lab order'} ΓÇó {order.status}</span>
                        <span className="text-xs text-muted-foreground">{order.paymentStatus || 'pending'}</span>
                      </div>
                    ))}
                    {(quickViewData.summary?.recentLabOrders || []).length === 0 && (
                      <p className="text-sm text-muted-foreground">No lab orders in the recent list.</p>
                    )}
                  </div>
                </div>
                <div className="rounded-xl border border-border p-4">
                  <p className="text-sm font-semibold text-foreground">Prescription history</p>
                  <div className="mt-2 space-y-2">
                    {(quickViewData.summary?.recentPrescriptions || []).map((prescription) => (
                      <div key={prescription._id} className="rounded-lg bg-muted/50 px-3 py-2 text-sm">
                        <p className="font-medium text-foreground">{prescription.diagnosis || 'Prescription'}</p>
                        <p className="text-xs text-muted-foreground">
                          {prescription.medicines?.map((med) => med.name).filter(Boolean).join(', ') || 'No medicines listed'}
                        </p>
                      </div>
                    ))}
                    {(quickViewData.summary?.recentPrescriptions || []).length === 0 && (
                      <p className="text-sm text-muted-foreground">No recent prescriptions on record.</p>
                    )}
                  </div>
                </div>
              </div>

              <div className="rounded-xl border border-border p-4">
                <p className="text-sm font-semibold text-foreground">Lab report previews</p>
                <div className="mt-3 grid gap-3 md:grid-cols-2">
                  {(quickViewData.summary?.recentLabReports || []).map((report) => (
                    <div key={report._id} className="rounded-lg border border-border/60 bg-muted/40 p-3">
                      <p className="font-medium text-foreground">{report.reportName || 'Lab report'}</p>
                      <p className="text-xs text-muted-foreground">{report.reportType || 'Diagnostic report'}</p>
                      {report.reportFile && isImageReport(report.reportFile) && (
                        <img src={report.reportFile} alt={report.reportName} className="mt-2 h-32 w-full rounded-lg object-cover" />
                      )}
                      {report.reportFile && (
                        <a
                          href={report.reportFile}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="mt-2 inline-flex text-xs font-semibold text-primary hover:underline"
                        >
                          Open report file
                        </a>
                      )}
                    </div>
                  ))}
                  {(quickViewData.summary?.recentLabReports || []).length === 0 && (
                    <p className="text-sm text-muted-foreground">No lab reports available yet.</p>
                  )}
                </div>
              </div>
            </div>
          )}
          <DialogFooter>
            <Button variant="outline" onClick={closeQuickView}>Close</Button>
            {quickViewData?.appointment?._id && (
              <Button onClick={() => navigate(`/doctor/appointments/${quickViewData.appointment._id}/summary`)}>
                Full summary
              </Button>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../../components/ui/card';
import { Input } from '../../components/ui/input';
import { Label } from '../../components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../../components/ui/select';
import { FormDialog, LoadingSkeleton, ErrorState } from '../../components';
import { availabilityApi } from '../../services/apiServices';
import { useAuth } from '../../hooks';
import { toast } from 'sonner';
import { Clock, Plus, Edit2 } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const DAYS_OF_WEEK = [
  'Sunday',
  'Monday',
  'Tuesday',
  'Wednesday',
  'Thursday',
  'Friday',
  'Saturday',
];

export default function DoctorAvailability() {
  const { user } = useAuth();
  const canEdit = ['admin', 'superadmin'].includes(user?.role);
  const [availabilities, setAvailabilities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  useEffect(() => {
    if (user?.id) {
      fetchAvailabilities();
    }
  }, [user?.id]);

  const fetchAvailabilities = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await availabilityApi.getByDoctor(user.id);
      setAvailabilities(Array.isArray(data) ? data : []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch availability');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (formData) => {
    if (!canEdit) {
      toast.error('Availability is managed by the hospital admin.');
      return;
    }
    try {
      const submitData = {
        ...formData,
        doctorId: user.id,
      };
      await availabilityApi.create(submitData);
      toast.success('Availability updated successfully');
      setShowForm(false);
      setEditingId(null);
      fetchAvailabilities();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to save availability');
    }
  };

  const formFields = [
    {
      name: 'dayOfWeek',
      label: 'Day of Week',
      type: 'select',
      required: true,
      options: DAYS_OF_WEEK,
    },
    {
      name: 'startTime',
      label: 'Start Time (HH:MM)',
      type: 'time',
      required: true,
      placeholder: '09:00',
    },
    {
      name: 'endTime',
      label: 'End Time (HH:MM)',
      type: 'time',
      required: true,
      placeholder: '17:00',
    },
    {
      name: 'slotDuration',
      label: 'Slot Duration (minutes)',
      type: 'number',
      required: true,
      placeholder: '30',
    },
  ];

  if (loading) return <LoadingSkeleton />;
  if (error) return <ErrorState error={error} />;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Your Availability</h2>
          <p className="text-muted-foreground">
            {canEdit ? 'Set your working hours and appointment slots' : 'Availability is managed by the hospital admin team.'}
          </p>
        </div>
        {canEdit && (
          <Button
            onClick={() => {
              setEditingId(null);
              setShowForm(true);
            }}
            className="shadow-md shadow-primary/20"
          >
            <Plus className="h-4 w-4 mr-2" /> Add Schedule
          </Button>
        )}
      </div>

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
        {DAYS_OF_WEEK.map((day) => {
          const dayAvailability = availabilities.find((a) => a.dayOfWeek === day);
          return (
            <Card key={day} className="border-border/50 bg-background/50 backdrop-blur-sm">
              <CardHeader className="pb-3">
                <CardTitle className="text-base">{day}</CardTitle>
              </CardHeader>
              <CardContent className="space-y-2">
                {dayAvailability ? (
                  <>
                    <div className="flex items-center text-sm">
                      <Clock className="h-4 w-4 mr-2 text-primary" />
                      <span className="font-medium">
                        {dayAvailability.startTime} - {dayAvailability.endTime}
                      </span>
                    </div>
                    <div className="text-xs text-muted-foreground">
                      Slot: {dayAvailability.slotDuration} mins
                    </div>
                    {canEdit && (
                      <Button
                        size="sm"
                        variant="outline"
                        className="w-full mt-2 text-xs"
                        onClick={() => {
                          setEditingId(dayAvailability._id);
                          setShowForm(true);
                        }}
                      >
                        <Edit2 className="h-3 w-3 mr-1" /> Edit
                      </Button>
                    )}
                  </>
                ) : (
                  <div className="text-xs text-muted-foreground text-center py-4">
                    Not available
                  </div>
                )}
              </CardContent>
            </Card>
          );
        })}
      </div>

      <FormDialog
        isOpen={showForm}
        onClose={() => {
          setShowForm(false);
          setEditingId(null);
        }}
        onSubmit={handleSubmit}
        title={editingId ? 'Edit Schedule' : 'Add New Schedule'}
        description="Set your availability for this day"
        fields={formFields}
      />

      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle>Schedule Summary</CardTitle>
          <CardDescription>
            You have availability set for {availabilities.length} day(s) per week
          </CardDescription>
        </CardHeader>
        <CardContent>
          {availabilities.length === 0 ? (
            <p className="text-muted-foreground text-sm">
              No availability set. Add your working hours to accept appointments.
            </p>
          ) : (
            <div className="space-y-2">
              {availabilities.map((avail) => (
                <div key={avail._id} className="flex justify-between items-center p-3 bg-muted/50 rounded">
                  <div>
                    <p className="font-medium text-sm">{avail.dayOfWeek}</p>
                    <p className="text-xs text-muted-foreground">
                      {avail.startTime} - {avail.endTime} ({avail.slotDuration} min slots)
                    </p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { Calendar, Clock, Activity, FileText, AlertCircle, ClipboardList, Stethoscope } from 'lucide-react';
import { LoadingSkeleton, ErrorState } from '../../components';
import { doctorApi, appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { formatDate } from '../../utils/formatters';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function DoctorDashboard() {
  const [dashboardData, setDashboardData] = useState(null);
  const [todayQueue, setTodayQueue] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [startingConsultation, setStartingConsultation] = useState(null);

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    try {
      setLoading(true);
      setError(null);
      const [data, todayAppointments] = await Promise.all([
        doctorApi.getDashboard(),
        appointmentApi.getDoctorToday(),
      ]);
      setDashboardData(data);
      setTodayQueue(Array.isArray(todayAppointments) ? todayAppointments : []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load dashboard');
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <LoadingSkeleton />;

  if (error) return <ErrorState error={error} onRetry={fetchDashboard} />;

  const stats = dashboardData?.todayStats || {
    total: 0,
    completed: 0,
    inProgress: 0,
    pending: 0,
  };

  const doctorName = dashboardData?.doctor?.userId?.name || 'Doctor';
  const departmentName = dashboardData?.doctor?.departmentId?.name || 'Department';
  const nextAppointment =
    todayQueue?.find((apt) => ['booked', 'confirmed', 'arrived', 'checked-in', 'inConsultation'].includes(apt.status)) ||
    dashboardData?.upcomingAppointments?.[0];

  const handleStartConsultation = async (appointmentId) => {
    try {
      setStartingConsultation(appointmentId);
      await appointmentApi.startConsultation(appointmentId);
      toast.success('Consultation started');
      fetchDashboard();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to start consultation');
    } finally {
      setStartingConsultation(null);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold tracking-tight">Welcome back, {doctorName}</h2>
          <p className="text-muted-foreground">
            {departmentName} ΓÇó {new Date().toLocaleDateString('en-US', {
              weekday: 'long',
              year: 'numeric',
              month: 'long',
              day: 'numeric',
            })}
          </p>
        </div>
        <div className="flex gap-2">
          <Button asChild variant="outline">
            <Link to="/doctor/appointments">
              <Calendar className="mr-2 h-4 w-4" /> View Queue
            </Link>
          </Button>
          <Button asChild>
            <Link to="/doctor/availability">
              <Clock className="mr-2 h-4 w-4" /> Schedule
            </Link>
          </Button>
        </div>
      </div>

      <Card className="border-border/50 bg-background/60 backdrop-blur-sm">
        <CardHeader className="flex flex-row items-center justify-between">
          <div>
            <CardTitle className="text-base">Clinical Snapshot</CardTitle>
            <p className="text-sm text-muted-foreground">
              Your next appointment and high-priority tasks for today.
            </p>
          </div>
          {nextAppointment && (
            <Button asChild size="sm" variant="outline">
              <Link to="/doctor/appointments">
                <Stethoscope className="mr-2 h-4 w-4" /> View details
              </Link>
            </Button>
          )}
        </CardHeader>
        <CardContent className="grid gap-4 md:grid-cols-3">
          <div className="rounded-2xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Next patient</p>
            <p className="mt-2 text-lg font-semibold">
              {nextAppointment?.patientId?.name || 'No upcoming patients'}
            </p>
            <p className="mt-1 text-sm text-muted-foreground">
              {nextAppointment
                ? `${nextAppointment.slot} ΓÇó ${nextAppointment.consultationMode || 'In-person'}`
                : 'Your schedule is clear.'}
            </p>
          </div>
          <div className="rounded-2xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Pending lab orders</p>
            <p className="mt-2 text-lg font-semibold">{dashboardData?.pendingLabOrders?.length || 0}</p>
            <p className="mt-1 text-sm text-muted-foreground">Results and releases awaiting review.</p>
          </div>
          <div className="rounded-2xl border border-border/60 bg-muted/30 p-4">
            <p className="text-xs uppercase tracking-[0.2em] text-muted-foreground">Recent prescriptions</p>
            <p className="mt-2 text-lg font-semibold">{dashboardData?.recentPrescriptions?.length || 0}</p>
            <p className="mt-1 text-sm text-muted-foreground">Issued in the last few consultations.</p>
          </div>
        </CardContent>
      </Card>

      {/* Today's Stats */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Today's Appointments
            </CardTitle>
            <Calendar className="h-4 w-4 text-primary" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.total}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {stats.pending} pending ΓÇó {stats.inProgress} in progress
            </p>
          </CardContent>
        </Card>

        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Completed Today
            </CardTitle>
            <Activity className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.completed}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {Math.round((stats.completed / stats.total) * 100) || 0}% completion rate
            </p>
          </CardContent>
        </Card>

        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Pending Prescriptions
            </CardTitle>
            <FileText className="h-4 w-4 text-blue-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {dashboardData?.recentPrescriptions?.length || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Recent creations</p>
          </CardContent>
        </Card>

        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Lab Orders
            </CardTitle>
            <AlertCircle className="h-4 w-4 text-orange-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {dashboardData?.pendingLabOrders?.length || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Pending test results</p>
          </CardContent>
        </Card>
      </div>

      <div className="grid gap-4 lg:grid-cols-3">
        {/* Today's Queue */}
        <Card className="bg-background/50 backdrop-blur-sm border-border/50 lg:col-span-2">
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle className="flex items-center gap-2">
              <ClipboardList className="h-5 w-5" /> Today's Queue
            </CardTitle>
            <Button asChild variant="outline" size="sm">
              <Link to="/doctor/appointments">Open full queue</Link>
            </Button>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {todayQueue.length > 0 ? (
                todayQueue.slice(0, 6).map((apt) => (
                  <div
                    key={apt._id}
                    className="flex flex-wrap items-center justify-between gap-3 border-b border-border/50 pb-3 last:border-0 last:pb-0"
                  >
                    <div className="flex flex-col gap-1">
                      <span className="font-medium text-sm">{apt.patientId?.name || 'Patient'}</span>
                      <span className="text-xs text-muted-foreground">
                        {apt.slot} ΓÇó {apt.consultationMode || 'In-person'}
                      </span>
                    </div>
                    <div className="flex items-center gap-2">
                      <span
                        className={`text-xs px-2 py-1 rounded-full ${
                          apt.status === 'booked'
                            ? 'bg-blue-500/10 text-blue-600'
                            : apt.status === 'inConsultation'
                              ? 'bg-orange-500/10 text-orange-600'
                              : apt.status === 'completed'
                                ? 'bg-green-500/10 text-green-600'
                                : 'bg-muted/50 text-muted-foreground'
                        }`}
                      >
                        {apt.status}
                      </span>
                      {['booked', 'confirmed', 'arrived', 'checked-in'].includes(apt.status) && (
                        <Button
                          size="sm"
                          variant="default"
                          onClick={() => handleStartConsultation(apt._id)}
                          disabled={startingConsultation === apt._id}
                          className="text-xs"
                        >
                          {startingConsultation === apt._id ? 'Starting...' : 'Start'}
                        </Button>
                      )}
                      <Button asChild size="sm" variant="outline" className="text-xs">
                        <Link to={`/doctor/appointments/${apt._id}/summary`}>View</Link>
                      </Button>
                    </div>
                  </div>
                ))
              ) : (
                <p className="text-sm text-muted-foreground py-4 text-center">
                  No appointments scheduled for today.
                </p>
              )}
            </div>
          </CardContent>
        </Card>

        {/* Quick Actions */}
        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Activity className="h-5 w-5" /> Quick Actions
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2 flex flex-col">
              <Button asChild className="w-full" variant="default">
                <Link to="/doctor/appointments">
                  <Calendar className="mr-2 h-4 w-4" /> Review queue
                </Link>
              </Button>
              <Button asChild variant="outline" className="w-full">
                <Link to="/doctor/prescriptions">
                  <FileText className="mr-2 h-4 w-4" /> New prescription
                </Link>
              </Button>
              <Button asChild variant="outline" className="w-full">
                <Link to="/doctor/lab-orders">
                  <AlertCircle className="mr-2 h-4 w-4" /> Order lab tests
                </Link>
              </Button>
              <Button asChild variant="outline" className="w-full">
                <Link to="/doctor/availability">
                  <Clock className="mr-2 h-4 w-4" /> Manage schedule
                </Link>
              </Button>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Recent Activity */}
      <div className="grid gap-4 md:grid-cols-2">
        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle>Recent prescriptions</CardTitle>
            <Button asChild size="sm" variant="outline">
              <Link to="/doctor/prescriptions">View all</Link>
            </Button>
          </CardHeader>
          <CardContent>
            {dashboardData?.recentPrescriptions && dashboardData.recentPrescriptions.length > 0 ? (
              <div className="space-y-4">
                {dashboardData.recentPrescriptions.map((prescription) => (
                  <div key={prescription._id} className="flex items-start gap-4 pb-4 border-b border-border/50 last:border-0">
                    <div className="w-2 h-2 rounded-full bg-primary mt-2 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-sm font-medium">Prescription issued</p>
                      <p className="text-xs text-muted-foreground">
                        {prescription.appointmentId ? formatDate(prescription.appointmentId.date) : 'Appointment pending'}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-sm text-muted-foreground text-center py-8">
                No recent prescriptions.
              </p>
            )}
          </CardContent>
        </Card>

        <Card className="bg-background/50 backdrop-blur-sm border-border/50">
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle>Pending lab orders</CardTitle>
            <Button asChild size="sm" variant="outline">
              <Link to="/doctor/lab-orders">Review inbox</Link>
            </Button>
          </CardHeader>
          <CardContent>
            {dashboardData?.pendingLabOrders && dashboardData.pendingLabOrders.length > 0 ? (
              <div className="space-y-4">
                {dashboardData.pendingLabOrders.map((order) => (
                  <div key={order._id} className="flex items-start gap-4 pb-4 border-b border-border/50 last:border-0">
                    <div className="w-2 h-2 rounded-full bg-orange-500 mt-2 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-sm font-medium">{order.testName || 'Lab order'}</p>
                      <p className="text-xs text-muted-foreground capitalize">{order.status || 'pending'}</p>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-sm text-muted-foreground text-center py-8">
                No lab orders awaiting action.
              </p>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Input } from '../../components/ui/input';
import { Label } from '../../components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../../components/ui/select';
import { Textarea } from '../../components/ui/textarea';
import { LoadingSkeleton } from '../../components';
import { labOrderApi, appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { Plus, Trash2, Download, Send, AlertCircle } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';
import { StatusBadge } from '../../components/StatusBadge.jsx';

// Common lab tests
const COMMON_TESTS = [
  { testName: 'Complete Blood Count (CBC)', testCode: 'CBC', price: 150 },
  { testName: 'Blood Sugar (Fasting)', testCode: 'BS-F', price: 100 },
  { testName: 'Blood Sugar (Random)', testCode: 'BS-R', price: 100 },
  { testName: 'Thyroid Profile (TSH, T3, T4)', testCode: 'THYROID', price: 350 },
  { testName: 'Lipid Profile', testCode: 'LIPID', price: 250 },
  { testName: 'Liver Function Tests (LFT)', testCode: 'LFT', price: 300 },
  { testName: 'Kidney Function Tests (KFT)', testCode: 'KFT', price: 300 },
  { testName: 'Urine Routine', testCode: 'URINE', price: 100 },
  { testName: 'X-Ray (Chest)', testCode: 'XR-CHEST', price: 400 },
  { testName: 'Ultrasound (Abdomen)', testCode: 'USG-ABD', price: 500 },
  { testName: 'ECG', testCode: 'ECG', price: 200 },
];

export default function LabOrderCreation() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const appointmentId = searchParams.get('appointmentId');
  const patientId = searchParams.get('patientId');

  const [loading, setLoading] = useState(false);
  const [appointment, setAppointment] = useState(null);
  const [recentOrders, setRecentOrders] = useState([]);

  const [formData, setFormData] = useState({
    patientId: patientId || '',
    appointmentId: appointmentId || '',
    urgency: 'routine',
    notes: '',
    tests: [],
  });

  const [selectedTest, setSelectedTest] = useState('');

  useEffect(() => {
    if (appointmentId) {
      const fetchAppointment = async () => {
        try {
          setLoading(true);
          const response = await appointmentApi.getDoctorToday();
          const found = Array.isArray(response) ? response.find((a) => a._id === appointmentId) : null;
          if (found) {
            setAppointment(found);
            setFormData((prev) => ({
              ...prev,
              patientId: found.patientId,
              appointmentId,
            }));
          }
        } catch (err) {
          console.error('Failed to fetch appointment', err);
        } finally {
          setLoading(false);
        }
      };
      fetchAppointment();
    }
  }, [appointmentId]);

  const loadRecentOrders = async () => {
    try {
      const data = await labOrderApi.getByDoctor();
      setRecentOrders(Array.isArray(data) ? data : []);
    } catch {
      // ignore dashboard list failures
    }
  };

  useEffect(() => {
    loadRecentOrders();
  }, []);

  const handleAddTest = () => {
    if (!selectedTest) {
      toast.error('Please select a test');
      return;
    }

    const test = COMMON_TESTS.find((t) => t.testCode === selectedTest);
    if (test && !formData.tests.find((t) => t.testCode === selectedTest)) {
      setFormData({
        ...formData,
        tests: [...formData.tests, test],
      });
      setSelectedTest('');
    } else if (formData.tests.find((t) => t.testCode === selectedTest)) {
      toast.error('This test is already added');
    }
  };

  const handleRemoveTest = (testCode) => {
    setFormData({
      ...formData,
      tests: formData.tests.filter((t) => t.testCode !== testCode),
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!formData.patientId) {
      toast.error('Patient is required');
      return;
    }

    if (formData.tests.length === 0) {
      toast.error('Please select at least one test');
      return;
    }

    try {
      setLoading(true);
      const response = await labOrderApi.create({
        patientId: formData.patientId,
        appointmentId: formData.appointmentId || undefined,
        tests: formData.tests,
        urgency: formData.urgency,
        notes: formData.notes,
      });

      toast.success('Lab order created successfully');

      // Option to download PDF
      setTimeout(() => {
        if (confirm('Download lab order as PDF?')) {
          labOrderApi.downloadPdf(response.labOrder._id);
        }
        navigate('/doctor/appointments');
      }, 1000);
    } catch (err) {
      toast.error(
        err.response?.data?.message || 'Failed to create lab order'
      );
    } finally {
      setLoading(false);
    }
  };

  const totalAmount = formData.tests.reduce((sum, test) => sum + test.price, 0);

  const orderStats = recentOrders.reduce(
    (acc, order) => {
      acc.total += 1;
      acc[order.status] = (acc[order.status] || 0) + 1;
      return acc;
    },
    { total: 0 }
  );

  return (
    <div className="space-y-6 max-w-5xl mx-auto">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">Order Lab Tests</h2>
        <p className="text-muted-foreground">
          Create a lab order for the patient's diagnostic testing
        </p>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total orders</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{orderStats.total || 0}</div>
            <p className="text-xs text-muted-foreground mt-1">Issued by you</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pending processing</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{orderStats.ordered || 0}</div>
            <p className="text-xs text-muted-foreground mt-1">Awaiting lab pickup</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Reports ready</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{orderStats.reportReady || 0}</div>
            <p className="text-xs text-muted-foreground mt-1">Ready for release</p>
          </CardContent>
        </Card>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Patient and Appointment Info */}
        <Card>
          <CardHeader>
            <CardTitle>Patient & Appointment</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {appointment && (
              <div className="grid md:grid-cols-2 gap-4 p-3 bg-blue-50 rounded-lg border border-blue-200">
                <div>
                  <p className="text-sm text-muted-foreground">Patient</p>
                  <p className="font-semibold">{appointment.patientId?.name}</p>
                </div>
                <div>
                  <p className="text-sm text-muted-foreground">Appointment</p>
                  <p className="font-semibold">
                    {appointment.slot} - {appointment.consultationMode}
                  </p>
                </div>
              </div>
            )}

            {!appointment && (
              <div>
                <Label htmlFor="patient">Patient ID *</Label>
                <Input
                  id="patient"
                  placeholder="Enter patient ID or email"
                  value={formData.patientId}
                  onChange={(e) =>
                    setFormData({ ...formData, patientId: e.target.value })
                  }
                  required
                />
              </div>
            )}
          </CardContent>
        </Card>

        {/* Test Selection */}
        <Card>
          <CardHeader>
            <CardTitle>Select Tests</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex gap-2">
              <Select value={selectedTest} onValueChange={setSelectedTest}>
                <SelectTrigger>
                  <SelectValue placeholder="Select a test..." />
                </SelectTrigger>
                <SelectContent>
                  {COMMON_TESTS.map((test) => (
                    <SelectItem key={test.testCode} value={test.testCode}>
                      {test.testName}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              <Button
                type="button"
                onClick={handleAddTest}
                variant="outline"
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>

            {/* Selected Tests */}
            {formData.tests.length > 0 && (
              <div className="space-y-2">
                <Label className="text-base font-semibold">Tests ({formData.tests.length})</Label>
                {formData.tests.map((test) => (
                  <div
                    key={test.testCode}
                    className="flex items-center justify-between p-3 border rounded-lg bg-muted/50"
                  >
                    <div className="flex-1">
                      <p className="font-medium text-sm">{test.testName}</p>
                      <p className="text-xs text-muted-foreground">{test.testCode}</p>
                    </div>
                    <div className="text-right pr-3">
                      <p className="font-semibold">Γé╣{test.price}</p>
                    </div>
                    <Button
                      type="button"
                      onClick={() => handleRemoveTest(test.testCode)}
                      variant="ghost"
                      size="sm"
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Urgency & Notes */}
        <Card>
          <CardHeader>
            <CardTitle>Additional Information</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div>
              <Label htmlFor="urgency">Urgency *</Label>
              <Select value={formData.urgency} onValueChange={(value) => setFormData({ ...formData, urgency: value })}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="routine">Routine</SelectItem>
                  <SelectItem value="urgent">Urgent</SelectItem>
                  <SelectItem value="stat">STAT (Immediate)</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label htmlFor="notes">Clinical Notes</Label>
              <Textarea
                id="notes"
                placeholder="Any special instructions or clinical context for the lab..."
                value={formData.notes}
                onChange={(e) =>
                  setFormData({ ...formData, notes: e.target.value })
                }
                rows={3}
              />
            </div>
          </CardContent>
        </Card>

        {/* Summary */}
        <Card className="border-blue-200 bg-blue-50">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertCircle className="h-5 w-5" />
              Order Summary
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <div className="flex justify-between">
                <span>Number of Tests:</span>
                <span className="font-semibold">{formData.tests.length}</span>
              </div>
              <div className="flex justify-between text-lg font-bold border-t pt-2">
                <span>Total Amount:</span>
                <span>Γé╣{totalAmount}</span>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Submit */}
        <div className="flex gap-2">
          <Button
            type="submit"
            disabled={loading || formData.tests.length === 0}
            className="gap-2"
          >
            <Send className="h-4 w-4" />
            {loading ? 'Creating...' : 'Create Lab Order'}
          </Button>
          <Button
            type="button"
            variant="outline"
            onClick={() => navigate(-1)}
          >
            Cancel
          </Button>
        </div>
      </form>

      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>Recent lab orders</CardTitle>
          <Button variant="outline" onClick={loadRecentOrders}>Refresh</Button>
        </CardHeader>
        <CardContent>
          {recentOrders.length === 0 ? (
            <p className="text-muted-foreground text-center py-8">
              No lab orders created yet.
            </p>
          ) : (
            <div className="space-y-3">
              {recentOrders.slice(0, 6).map((order) => (
                <div key={order._id} className="rounded-xl border border-border p-4">
                  <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
                    <div>
                      <p className="font-medium text-foreground">
                        {order.patientName || 'Patient'} ΓÇó {order.orderNumber || order._id}
                      </p>
                      <p className="text-sm text-muted-foreground">
                        {order.items?.map((item) => item.testName).join(', ') || 'No tests listed'}
                      </p>
                      <p className="text-xs text-muted-foreground mt-1">
                        {order.createdAt ? new Date(order.createdAt).toLocaleString() : 'Created recently'}
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      <StatusBadge status={order.status}>{order.status}</StatusBadge>
                      <StatusBadge status={order.paymentStatus}>{order.paymentStatus}</StatusBadge>
                      {order.urgency && order.urgency !== 'routine' && (
                        <StatusBadge status="urgent">{order.urgency}</StatusBadge>
                      )}
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => labOrderApi.downloadPdf(order._id)}
                      >
                        <Download className="h-4 w-4 mr-1" /> PDF
                      </Button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { LoadingSkeleton, ErrorState } from '../../components';
import { appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';
import {
  User,
  Phone,
  Mail,
  AlertCircle,
  Heart,
  History,
  FileText,
  Pill,
  Plus,
  ArrowLeft,
  Stethoscope,
} from 'lucide-react';

export default function PatientSummary() {
  const { appointmentId } = useParams();
  const navigate = useNavigate();
  const [summaryData, setSummaryData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadSummary = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // Fetch appointment first to get patient ID
        const appointmentResponse = await appointmentApi.getDoctorToday();
        const appointment = Array.isArray(appointmentResponse)
          ? appointmentResponse.find((a) => a._id === appointmentId)
          : null;

        if (!appointment) {
          setError('Appointment not found');
          return;
        }

        // Fetch patient summary
        const patientResponse = await appointmentApi.getPatientSummary(appointment.patientId);
        setSummaryData({
          appointment,
          ...patientResponse,
        });
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to load patient summary');
        toast.error('Failed to load patient data');
      } finally {
        setLoading(false);
      }
    };
    
    if (appointmentId) {
      loadSummary();
    }
  }, [appointmentId]);

  const fetchPatientSummary = async () => {
    try {
      setLoading(true);
      setError(null);
      
      // Fetch appointment first to get patient ID
      const appointmentResponse = await appointmentApi.getDoctorToday();
      const appointment = Array.isArray(appointmentResponse)
        ? appointmentResponse.find((a) => a._id === appointmentId)
        : null;

      if (!appointment) {
        setError('Appointment not found');
        return;
      }

      // Fetch patient summary
      const patientResponse = await appointmentApi.getPatientSummary(appointment.patientId);
      setSummaryData({
        appointment,
        ...patientResponse,
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load patient summary');
      toast.error('Failed to load patient data');
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <LoadingSkeleton />;

  if (error) return <ErrorState error={error} onRetry={fetchPatientSummary} />;

  if (!summaryData)
    return (
      <div className="text-center py-12">
        <p className="text-muted-foreground">Patient data not found</p>
      </div>
    );

  const patient = summaryData.patient;
  const recentPrescriptions = summaryData.recentPrescriptions || [];
  const recentLabOrders = summaryData.recentLabOrders || [];
  const recentLabReports = summaryData.recentLabReports || [];
  const appointmentHistory = summaryData.appointmentHistory || [];
  const triageFlags = [];

  if (patient?.allergies?.length) {
    triageFlags.push('Allergy risk');
  }
  if (patient?.chronicDiseases?.length) {
    triageFlags.push('Chronic condition');
  }
  if (patient?.latestVitals) {
    const vitals = patient.latestVitals;
    const highTemp = vitals.temperature && Number(vitals.temperature) >= 100;
    const lowSpo2 = vitals.spo2 && Number(vitals.spo2) < 94;
    const highPulse = vitals.pulse && Number(vitals.pulse) > 100;
    const highBp = vitals.bloodPressure && vitals.bloodPressure.split('/').some((val) => Number(val) >= 140);
    if (highTemp || lowSpo2 || highPulse || highBp) {
      triageFlags.push('Vitals out of range');
    }
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <Button
            variant="outline"
            size="sm"
            onClick={() => navigate('/doctor/appointments')}
          >
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <div>
            <h2 className="text-3xl font-bold tracking-tight">Patient Summary</h2>
            <p className="text-muted-foreground">
              Before starting consultation - review patient history
            </p>
          </div>
        </div>
        <Button asChild className="gap-2">
          <a href="#consultation">
            <Stethoscope className="h-4 w-4" />
            Start Prescription
          </a>
        </Button>
      </div>

      {/* Patient Identity Card */}
      <Card className="bg-gradient-to-br from-blue-50 to-blue-100/50 border-blue-200">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <User className="h-5 w-5" />
            Patient Information
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid md:grid-cols-2 gap-6">
            <div>
              <p className="text-sm text-muted-foreground">Full Name</p>
              <p className="text-lg font-semibold">{patient?.name || 'N/A'}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Patient ID</p>
              <p className="text-lg font-semibold font-mono">{patient?.patientId || 'N/A'}</p>
            </div>
            <div className="flex items-center gap-2">
              <Phone className="h-4 w-4 text-muted-foreground" />
              <div>
                <p className="text-sm text-muted-foreground">Phone</p>
                <p className="font-medium">{patient?.phone || 'N/A'}</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Mail className="h-4 w-4 text-muted-foreground" />
              <div>
                <p className="text-sm text-muted-foreground">Email</p>
                <p className="font-medium text-sm">{patient?.email || 'N/A'}</p>
              </div>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Age</p>
              <p className="text-lg font-semibold">{patient?.age || 'N/A'} years</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Gender</p>
              <p className="text-lg font-semibold capitalize">{patient?.gender || 'N/A'}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Blood Group</p>
              <p className="text-lg font-semibold">{patient?.bloodGroup || 'Not specified'}</p>
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Marital Status</p>
              <p className="text-lg font-semibold capitalize">{patient?.maritalStatus || 'N/A'}</p>
            </div>
          </div>

          {/* Vitals */}
          {(patient?.height || patient?.weight) && (
            <div className="border-t pt-4">
              <p className="font-semibold mb-2">Vitals on Record</p>
              <div className="grid md:grid-cols-3 gap-4">
                {patient?.height && (
                  <div>
                    <p className="text-sm text-muted-foreground">Height</p>
                    <p>{patient.height} cm</p>
                  </div>
                )}
                {patient?.weight && (
                  <div>
                    <p className="text-sm text-muted-foreground">Weight</p>
                    <p>{patient.weight} kg</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Triage Flags */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <AlertCircle className="h-5 w-5" />
            Triage highlights
          </CardTitle>
        </CardHeader>
        <CardContent className="flex flex-wrap gap-2">
          {triageFlags.length ? (
            triageFlags.map((flag) => (
              <span
                key={flag}
                className="rounded-full bg-red-500/10 px-3 py-1 text-xs font-semibold text-red-600"
              >
                {flag}
              </span>
            ))
          ) : (
            <span className="rounded-full bg-emerald-500/10 px-3 py-1 text-xs font-semibold text-emerald-600">
              No high-risk flags identified
            </span>
          )}
        </CardContent>
      </Card>

      {/* Medical History */}
      <div className="grid md:grid-cols-2 gap-6">
        {/* Allergies */}
        {patient?.allergies && patient.allergies.length > 0 && (
          <Card className="border-orange-200 bg-orange-50/50">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-orange-900">
                <AlertCircle className="h-5 w-5" />
                Allergies
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2">
                {patient.allergies.map((allergy, idx) => (
                  <div
                    key={idx}
                    className="px-3 py-2 bg-orange-100 rounded-md text-sm font-medium"
                  >
                    {allergy}
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Chronic Diseases */}
        {patient?.chronicDiseases && patient.chronicDiseases.length > 0 && (
          <Card className="border-red-200 bg-red-50/50">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-red-900">
                <Heart className="h-5 w-5" />
                Chronic Conditions
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-2">
                {patient.chronicDiseases.map((disease, idx) => (
                  <div
                    key={idx}
                    className="px-3 py-2 bg-red-100 rounded-md text-sm font-medium"
                  >
                    {disease}
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        {/* Insurance */}
        {patient?.insuranceProvider && (
          <Card>
            <CardHeader>
              <CardTitle className="text-sm">Insurance</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="font-medium">{patient.insuranceProvider}</p>
              {patient.insuranceNumber && (
                <p className="text-sm text-muted-foreground">{patient.insuranceNumber}</p>
              )}
            </CardContent>
          </Card>
        )}

        {/* Emergency Contact */}
        {patient?.emergencyContact && (
          <Card>
            <CardHeader>
              <CardTitle className="text-sm">Emergency Contact</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="font-medium">{patient.emergencyContact.name}</p>
              <p className="text-sm text-muted-foreground">
                {patient.emergencyContact.relation}
              </p>
              <p className="text-sm">{patient.emergencyContact.phone}</p>
            </CardContent>
          </Card>
        )}
      </div>

      {/* Recent Prescriptions */}
      {recentPrescriptions && recentPrescriptions.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Pill className="h-5 w-5" />
              Recent Prescriptions
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {recentPrescriptions.map((prescription) => (
                <div
                  key={prescription._id}
                  className="border-l-4 border-blue-500 pl-4 py-2"
                >
                  <p className="font-medium text-sm">
                    {prescription.diagnosis || 'Medical Prescription'}
                  </p>
                  <p className="text-xs text-muted-foreground">
                    {prescription.medicines?.length || 0} items
                  </p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {recentLabOrders && recentLabOrders.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Recent Lab Orders
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {recentLabOrders.map((order) => (
                <div
                  key={order._id}
                  className="border-l-4 border-amber-500 pl-4 py-2"
                >
                  <p className="font-medium text-sm">{order.orderNumber || 'Lab order'}</p>
                  <p className="text-xs text-muted-foreground">
                    {order.status} ΓÇó {order.paymentStatus} ΓÇó {order.urgency || 'routine'}
                  </p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Recent Lab Reports */}
      {recentLabReports && recentLabReports.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Recent Lab Reports
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {recentLabReports.map((report) => (
                <div
                  key={report._id}
                  className="border-l-4 border-green-500 pl-4 py-2"
                >
                  <p className="font-medium text-sm">{report.reportName}</p>
                  <p className="text-xs text-muted-foreground">
                    {new Date(report.createdAt).toLocaleDateString()}
                  </p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Appointment History */}
      {appointmentHistory && appointmentHistory.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <History className="h-5 w-5" />
              Appointment History
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {appointmentHistory.slice(0, 5).map((apt) => (
                <div
                  key={apt._id}
                  className="flex justify-between items-center pb-2 border-b last:border-0 last:pb-0"
                >
                  <div className="text-sm">
                    <p className="font-medium">
                      {new Date(apt.createdAt).toLocaleDateString()}
                    </p>
                    <p className="text-xs text-muted-foreground">{apt.slot}</p>
                  </div>
                  <div className="text-xs badge">{apt.status}</div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Action Buttons */}
      <div className="flex gap-3">
        <Button asChild className="gap-2">
          <a href="#consultation">
            <Stethoscope className="h-4 w-4" />
            Start Consultation
          </a>
        </Button>
        <Button
          variant="outline"
          onClick={() =>
            navigate(`/doctor/prescriptions?appointmentId=${appointmentId}`)
          }
        >
          <Plus className="h-4 w-4 mr-2" />
          Create Prescription
        </Button>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { DataTable, LoadingSkeleton, ErrorState } from '../../components';
import { patientApi, appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { Users, FileText, Calendar } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function DoctorPatients() {
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [patientHistory, setPatientHistory] = useState([]);

  useEffect(() => {
    fetchPatients();
  }, []);

  const fetchPatients = async () => {
    try {
      setLoading(true);
      setError(null);
      const data = await patientApi.getAll();
      setPatients(Array.isArray(data) ? data : []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch patients');
      toast.error('Failed to load patients');
    } finally {
      setLoading(false);
    }
  };

  const handleViewHistory = async (patientId) => {
    try {
      const history = await appointmentApi.getPatientHistory(patientId);
      setPatientHistory(Array.isArray(history) ? history : []);
      setSelectedPatient(patientId);
    } catch {
      toast.error('Failed to fetch patient history');
    }
  };

  const columns = [
    {
      key: 'userId',
      label: 'Name',
      sortable: true,
      render: (user) => user?.name || 'N/A',
    },
    {
      key: 'userId',
      label: 'Email',
      render: (user) => user?.email || 'N/A',
    },
    {
      key: 'userId',
      label: 'Phone',
      render: (user) => user?.phone || 'N/A',
    },
    {
      key: 'bloodGroup',
      label: 'Blood Group',
      render: (bg) => bg || 'Not specified',
    },
    {
      key: '_id',
      label: 'Actions',
      render: (_, row) => (
        <Button
          size="sm"
          variant="outline"
          onClick={() => handleViewHistory(row._id)}
        >
          <FileText className="h-4 w-4 mr-1" /> History
        </Button>
      ),
    },
  ];

  if (loading) return <LoadingSkeleton />;

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">My Patients</h2>
        <p className="text-muted-foreground">View all your patients and their medical history</p>
      </div>

      {error && <ErrorState error={error} />}

      {/* Patients List */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Users className="h-5 w-5" /> Patients ({patients.length})
          </CardTitle>
        </CardHeader>
        <CardContent>
          {patients.length === 0 ? (
            <p className="text-muted-foreground text-center py-8">
              No patients found.
            </p>
          ) : (
            <DataTable
              data={patients}
              columns={columns}
              searchPlaceholder="Search patients by name..."
              searchKey="userId"
            />
          )}
        </CardContent>
      </Card>

      {/* Patient History */}
      {selectedPatient && (
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="h-5 w-5" /> Appointment History
            </CardTitle>
          </CardHeader>
          <CardContent>
            {patientHistory.length === 0 ? (
              <p className="text-muted-foreground text-center py-8">
                No appointment history found.
              </p>
            ) : (
              <div className="space-y-3">
                {patientHistory.map((apt) => (
                  <div
                    key={apt._id}
                    className="p-4 border border-border/50 rounded-lg hover:bg-muted/50 transition-colors"
                  >
                    <div className="flex justify-between items-start">
                      <div>
                        <p className="font-medium text-sm">
                          {new Date(apt.date).toLocaleDateString()} at {apt.slot || 'ΓÇö'}
                        </p>
                        <p className="text-sm text-muted-foreground mt-1">
                          Status: <span className="font-medium capitalize">{apt.status}</span>
                        </p>
                      </div>
                      <span className="text-xs px-2 py-1 rounded bg-primary/10 text-primary">
                        {apt.status}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Input } from '../../components/ui/input';
import { Label } from '../../components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../../components/ui/select';
import { ErrorState, LoadingSkeleton } from '../../components';
import { prescriptionApi, appointmentApi, pharmacyApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { Plus, Trash2, Send, FileText } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function DoctorPrescriptions() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const appointmentId = searchParams.get('appointmentId');

  const [loading, setLoading] = useState(!!appointmentId);
  const [error, setError] = useState(null);
  const [medicines, setMedicines] = useState([]);
  const [appointment, setAppointment] = useState(null);
  const [recentPrescriptions, setRecentPrescriptions] = useState([]);

  const [formData, setFormData] = useState({
    appointmentId: appointmentId || '',
    diagnosis: '',
    medicines: [],
    notes: '',
  });

  const [medicineInput, setMedicineInput] = useState({
    medicineId: '',
    dosage: '',
    frequency: '',
    duration: '',
  });

  useEffect(() => {
    Promise.all([fetchMedicines(), appointmentId && fetchAppointment(appointmentId), fetchRecentPrescriptions()]);
  }, [appointmentId]);

  const fetchMedicines = async () => {
    try {
      const data = await pharmacyApi.getAll();
      setMedicines(Array.isArray(data) ? data : []);
    } catch {
      toast.error('Failed to load medicines');
    }
  };

  const fetchAppointment = async (id) => {
    try {
      setLoading(true);
      const data = await appointmentApi.getAll();
      const found = Array.isArray(data) ? data.find((a) => a._id === id) : null;
      if (found) {
        setAppointment(found);
      } else {
        setError('Appointment not found');
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch appointment');
    } finally {
      setLoading(false);
    }
  };

  const fetchRecentPrescriptions = async () => {
    try {
      const data = await prescriptionApi.getMy();
      setRecentPrescriptions(Array.isArray(data) ? data : []);
    } catch {
      // ignore recent list failures
    }
  };

  const handleAddMedicine = () => {
    if (!medicineInput.medicineId || !medicineInput.dosage || !medicineInput.frequency) {
      toast.error('Please fill all medicine fields');
      return;
    }
    setFormData({
      ...formData,
      medicines: [
        ...formData.medicines,
        { ...medicineInput, medicineId: medicineInput.medicineId },
      ],
    });
    setMedicineInput({ medicineId: '', dosage: '', frequency: '', duration: '' });
  };

  const handleRemoveMedicine = (index) => {
    setFormData({
      ...formData,
      medicines: formData.medicines.filter((_, i) => i !== index),
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.appointmentId || !formData.diagnosis || formData.medicines.length === 0) {
      toast.error('Please fill all required fields');
      return;
    }

    try {
      setLoading(true);
      await prescriptionApi.create(formData);
      toast.success('Prescription created successfully');
      navigate('/doctor/appointments');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to create prescription');
    } finally {
      setLoading(false);
    }
  };

  if (loading && appointmentId) return <LoadingSkeleton />;
  if (error) return <ErrorState error={error} />;

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">Create Prescription</h2>
        <p className="text-muted-foreground">
          {appointment
            ? `Create prescription for ${appointment.patientId?.userId?.name || 'Patient'}`
            : 'Fill in the prescription details below'}
        </p>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total prescriptions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{recentPrescriptions.length}</div>
            <p className="text-xs text-muted-foreground mt-1">Created by you</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Latest prescription</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {recentPrescriptions[0]?.createdAt ? new Date(recentPrescriptions[0].createdAt).toLocaleDateString() : 'ΓÇö'}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Most recent order</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Unique patients</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {new Set(recentPrescriptions.map((p) => p.patientId?._id || p.patientId)).size || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Prescriptions issued</p>
          </CardContent>
        </Card>
      </div>

      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle>Prescription Form</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Appointment Selection */}
            <div className="space-y-2">
              <Label htmlFor="appointment">
                Appointment <span className="text-red-500">*</span>
              </Label>
              <Input
                id="appointment"
                value={formData.appointmentId}
                onChange={(e) =>
                  setFormData({ ...formData, appointmentId: e.target.value })
                }
                placeholder="Enter appointment ID or select from list"
                required
              />
              {appointment && (
                <div className="mt-2 p-3 bg-muted/50 rounded text-sm">
                  <p className="font-medium">{appointment.patientId?.userId?.name}</p>
                  <p className="text-muted-foreground">
                    {new Date(appointment.date).toLocaleDateString()} at{' '}
                    {appointment.slot || 'ΓÇö'}
                  </p>
                </div>
              )}
            </div>

            {/* Diagnosis */}
            <div className="space-y-2">
              <Label htmlFor="diagnosis">
                Diagnosis <span className="text-red-500">*</span>
              </Label>
              <textarea
                id="diagnosis"
                value={formData.diagnosis}
                onChange={(e) =>
                  setFormData({ ...formData, diagnosis: e.target.value })
                }
                placeholder="Describe the patient's diagnosis and findings..."
                className="w-full p-3 border border-border rounded-md bg-background/50 focus:outline-none focus:ring-2 focus:ring-primary"
                rows="4"
                required
              />
            </div>

            {/* Medicines */}
            <div className="space-y-4 p-4 bg-muted/30 rounded-lg">
              <h3 className="font-semibold flex items-center gap-2">
                <FileText className="h-4 w-4" /> Medicines
              </h3>

              {/* Add Medicine Form */}
              <div className="space-y-4 p-3 bg-background/50 rounded border border-border/50">
                <div className="grid gap-4 md:grid-cols-2">
                  <div className="space-y-2">
                    <Label htmlFor="medicine">Medicine</Label>
                    <Select
                      value={medicineInput.medicineId}
                      onValueChange={(value) =>
                        setMedicineInput({ ...medicineInput, medicineId: value })
                      }
                    >
                      <SelectTrigger>
                        <SelectValue placeholder="Select medicine" />
                      </SelectTrigger>
                      <SelectContent>
                        {medicines.map((med) => (
                          <SelectItem key={med._id} value={med._id}>
                            {med.name} ({med.strength})
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="dosage">Dosage</Label>
                    <Input
                      id="dosage"
                      value={medicineInput.dosage}
                      onChange={(e) =>
                        setMedicineInput({
                          ...medicineInput,
                          dosage: e.target.value,
                        })
                      }
                      placeholder="e.g., 500mg"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="frequency">Frequency</Label>
                    <Input
                      id="frequency"
                      value={medicineInput.frequency}
                      onChange={(e) =>
                        setMedicineInput({
                          ...medicineInput,
                          frequency: e.target.value,
                        })
                      }
                      placeholder="e.g., twice daily"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="duration">Duration</Label>
                    <Input
                      id="duration"
                      value={medicineInput.duration}
                      onChange={(e) =>
                        setMedicineInput({
                          ...medicineInput,
                          duration: e.target.value,
                        })
                      }
                      placeholder="e.g., 7 days"
                    />
                  </div>
                </div>

                <Button
                  type="button"
                  onClick={handleAddMedicine}
                  variant="outline"
                  className="w-full"
                >
                  <Plus className="h-4 w-4 mr-2" /> Add Medicine
                </Button>
              </div>

              {/* Added Medicines List */}
              {formData.medicines.length > 0 && (
                <div className="space-y-2">
                  <p className="text-sm font-medium">Added Medicines:</p>
                  {formData.medicines.map((med, idx) => {
                    const medicine = medicines.find((m) => m._id === med.medicineId);
                    return (
                      <div
                        key={idx}
                        className="flex justify-between items-start p-3 bg-muted/50 rounded text-sm"
                      >
                        <div>
                          <p className="font-medium">{medicine?.name}</p>
                          <p className="text-xs text-muted-foreground">
                            {med.dosage} - {med.frequency} for {med.duration}
                          </p>
                        </div>
                        <Button
                          type="button"
                          size="sm"
                          variant="destructive"
                          onClick={() => handleRemoveMedicine(idx)}
                        >
                          <Trash2 className="h-3 w-3" />
                        </Button>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>

            {/* Notes */}
            <div className="space-y-2">
              <Label htmlFor="notes">Additional Notes</Label>
              <textarea
                id="notes"
                value={formData.notes}
                onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                placeholder="Any additional instructions for the patient..."
                className="w-full p-3 border border-border rounded-md bg-background/50 focus:outline-none focus:ring-2 focus:ring-primary"
                rows="3"
              />
            </div>

            {/* Actions */}
            <div className="flex gap-3">
              <Button type="submit" className="flex-1 shadow-md shadow-primary/20" disabled={loading}>
                <Send className="h-4 w-4 mr-2" /> Create Prescription
              </Button>
              <Button
                type="button"
                variant="outline"
                onClick={() => navigate('/doctor/appointments')}
              >
                Cancel
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle>Recent prescriptions</CardTitle>
        </CardHeader>
        <CardContent>
          {recentPrescriptions.length === 0 ? (
            <p className="text-muted-foreground text-center py-8">
              No prescriptions created yet.
            </p>
          ) : (
            <div className="space-y-3">
              {recentPrescriptions.slice(0, 6).map((prescription) => (
                <div key={prescription._id} className="rounded-xl border border-border p-4">
                  <p className="font-medium text-foreground">
                    {prescription.patientId?.userId?.name || 'Patient'} ΓÇó {prescription.diagnosis || 'Prescription'}
                  </p>
                  <p className="mt-1 text-sm text-muted-foreground">
                    {prescription.createdAt ? new Date(prescription.createdAt).toLocaleString() : 'Created recently'}
                  </p>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '../../components/ui/card';
import { Input } from '../../components/ui/input';
import { Label } from '../../components/ui/label';
import { LoadingSkeleton, ErrorState, DataTable } from '../../components';
import { reportApi, patientApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { Upload, FileText, Trash2 } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function DoctorReports() {
  const [reports, setReports] = useState([]);
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [uploading, setUploading] = useState(false);

  const [formData, setFormData] = useState({
    patientId: '',
    appointmentId: '',
    report: null,
  });

  useEffect(() => {
    fetchInitialData();
  }, []);

  const fetchInitialData = async () => {
    try {
      setLoading(true);
      setError(null);
      const [patientsData, reportsData] = await Promise.all([
        patientApi.getAll(),
        reportApi.getMy(),
      ]);
      setPatients(Array.isArray(patientsData) ? patientsData : []);
      setReports(Array.isArray(reportsData) ? reportsData : []);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load data');
    } finally {
      setLoading(false);
    }
  };

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 10 * 1024 * 1024) {
        toast.error('File size must be less than 10MB');
        return;
      }
      setFormData({ ...formData, report: file });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.patientId || !formData.report) {
      toast.error('Please select a patient and upload a report');
      return;
    }

    try {
      setUploading(true);
      const uploadFormData = new FormData();
      uploadFormData.append('patientId', formData.patientId);
      if (formData.appointmentId) {
        uploadFormData.append('appointmentId', formData.appointmentId);
      }
      uploadFormData.append('report', formData.report);

      await reportApi.create(uploadFormData);
      toast.success('Report uploaded successfully');
      setFormData({ patientId: '', appointmentId: '', report: null });
      fetchInitialData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to upload report');
    } finally {
      setUploading(false);
    }
  };

  const columns = [
    {
      key: 'patientId',
      label: 'Patient',
      render: (_, row) => row?.patientProfileId?.userId?.name || row?.patientId?.userId?.name || 'N/A',
    },
    {
      key: 'createdAt',
      label: 'Uploaded',
      render: (date) => new Date(date).toLocaleDateString(),
    },
    {
      key: 'reportUrl',
      label: 'File',
      render: (url) => (
        <a href={url} target="_blank" rel="noopener noreferrer" className="text-primary hover:underline text-sm">
          Download
        </a>
      ),
    },
  ];

  if (loading) return <LoadingSkeleton />;

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">My Reports</h2>
        <p className="text-muted-foreground">Upload and manage patient medical reports</p>
      </div>

      {error && <ErrorState error={error} />}

      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total uploads</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{reports.length}</div>
            <p className="text-xs text-muted-foreground mt-1">Reports you uploaded</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Latest upload</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {reports[0]?.createdAt ? new Date(reports[0].createdAt).toLocaleDateString() : 'ΓÇö'}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Most recent report</p>
          </CardContent>
        </Card>
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Active patients</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {new Set(reports.map((r) => r.patientId?._id || r.patientId)).size || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Patients with reports</p>
          </CardContent>
        </Card>
      </div>

      {/* Upload Form */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Upload className="h-5 w-5" /> Upload New Report
          </CardTitle>
          <CardDescription>Add a medical report for a patient</CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="patient">
                  Patient <span className="text-red-500">*</span>
                </Label>
                <select
                  id="patient"
                  value={formData.patientId}
                  onChange={(e) =>
                    setFormData({ ...formData, patientId: e.target.value })
                  }
                  className="w-full px-3 py-2 border border-border rounded-md bg-background/50 focus:outline-none focus:ring-2 focus:ring-primary"
                  required
                >
                  <option value="">Select a patient...</option>
                  {patients.map((patient) => (
                    <option key={patient._id} value={patient._id}>
                      {patient.userId?.name} ({patient.userId?.email})
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="appointment">Appointment ID (Optional)</Label>
                <Input
                  id="appointment"
                  value={formData.appointmentId}
                  onChange={(e) =>
                    setFormData({ ...formData, appointmentId: e.target.value })
                  }
                  placeholder="Enter appointment ID if applicable"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label htmlFor="file">
                Report File <span className="text-red-500">*</span>
              </Label>
              <div className="border-2 border-dashed border-border/50 rounded-lg p-6 text-center hover:border-primary/50 transition-colors cursor-pointer">
                <input
                  id="file"
                  type="file"
                  onChange={handleFileChange}
                  accept=".pdf,.doc,.docx,.txt,.jpg,.jpeg,.png"
                  className="hidden"
                  required
                />
                <label htmlFor="file" className="cursor-pointer">
                  <FileText className="h-10 w-10 mx-auto mb-2 text-muted-foreground" />
                  <p className="font-medium">
                    {formData.report ? formData.report.name : 'Click to upload or drag file'}
                  </p>
                  <p className="text-xs text-muted-foreground mt-1">
                    PDF, DOC, DOCX, TXT, JPG, PNG (max 10MB)
                  </p>
                </label>
              </div>
            </div>

            <Button
              type="submit"
              className="w-full shadow-md shadow-primary/20"
              disabled={uploading}
            >
              {uploading ? (
                <>
                  <span className="animate-spin mr-2 border-b-2 border-white w-4 h-4 rounded-full"></span>
                  Uploading...
                </>
              ) : (
                <>
                  <Upload className="h-4 w-4 mr-2" /> Upload Report
                </>
              )}
            </Button>
          </form>
        </CardContent>
      </Card>

      {/* Reports List */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle>Your Uploaded Reports ({reports.length})</CardTitle>
        </CardHeader>
        <CardContent>
          {reports.length === 0 ? (
            <p className="text-muted-foreground text-center py-8">
              No reports uploaded yet. Start by uploading a patient report above.
            </p>
          ) : (
            <DataTable
              data={reports}
              columns={columns}
              searchPlaceholder="Search reports..."
              searchKey="patientId"
            />
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { toast } from 'sonner';
import { updateUser } from '../../store/authSlice.js';
import { getRoleLabel } from '../../auth/constants.js';
import { userApi } from '../../services/apiServices.js';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialForm = {
  name: '',
  phone: '',
  gender: '',
  address: '',
};

export default function AdminProfilePage() {
  const dispatch = useDispatch();
  const authUser = useSelector((state) => state.auth.user);
  const [form, setForm] = useState(initialForm);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    const loadProfile = async () => {
      setLoading(true);
      try {
        const response = await userApi.getMe();
        const profile = response.data || response;
        setForm({
          name: profile.name || '',
          phone: profile.phone || '',
          gender: profile.gender || '',
          address: profile.address || '',
        });
        dispatch(updateUser(profile));
      } catch (err) {
        toast.error(err.response?.data?.message || 'Failed to load profile.');
      } finally {
        setLoading(false);
      }
    };

    loadProfile();
  }, [dispatch]);

  const handleSave = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      const response = await userApi.updateMe(form);
      const profile = response.data || response;
      dispatch(updateUser(profile));
      toast.success('Profile updated successfully.');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update profile.');
    } finally {
      setSaving(false);
    }
  };

  const handleProfileImage = async (event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('profileImage', file);
    setUploading(true);
    try {
      const response = await userApi.uploadProfileImage(formData);
      const profile = response.data || response;
      dispatch(updateUser(profile));
      toast.success('Profile image updated successfully.');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to upload image.');
    } finally {
      setUploading(false);
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Admin Profile</p>
        <h2 className="mt-3 text-3xl font-semibold text-foreground">Your governance profile</h2>
        <p className="mt-3 max-w-3xl text-muted-foreground">
          Update your basic identity details, review your role, and maintain the account used to manage hospital governance tools.
        </p>
      </div>

      <div className="grid gap-6 xl:grid-cols-[320px,minmax(0,1fr)]">
        <article className="rounded-2xl bg-card p-6 shadow-sm">
          <div className="flex flex-col items-center text-center">
            <img
              src={authUser?.profileImage || `https://api.dicebear.com/7.x/initials/svg?seed=${encodeURIComponent(authUser?.name || 'Employee')}`}
              alt={authUser?.name || 'Employee'}
              className="h-28 w-28 rounded-full border border-border object-cover"
            />
            <h3 className="mt-4 text-xl font-semibold text-foreground">{authUser?.name || 'Employee'}</h3>
            <p className="mt-1 text-sm text-muted-foreground">{getRoleLabel(authUser?.role || 'employee')}</p>
            <p className="mt-2 text-xs uppercase tracking-[0.18em] text-muted-foreground">{authUser?.employeeId || 'No employee ID'}</p>
            <label className="mt-5 inline-flex cursor-pointer rounded-full bg-slate-900 px-4 py-2 text-sm font-semibold text-white transition hover:bg-slate-800">
              {uploading ? 'Uploading...' : 'Update Photo'}
              <input type="file" accept="image/*" className="hidden" onChange={handleProfileImage} />
            </label>
          </div>
        </article>

        <form onSubmit={handleSave} className="rounded-2xl bg-card p-6 shadow-sm">
          <div className="grid gap-5 md:grid-cols-2">
            <Field label="Full Name">
              <input
                type="text"
                value={form.name}
                onChange={(event) => setForm((current) => ({ ...current, name: event.target.value }))}
                className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary"
                disabled={loading}
              />
            </Field>
            <Field label="Email">
              <input
                type="email"
                value={authUser?.email || ''}
                className="w-full rounded-2xl border border-border bg-muted/50 px-4 py-3 text-muted-foreground outline-none"
                disabled
              />
            </Field>
            <Field label="Phone">
              <input
                type="text"
                value={form.phone}
                onChange={(event) => setForm((current) => ({ ...current, phone: event.target.value }))}
                className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary"
                disabled={loading}
              />
            </Field>
            <Field label="Gender">
              <select
                value={form.gender}
                onChange={(event) => setForm((current) => ({ ...current, gender: event.target.value }))}
                className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary"
                disabled={loading}
              >
                <option value="">Select gender</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </Field>
            <Field label="Role">
              <input
                type="text"
                value={getRoleLabel(authUser?.role || 'employee')}
                className="w-full rounded-2xl border border-border bg-muted/50 px-4 py-3 text-muted-foreground outline-none"
                disabled
              />
            </Field>
            <Field label="Onboarding Status">
              <input
                type="text"
                value={authUser?.onboardingStatus || 'active'}
                className="w-full rounded-2xl border border-border bg-muted/50 px-4 py-3 text-muted-foreground outline-none"
                disabled
              />
            </Field>
          </div>

          <Field label="Address" className="mt-5">
            <textarea
              value={form.address}
              onChange={(event) => setForm((current) => ({ ...current, address: event.target.value }))}
              className="min-h-[120px] w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary"
              disabled={loading}
            />
          </Field>

          <div className="mt-6 flex flex-wrap items-center gap-3">
            <button
              type="submit"
              disabled={saving || loading}
              className="rounded-full bg-slate-900 px-5 py-3 text-sm font-semibold text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:opacity-60"
            >
              {saving ? 'Saving...' : 'Save Profile'}
            </button>
            <p className="text-sm text-muted-foreground">Password and advanced account security can be expanded in a later module.</p>
          </div>
        </form>
      </div>
    </motion.section>
  );
}

function Field({ children, className = '', label }) {
  return (
    <div className={className}>
      <label className="mb-2 block text-sm font-medium text-foreground">{label}</label>
      {children}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { adminApi } from '../../services/apiServices.js';
import { getRoleLabel } from '../../auth/constants.js';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function AuditHistoryPage() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadAudit = async () => {
      setLoading(true);
      try {
        const response = await adminApi.getAuditHistory({ limit: 30 });
        setLogs(response.logs || []);
        setError('');
      } catch (err) {
        setError(err.response?.data?.message || 'Unable to load audit history.');
      } finally {
        setLoading(false);
      }
    };

    loadAudit();
  }, []);

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Audit History</p>
        <h2 className="mt-3 text-3xl font-semibold text-foreground">Governance activity log</h2>
        <p className="mt-3 max-w-3xl text-muted-foreground">
          This audit foundation records governance actions like user creation and active-status changes so the hospital
          can trace who performed important administrative actions.
        </p>
      </div>

      {error && (
        <article className="rounded-2xl border border-red-200 bg-red-50 p-5 text-sm text-red-700">
          {error}
        </article>
      )}

      <article className="rounded-2xl bg-card p-6 shadow-sm">
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead>
              <tr className="border-b border-border text-left text-muted-foreground">
                <th className="px-2 py-3 font-medium">Action</th>
                <th className="px-2 py-3 font-medium">Actor</th>
                <th className="px-2 py-3 font-medium">Target</th>
                <th className="px-2 py-3 font-medium">Timestamp</th>
              </tr>
            </thead>
            <tbody>
              {loading && (
                <tr>
                  <td colSpan={4} className="px-2 py-8 text-center text-muted-foreground">Loading audit history...</td>
                </tr>
              )}
              {!loading && logs.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-2 py-8 text-center text-muted-foreground">No audit activity available yet.</td>
                </tr>
              )}
              {logs.map((log) => (
                <tr key={log._id} className="border-b border-slate-100 last:border-b-0">
                  <td className="px-2 py-3">
                    <span className="rounded-full bg-slate-900 px-2.5 py-1 text-xs font-semibold text-white capitalize">
                      {log.action}
                    </span>
                  </td>
                  <td className="px-2 py-3 text-foreground">
                    {log.creatorName}
                    <div className="text-xs text-muted-foreground">{getRoleLabel(log.creatorRole)}</div>
                  </td>
                  <td className="px-2 py-3 text-foreground">
                    {log.createdUserName}
                    <div className="text-xs text-muted-foreground">{getRoleLabel(log.createdUserRole)}</div>
                  </td>
                  <td className="px-2 py-3 text-muted-foreground">{new Date(log.createdAt).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </article>
    </motion.section>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useSelector } from 'react-redux';
import { Button } from '../../components/ui/button';
import { billingApi, patientApi } from '../../services/apiServices.js';
import { StatusBadge } from '../../components/StatusBadge.jsx';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialForm = {
  patientId: '',
  billType: 'mixed',
  notes: '',
  lineItems: [{ label: '', category: 'other', quantity: 1, unitPrice: 0, notes: '' }],
};

export default function BillingManagement() {
  const user = useSelector((state) => state.auth.user);
  const [invoices, setInvoices] = useState([]);
  const [patients, setPatients] = useState([]);
  const [filters, setFilters] = useState({ search: '', billType: '', paymentStatus: '', date: '' });
  const [selectedInvoiceId, setSelectedInvoiceId] = useState('');
  const [selectedInvoice, setSelectedInvoice] = useState(null);
  const [form, setForm] = useState(initialForm);
  const [showCreate, setShowCreate] = useState(false);
  const [saving, setSaving] = useState(false);
  const [downloadingId, setDownloadingId] = useState('');

  const loadInvoices = async () => {
    try {
      const data = await billingApi.getAll(filters);
      const list = Array.isArray(data) ? data : [];
      setInvoices(list);
      if (!selectedInvoiceId && list.length) {
        setSelectedInvoiceId(list[0].id);
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load invoices.');
    }
  };

  const loadInvoiceDetail = async (invoiceId) => {
    if (!invoiceId) {
      setSelectedInvoice(null);
      return;
    }
    try {
      const data = await billingApi.getById(invoiceId);
      setSelectedInvoice(data);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load invoice detail.');
    }
  };

  const loadPatients = async () => {
    try {
      const response = await patientApi.getAdminList({});
      setPatients(response.patients || []);
    } catch {
      setPatients([]);
    }
  };

  useEffect(() => {
    loadInvoices();
    loadPatients();
  }, [filters.search, filters.billType, filters.paymentStatus, filters.date]);

  useEffect(() => {
    loadInvoiceDetail(selectedInvoiceId);
  }, [selectedInvoiceId]);

  const totals = useMemo(
    () => ({
      total: invoices.reduce((sum, invoice) => sum + Number(invoice.totalAmount || 0), 0),
      paid: invoices.filter((invoice) => invoice.paymentStatus === 'paid').reduce((sum, invoice) => sum + Number(invoice.totalAmount || 0), 0),
      pending: invoices.filter((invoice) => invoice.paymentStatus === 'pending').reduce((sum, invoice) => sum + Number(invoice.totalAmount || 0), 0),
    }),
    [invoices]
  );

  const updateLineItem = (index, patch) => {
    setForm((current) => ({
      ...current,
      lineItems: current.lineItems.map((item, itemIndex) => (itemIndex === index ? { ...item, ...patch } : item)),
    }));
  };

  const addLineItem = () => {
    setForm((current) => ({
      ...current,
      lineItems: [...current.lineItems, { label: '', category: 'other', quantity: 1, unitPrice: 0, notes: '' }],
    }));
  };

  const createInvoice = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      await billingApi.create({
        patientId: form.patientId,
        billType: form.billType,
        notes: form.notes,
        lineItems: form.lineItems
          .filter((item) => item.label.trim())
          .map((item) => ({
            ...item,
            quantity: Number(item.quantity || 1),
            unitPrice: Number(item.unitPrice || 0),
            lineTotal: Number(item.quantity || 1) * Number(item.unitPrice || 0),
          })),
      });
      toast.success('Invoice created successfully.');
      setShowCreate(false);
      setForm(initialForm);
      await loadInvoices();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create invoice.');
    } finally {
      setSaving(false);
    }
  };

  const markPaid = async (invoiceId) => {
    try {
      await billingApi.pay(invoiceId, { paymentMethod: 'cash' });
      toast.success('Payment marked successfully.');
      await loadInvoices();
      await loadInvoiceDetail(invoiceId);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to mark payment.');
    }
  };

  const downloadPdf = async (invoiceId) => {
    try {
      setDownloadingId(invoiceId);
      const response = await billingApi.downloadPdf(invoiceId);
      const blob = new Blob([response], { type: 'application/pdf' });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `invoice-${invoiceId}.pdf`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to download invoice.');
    } finally {
      setDownloadingId('');
    }
  };

  const emailInvoice = async (invoiceId) => {
    try {
      await billingApi.emailInvoice(invoiceId);
      toast.success('Invoice email sent.');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to send invoice email.');
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="flex flex-col gap-4 rounded-2xl bg-card p-8 shadow-sm md:flex-row md:items-center md:justify-between">
        <div>
          <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Financial Operations</p>
          <h2 className="mt-2 text-3xl font-semibold text-foreground">Billing and payments</h2>
          <p className="mt-2 max-w-3xl text-muted-foreground">
            Manage consultation, lab, pharmacy, and future ward-ready invoices with payment state visibility across patient and staff workflows.
          </p>
        </div>
        <Button onClick={() => setShowCreate(true)}>Create Invoice</Button>
      </div>

      <div className="grid gap-4 md:grid-cols-3">
        <SummaryCard label="Total billed" value={`Γé╣${totals.total.toLocaleString()}`} />
        <SummaryCard label="Paid" value={`Γé╣${totals.paid.toLocaleString()}`} />
        <SummaryCard label="Pending" value={`Γé╣${totals.pending.toLocaleString()}`} />
      </div>

      <section className="rounded-2xl bg-card p-6 shadow-sm">
        <div className="grid gap-3 md:grid-cols-4">
          <input value={filters.search} onChange={(event) => setFilters((current) => ({ ...current, search: event.target.value }))} placeholder="Search invoice, patient, or context" className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary" />
          <select value={filters.billType} onChange={(event) => setFilters((current) => ({ ...current, billType: event.target.value }))} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
            <option value="">All bill types</option>
            <option value="consultation">Consultation</option>
            <option value="lab">Lab</option>
            <option value="pharmacy">Pharmacy</option>
            <option value="ward">Ward</option>
            <option value="mixed">Mixed</option>
          </select>
          <select value={filters.paymentStatus} onChange={(event) => setFilters((current) => ({ ...current, paymentStatus: event.target.value }))} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
            <option value="">All payment states</option>
            <option value="pending">Pending</option>
            <option value="paid">Paid</option>
            <option value="cancelled">Cancelled</option>
          </select>
          <input type="date" value={filters.date} onChange={(event) => setFilters((current) => ({ ...current, date: event.target.value }))} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary" />
        </div>
      </section>

      <div className="grid gap-6 xl:grid-cols-[1fr,1fr]">
        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Invoice List</p>
          <div className="mt-4 space-y-3">
            {invoices.map((invoice) => (
              <button key={invoice.id} type="button" onClick={() => setSelectedInvoiceId(invoice.id)} className={`w-full rounded-xl border p-4 text-left ${selectedInvoiceId === invoice.id ? 'border-slate-900 bg-muted/50' : 'border-border hover:border-border'}`}>
                <div className="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
                  <div>
                    <p className="font-semibold text-foreground">{invoice.invoiceNumber}</p>
                    <p className="mt-1 text-sm text-muted-foreground">{invoice.patient?.name || 'Patient'} ΓÇó {invoice.patient?.patientId || 'No ID'}</p>
                    <p className="mt-1 text-sm text-muted-foreground">{invoice.createdAt ? new Date(invoice.createdAt).toLocaleString() : 'ΓÇö'}</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <StatusBadge status={invoice.billType}>{invoice.billType}</StatusBadge>
                    <StatusBadge status={invoice.paymentStatus}>{invoice.paymentStatus}</StatusBadge>
                  </div>
                </div>
              </button>
            ))}
            {invoices.length === 0 && <p className="rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">No invoices match the selected filters.</p>}
          </div>
        </section>

        <section className="rounded-2xl bg-card p-6 shadow-sm">
          {!selectedInvoice && <div className="py-24 text-center text-muted-foreground">Select an invoice to review its itemized detail.</div>}
          {selectedInvoice && (
            <div className="space-y-5">
              <div className="flex flex-col gap-3 md:flex-row md:items-start md:justify-between">
                <div>
                  <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Invoice Detail</p>
                  <h3 className="mt-2 text-2xl font-semibold text-foreground">{selectedInvoice.invoiceNumber}</h3>
                  <p className="mt-1 text-sm text-muted-foreground">{selectedInvoice.patient?.name || 'Patient'} ΓÇó {selectedInvoice.patient?.patientId || 'No ID'}</p>
                </div>
                <div className="flex flex-wrap gap-2">
                  <StatusBadge status={selectedInvoice.billType}>{selectedInvoice.billType}</StatusBadge>
                  <StatusBadge status={selectedInvoice.paymentStatus}>{selectedInvoice.paymentStatus}</StatusBadge>
                </div>
              </div>

              <article className="rounded-xl border border-border p-4">
                <p className="font-semibold text-foreground">Linked context</p>
                <div className="mt-3 space-y-2 text-sm text-muted-foreground">
                  {selectedInvoice.context?.appointment && (
                    <p>
                      Appointment: {selectedInvoice.context.appointment.date} ΓÇó {selectedInvoice.context.appointment.slot} ΓÇó {selectedInvoice.context.appointment.doctorName || 'Doctor'}
                      {selectedInvoice.context.appointment.consultationMode ? ` ΓÇó ${selectedInvoice.context.appointment.consultationMode}` : ''}
                      {selectedInvoice.context.appointment.locationName ? ` ΓÇó ${selectedInvoice.context.appointment.locationName}` : ''}
                    </p>
                  )}
                  {selectedInvoice.context?.labOrder && <p>Lab Order: {selectedInvoice.context.labOrder.orderNumber} ΓÇó {selectedInvoice.context.labOrder.status}</p>}
                  {selectedInvoice.context?.pharmacyOrder && <p>Pharmacy Order: {selectedInvoice.context.pharmacyOrder.id} ΓÇó {selectedInvoice.context.pharmacyOrder.status}</p>}
                  {selectedInvoice.context?.ward && <p>Ward: {selectedInvoice.context.ward.name}</p>}
                  {!selectedInvoice.context?.appointment && !selectedInvoice.context?.labOrder && !selectedInvoice.context?.pharmacyOrder && !selectedInvoice.context?.ward && <p>No linked operational context.</p>}
                </div>
              </article>

              <article className="rounded-xl border border-border p-4">
                <p className="font-semibold text-foreground">Itemized lines</p>
                <div className="mt-3 space-y-3">
                  {(selectedInvoice.lineItems || []).map((item) => (
                    <div key={item.id} className="flex items-center justify-between gap-4 rounded-xl bg-muted/50 p-4">
                      <div>
                        <p className="font-medium text-foreground">{item.label}</p>
                        <p className="mt-1 text-sm text-muted-foreground capitalize">
                          {item.category || 'charge'} ΓÇó Qty {item.quantity} ΓÇó Unit Γé╣{Number(item.unitPrice || 0).toLocaleString()}
                        </p>
                        {item.notes && <p className="mt-1 text-sm text-muted-foreground">{item.notes}</p>}
                      </div>
                      <p className="font-semibold text-foreground">Γé╣{Number(item.lineTotal || 0).toLocaleString()}</p>
                    </div>
                  ))}
                </div>
              </article>

              <article className="rounded-xl border border-border p-4">
                <div className="space-y-2 text-sm text-muted-foreground">
                  <div className="flex items-center justify-between"><span>Subtotal</span><span>Γé╣{Number(selectedInvoice.subtotal || 0).toLocaleString()}</span></div>
                  <div className="flex items-center justify-between font-semibold text-foreground"><span>Total</span><span>Γé╣{Number(selectedInvoice.totalAmount || 0).toLocaleString()}</span></div>
                  <div className="flex items-center justify-between"><span>Payment method</span><span>{selectedInvoice.paymentMethod || 'Not recorded'}</span></div>
                  <div className="flex items-center justify-between"><span>Paid at</span><span>{selectedInvoice.paidAt ? new Date(selectedInvoice.paidAt).toLocaleString() : 'Pending'}</span></div>
                  <div className="flex items-center justify-between"><span>Operator</span><span>{user?.name || 'Staff'}</span></div>
                </div>
              </article>

              <div className="flex flex-wrap gap-3">
                <Button variant="outline" onClick={() => downloadPdf(selectedInvoice.id)} disabled={downloadingId === selectedInvoice.id}>
                  {downloadingId === selectedInvoice.id ? 'Preparing PDF...' : 'Download PDF'}
                </Button>
                <Button variant="outline" onClick={() => emailInvoice(selectedInvoice.id)}>
                  Email Receipt
                </Button>
                {selectedInvoice.paymentStatus !== 'paid' && (
                  <Button onClick={() => markPaid(selectedInvoice.id)}>Mark Paid</Button>
                )}
              </div>
            </div>
          )}
        </section>
      </div>

      {showCreate && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <form onSubmit={createInvoice} className="max-h-[92vh] w-full max-w-4xl overflow-y-auto rounded-2xl bg-card p-6 shadow-2xl">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold text-foreground">Create Invoice</h3>
              <button type="button" onClick={() => setShowCreate(false)} className="text-muted-foreground hover:text-foreground">Γ£ò</button>
            </div>

            <div className="mt-5 grid gap-4 md:grid-cols-2">
              <Field label="Patient">
                <select value={form.patientId} onChange={(event) => setForm((current) => ({ ...current, patientId: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required>
                  <option value="">Select patient</option>
                  {patients.map((patient) => (
                    <option key={patient.id} value={patient.id}>
                      {patient.user?.name || 'Patient'} ({patient.user?.patientId || 'No ID'})
                    </option>
                  ))}
                </select>
              </Field>
              <Field label="Bill type">
                <select value={form.billType} onChange={(event) => setForm((current) => ({ ...current, billType: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary">
                  <option value="consultation">Consultation</option>
                  <option value="lab">Lab</option>
                  <option value="pharmacy">Pharmacy</option>
                  <option value="ward">Ward</option>
                  <option value="mixed">Mixed</option>
                </select>
              </Field>
            </div>

            <Field label="Internal note" className="mt-4">
              <textarea value={form.notes} onChange={(event) => setForm((current) => ({ ...current, notes: event.target.value }))} className="min-h-[100px] w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
            </Field>

            <div className="mt-6 space-y-4">
              <div className="flex items-center justify-between">
                <h4 className="text-lg font-semibold text-foreground">Line items</h4>
                <Button type="button" variant="outline" onClick={addLineItem}>Add Line</Button>
              </div>
              {form.lineItems.map((item, index) => (
                <div key={`line-${index}`} className="grid gap-3 rounded-xl border border-border p-4 md:grid-cols-4">
                  <input value={item.label} onChange={(event) => updateLineItem(index, { label: event.target.value })} placeholder="Label" className="rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  <input value={item.category} onChange={(event) => updateLineItem(index, { category: event.target.value })} placeholder="Category" className="rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  <input type="number" min="1" value={item.quantity} onChange={(event) => updateLineItem(index, { quantity: event.target.value })} placeholder="Quantity" className="rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  <input type="number" min="0" value={item.unitPrice} onChange={(event) => updateLineItem(index, { unitPrice: event.target.value })} placeholder="Unit price" className="rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  <textarea value={item.notes} onChange={(event) => updateLineItem(index, { notes: event.target.value })} placeholder="Optional notes" className="md:col-span-4 min-h-[80px] rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                </div>
              ))}
            </div>

            <div className="mt-6 flex gap-3">
              <Button type="button" variant="outline" className="flex-1" onClick={() => setShowCreate(false)}>Cancel</Button>
              <Button type="submit" className="flex-1" disabled={saving}>{saving ? 'Creating...' : 'Create Invoice'}</Button>
            </div>
          </form>
        </div>
      )}
    </motion.section>
  );
}

function SummaryCard({ label, value }) {
  return (
    <article className="rounded-xl bg-card p-6 shadow-sm">
      <p className="text-sm text-muted-foreground">{label}</p>
