import { useEffect, useState } from 'react';
import { Button } from '../../components/ui/button';
import { StatusBadge } from '../../components/StatusBadge.jsx';
import { nurseApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialNoteForm = {
  patientId: '',
  noteType: 'general',
  content: '',
};

const initialEscalationForm = {
  patientId: '',
  content: '',
};

export default function NurseNotes() {
  const [patients, setPatients] = useState([]);
  const [notes, setNotes] = useState([]);
  const [escalations, setEscalations] = useState([]);
  const [noteForm, setNoteForm] = useState(initialNoteForm);
  const [escalationForm, setEscalationForm] = useState(initialEscalationForm);

  const load = async () => {
    try {
      const [patientData, noteData, escalationData] = await Promise.all([
        nurseApi.getAssignedPatients(),
        nurseApi.getNotes(),
        nurseApi.getEscalations(),
      ]);
      const patientList = Array.isArray(patientData) ? patientData : [];
      setPatients(patientList);
      setNotes(Array.isArray(noteData) ? noteData : []);
      setEscalations(Array.isArray(escalationData) ? escalationData : []);

      if (!noteForm.patientId && patientList.length) {
        setNoteForm((current) => ({ ...current, patientId: patientList[0].id }));
      }
      if (!escalationForm.patientId && patientList.length) {
        setEscalationForm((current) => ({ ...current, patientId: patientList[0].id }));
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load nursing notes.');
    }
  };

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    load();
  }, []);

  const submitNote = async (event) => {
    event.preventDefault();
    try {
      await nurseApi.createNote(noteForm);
      toast.success('Nursing note added.');
      setNoteForm((current) => ({ ...initialNoteForm, patientId: current.patientId }));
      await load();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create nursing note.');
    }
  };

  const submitEscalation = async (event) => {
    event.preventDefault();
    try {
      await nurseApi.createEscalation(escalationForm);
      toast.success('Escalation note recorded.');
      setEscalationForm((current) => ({ ...initialEscalationForm, patientId: current.patientId }));
      await load();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create escalation note.');
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Care Documentation</p>
        <h2 className="mt-2 text-3xl font-semibold text-foreground">Nursing notes and escalations</h2>
        <p className="mt-2 max-w-3xl text-muted-foreground">
          Document bedside observations, condition changes, general nursing notes, and urgent doctor-attention flags.
        </p>
      </div>

      <div className="grid gap-6 xl:grid-cols-2">
        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Add Nursing Note</p>
          <form className="mt-4 space-y-4" onSubmit={submitNote}>
            <select value={noteForm.patientId} onChange={(event) => setNoteForm((current) => ({ ...current, patientId: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
              <option value="">Select patient</option>
              {patients.map((patient) => (
                <option key={patient.id} value={patient.id}>
                  {patient.name} ({patient.patientId || 'No ID'})
                </option>
              ))}
            </select>
            <select value={noteForm.noteType} onChange={(event) => setNoteForm((current) => ({ ...current, noteType: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
              <option value="general">General care note</option>
              <option value="condition">Condition note</option>
              <option value="observation">Observation note</option>
              <option value="medication">Medication note</option>
              <option value="incident">Incident note</option>
            </select>
            <textarea value={noteForm.content} onChange={(event) => setNoteForm((current) => ({ ...current, content: event.target.value }))} rows={5} placeholder="Write the nursing note" className="w-full rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary" />
            <Button type="submit" className="w-full" disabled={!noteForm.patientId || !noteForm.content.trim()}>
              Save nursing note
            </Button>
          </form>
        </section>

        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Add Escalation</p>
          <form className="mt-4 space-y-4" onSubmit={submitEscalation}>
            <select value={escalationForm.patientId} onChange={(event) => setEscalationForm((current) => ({ ...current, patientId: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
              <option value="">Select patient</option>
              {patients.map((patient) => (
                <option key={patient.id} value={patient.id}>
                  {patient.name} ({patient.patientId || 'No ID'})
                </option>
              ))}
            </select>
            <textarea value={escalationForm.content} onChange={(event) => setEscalationForm((current) => ({ ...current, content: event.target.value }))} rows={5} placeholder="Describe why doctor attention is needed" className="w-full rounded-2xl border border-red-200 px-4 py-3 text-sm outline-none focus:border-red-500" />
            <Button type="submit" className="w-full" disabled={!escalationForm.patientId || !escalationForm.content.trim()}>
              Save escalation note
            </Button>
          </form>
        </section>
      </div>

      <div className="grid gap-6 xl:grid-cols-2">
        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Recent Nursing Notes</p>
          <div className="mt-4 space-y-3">
            {notes.map((note) => (
              <article key={note.id} className="rounded-xl border border-border p-4">
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="font-medium text-foreground">{note.patient?.name || 'Assigned patient'}</p>
                    <p className="mt-1 text-sm text-muted-foreground">{note.patient?.patientId || 'No patient ID'}</p>
                  </div>
                  <StatusBadge status={note.noteType}>{note.noteType}</StatusBadge>
                </div>
                <p className="mt-3 text-sm text-foreground">{note.content}</p>
                <p className="mt-2 text-xs text-muted-foreground">{new Date(note.createdAt).toLocaleString()}</p>
              </article>
            ))}
            {notes.length === 0 && <p className="text-sm text-muted-foreground">No nursing notes have been recorded yet.</p>}
          </div>
        </section>

        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Escalation Flags</p>
          <div className="mt-4 space-y-3">
            {escalations.map((note) => (
              <article key={note.id} className="rounded-xl border border-red-200 bg-red-50 p-4">
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="font-medium text-foreground">{note.patient?.name || 'Assigned patient'}</p>
                    <p className="mt-1 text-sm text-muted-foreground">{note.patient?.patientId || 'No patient ID'}</p>
                  </div>
                  <StatusBadge status="urgent">Doctor attention</StatusBadge>
                </div>
                <p className="mt-3 text-sm text-foreground">{note.content}</p>
                <p className="mt-2 text-xs text-muted-foreground">{new Date(note.createdAt).toLocaleString()}</p>
              </article>
            ))}
            {escalations.length === 0 && <p className="text-sm text-muted-foreground">No escalation notes are currently logged.</p>}
          </div>
        </section>
      </div>
    </motion.section>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { StatusBadge } from '../../components/StatusBadge.jsx';
import { nurseApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function NursePatients() {
  const [patients, setPatients] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedPatientId, setSelectedPatientId] = useState('');

  useEffect(() => {
    const load = async () => {
      try {
        const data = await nurseApi.getAssignedPatients();
        const list = Array.isArray(data) ? data : [];
        setPatients(list);
        if (!selectedPatientId && list.length) {
          setSelectedPatientId(list[0].id);
        }
      } catch (error) {
        toast.error(error.response?.data?.message || 'Failed to load assigned patients.');
      }
    };

    load();
  }, []);

  const filteredPatients = useMemo(() => {
    const query = search.toLowerCase();
    return patients.filter((patient) => {
      const text = [
        patient.name,
        patient.patientId,
        patient.assignedDoctor?.name,
        patient.diagnosisSummary,
        patient.ward?.name,
      ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();
      return !query || text.includes(query);
    });
  }, [patients, search]);

  const selectedPatient =
    filteredPatients.find((patient) => patient.id === selectedPatientId) ||
    patients.find((patient) => patient.id === selectedPatientId) ||
    null;

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Assigned Scope</p>
        <h2 className="mt-2 text-3xl font-semibold text-foreground">Assigned patients</h2>
        <p className="mt-2 max-w-3xl text-muted-foreground">
          Review your assigned patients, active medication context, allergies, diagnosis notes, lab visibility, and latest vitals.
        </p>
      </div>

      <section className="rounded-2xl bg-card p-6 shadow-sm">
        <input
          value={search}
          onChange={(event) => setSearch(event.target.value)}
          placeholder="Search patient, ID, doctor, diagnosis, or ward"
          className="w-full rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary"
        />
      </section>

      <div className="grid gap-6 xl:grid-cols-[0.9fr,1.1fr]">
        <section className="rounded-2xl bg-card p-6 shadow-sm">
          <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Patient Load</p>
          <div className="mt-4 space-y-3">
            {filteredPatients.map((patient) => (
              <button
                key={patient.id}
                type="button"
                onClick={() => setSelectedPatientId(patient.id)}
                className={`w-full rounded-xl border p-4 text-left ${
                  selectedPatientId === patient.id ? 'border-slate-900 bg-muted/50' : 'border-border bg-card hover:border-border'
                }`}
              >
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <p className="font-semibold text-foreground">{patient.name}</p>
                    <p className="mt-1 text-sm text-muted-foreground">
                      {patient.patientId || 'No patient ID'} ΓÇó {patient.age ?? 'ΓÇö'} yrs ΓÇó {patient.gender || 'ΓÇö'}
                    </p>
                    <p className="mt-1 text-sm text-muted-foreground">
                      {patient.ward?.name || 'No ward'} {patient.bed?.bedNumber ? `ΓÇó Bed ${patient.bed.bedNumber}` : ''}
                    </p>
                    <div className="mt-2 flex flex-wrap gap-2">
                      {patient.allergies?.length > 0 && (
                        <StatusBadge status="urgent">Allergy</StatusBadge>
                      )}
                      {patient.chronicDiseases?.length > 0 && (
                        <StatusBadge status="inProgress">Chronic</StatusBadge>
                      )}
                      {patient.latestVitals && (
                        <StatusBadge status="pending">Vitals on file</StatusBadge>
                      )}
                    </div>
                  </div>
                  {patient.pendingLabOrders?.length > 0 && (
                    <StatusBadge status="urgent">Lab pending</StatusBadge>
                  )}
                </div>
              </button>
            ))}
            {filteredPatients.length === 0 && (
              <p className="rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">
                No assigned patients match the current search.
              </p>
            )}
          </div>
        </section>

        <section className="rounded-2xl bg-card p-6 shadow-sm">
          {!selectedPatient && <div className="py-24 text-center text-muted-foreground">Select a patient to review their nursing care context.</div>}
          {selectedPatient && (
            <div className="space-y-5">
              <div>
                <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Patient Summary</p>
                <h3 className="mt-2 text-2xl font-semibold text-foreground">{selectedPatient.name}</h3>
                <p className="mt-1 text-sm text-muted-foreground">
                  {selectedPatient.patientId || 'No patient ID'} ΓÇó {selectedPatient.assignedDoctor?.name || 'No assigned doctor visible'}
                </p>
              </div>

              <div className="grid gap-4 md:grid-cols-2">
                <article className="rounded-xl border border-border p-4">
                  <p className="text-sm text-muted-foreground">Diagnosis summary</p>
                  <p className="mt-2 text-sm text-foreground">{selectedPatient.diagnosisSummary || 'No diagnosis summary available.'}</p>
                </article>
                <article className="rounded-xl border border-border p-4">
                  <p className="text-sm text-muted-foreground">Ward and bed</p>
                  <p className="mt-2 text-sm text-foreground">
                    {selectedPatient.ward?.name || 'No ward'}
                    {selectedPatient.bed?.bedNumber ? ` ΓÇó Bed ${selectedPatient.bed.bedNumber}` : ''}
                  </p>
                </article>
              </div>

              <article className="rounded-xl border border-border p-4">
                <p className="font-semibold text-foreground">Risk and history</p>
                <div className="mt-3 grid gap-4 md:grid-cols-2">
                  <div>
                    <p className="text-sm text-muted-foreground">Allergies</p>
                    <p className="mt-2 text-sm text-foreground">
                      {selectedPatient.allergies?.length ? selectedPatient.allergies.join(', ') : 'No allergies recorded'}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-muted-foreground">Chronic diseases</p>
                    <p className="mt-2 text-sm text-foreground">
                      {selectedPatient.chronicDiseases?.length ? selectedPatient.chronicDiseases.join(', ') : 'No chronic diseases recorded'}
                    </p>
                  </div>
                </div>
              </article>

              <article className="rounded-xl border border-border p-4">
                <p className="font-semibold text-foreground">Doctor instructions and medications</p>
                <div className="mt-3 space-y-3">
                  {(selectedPatient.medicationSummary || []).map((medicine, index) => (
                    <div key={`${selectedPatient.id}-med-${index}`} className="rounded-xl bg-muted/50 p-4">
                      <p className="font-medium text-foreground">{medicine.name}</p>
                      <p className="mt-1 text-sm text-muted-foreground">
                        {medicine.dosage || 'Dose not set'} ΓÇó {medicine.frequency || 'Frequency not set'} ΓÇó {medicine.duration || 'Duration not set'}
                      </p>
                      {medicine.instructions && <p className="mt-1 text-sm text-muted-foreground">{medicine.instructions}</p>}
                    </div>
                  ))}
                  {selectedPatient.medicationSummary?.length === 0 && (
                    <p className="text-sm text-muted-foreground">No active prescription medicines are visible for this patient.</p>
                  )}
                </div>
                {selectedPatient.activePrescription && (
                  <div className="mt-4 rounded-xl bg-amber-50 p-4 text-sm text-foreground">
                    <p><span className="font-semibold">Advice:</span> {selectedPatient.activePrescription.advice || 'No advice recorded.'}</p>
                    <p className="mt-2">
                      <span className="font-semibold">Admission recommendation:</span>{' '}
                      {selectedPatient.activePrescription.admissionRecommended ? 'Recommended' : 'Not marked'}
                    </p>
                  </div>
                )}
              </article>

              <div className="grid gap-4 md:grid-cols-2">
                <article className="rounded-xl border border-border p-4">
                  <p className="font-semibold text-foreground">Pending lab visibility</p>
                  <div className="mt-3 space-y-2">
                    {(selectedPatient.pendingLabOrders || []).map((order) => (
                      <div key={order.id} className="rounded-xl bg-muted/50 p-3">
                        <p className="text-sm font-medium text-foreground">{order.tests.join(', ') || 'Lab order'}</p>
                        <p className="mt-1 text-xs text-muted-foreground">
                          {order.orderNumber || order.id} ΓÇó {order.status} ΓÇó {order.urgency || 'routine'}
                        </p>
                      </div>
                    ))}
                    {selectedPatient.pendingLabOrders?.length === 0 && (
                      <p className="text-sm text-muted-foreground">No pending lab work is visible right now.</p>
                    )}
                  </div>
                </article>

                <article className="rounded-xl border border-border p-4">
                  <p className="font-semibold text-foreground">Latest vitals</p>
                  {selectedPatient.latestVitals ? (
                    <div className="mt-3 space-y-2 text-sm text-foreground">
                      <p>Recorded: {new Date(selectedPatient.latestVitals.recordedAt).toLocaleString()}</p>
                      <p>BP: {selectedPatient.latestVitals.bloodPressure || 'ΓÇö'}</p>
                      <p>Pulse: {selectedPatient.latestVitals.pulse || 'ΓÇö'}</p>
                      <p>Temperature: {selectedPatient.latestVitals.temperature || 'ΓÇö'}</p>
                      <p>SpO2: {selectedPatient.latestVitals.spo2 || 'ΓÇö'}</p>
                    </div>
                  ) : (
                    <p className="mt-3 text-sm text-muted-foreground">No vitals have been recorded yet.</p>
                  )}
                </article>
              </div>
            </div>
          )}
        </section>
      </div>
    </motion.section>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { Button } from '../../components/ui/button';
import { StatusBadge } from '../../components/StatusBadge.jsx';
import { nurseApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialTaskForm = {
  patientId: '',
  wardId: '',
  taskType: 'vitals recording',
  dueAt: '',
  notes: '',
};

export default function NurseTasks() {
  const [patients, setPatients] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [filters, setFilters] = useState({ status: '', patientId: '', type: '' });
  const [taskForm, setTaskForm] = useState(initialTaskForm);
  const [saving, setSaving] = useState(false);

  const selectedPatient = patients.find((patient) => patient.id === taskForm.patientId) || null;

  const load = async () => {
    try {
      const [patientData, taskData] = await Promise.all([
        nurseApi.getAssignedPatients(),
        nurseApi.getTasks(filters),
      ]);
      const patientList = Array.isArray(patientData) ? patientData : [];
      setPatients(patientList);
      setTasks(Array.isArray(taskData) ? taskData : []);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load nursing tasks.');
    }
  };

  useEffect(() => {
    load();
  }, [filters.status, filters.patientId, filters.type]);

  useEffect(() => {
    if (!taskForm.patientId && patients.length) {
      setTaskForm((current) => ({
        ...current,
        patientId: patients[0].id,
        wardId: patients[0].ward?.id || '',
      }));
    }
  }, [patients, taskForm.patientId]);

  const taskStats = useMemo(
    () => ({
      pending: tasks.filter((task) => task.status === 'pending').length,
      inProgress: tasks.filter((task) => task.status === 'inProgress').length,
      completed: tasks.filter((task) => task.status === 'completed').length,
      missed: tasks.filter((task) => task.status === 'missed').length,
    }),
    [tasks]
  );

  const createTask = async (event) => {
    event.preventDefault();
    try {
      setSaving(true);
      await nurseApi.createTask(taskForm);
      toast.success('Nursing task created.');
      setTaskForm((current) => ({ ...initialTaskForm, patientId: current.patientId, wardId: current.wardId }));
      await load();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create nursing task.');
    } finally {
      setSaving(false);
    }
  };

  const updateStatus = async (taskId, status) => {
    try {
      await nurseApi.updateTask(taskId, { status });
      toast.success('Task updated.');
      await load();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update nursing task.');
    }
  };

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.15em] text-muted-foreground">Nursing Workflow</p>
        <h2 className="mt-2 text-3xl font-semibold text-foreground">Task list</h2>
        <p className="mt-2 max-w-3xl text-muted-foreground">
          Manage bedside tasks for medicine support, vitals recording, observation rounds, discharge prep, and doctor-round assistance.
        </p>
      </div>

      <div className="grid gap-4 md:grid-cols-4">
