              className="w-full rounded-full bg-red-600 px-5 py-3 text-sm font-semibold text-white shadow-sm disabled:opacity-50"
            >
              {saving ? 'BookingΓÇª' : payLater ? 'Book Appointment' : 'Confirm & Pay'}
            </button>
          </CardContent>
        </Card>
      </div>
    </motion.section>
  );
}

