import { useEffect, useRef, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import { motion } from 'framer-motion';
import { MapPin, BriefcaseMedical, GraduationCap, IndianRupee, Trophy, ArrowLeft, Calendar, Video } from 'lucide-react';
import { appointmentApi, getDoctorPublicById, slotApi } from '../../services/apiServices.js';
import { SkeletonCard } from '../../components/ui/skeleton.jsx';
import { fadeInUp, fadeInLeft, fadeInRight, staggerContainer, staggerItem } from '../../lib/animation-variants.js';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '../../components/ui/tabs.jsx';
import { useSelector } from 'react-redux';
import { toast } from 'sonner';

export default function PublicDoctorProfile() {
  const { id } = useParams();
  const { isAuthenticated, sessionType, user } = useSelector((state) => state.auth);
  const isPatient = isAuthenticated && sessionType === 'patient' && user?.role === 'patient';
  const [doctor, setDoctor] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const bookingRef = useRef(null);
  const [bookingDate, setBookingDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [availableSlots, setAvailableSlots] = useState([]);
  const [allSlots, setAllSlots] = useState([]);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [selectedSlot, setSelectedSlot] = useState('');
  const [slotLoading, setSlotLoading] = useState(false);
  const [bookingMode, setBookingMode] = useState('in-person');
  const [bookingLocationId, setBookingLocationId] = useState('');
  const [bookingSaving, setBookingSaving] = useState(false);

  useEffect(() => {
    const loadDoctor = async () => {
      setLoading(true);
      try { setDoctor(await getDoctorPublicById(id)); setError(''); }
      catch (err) { setError(err.response?.data?.message || 'Doctor profile not available.'); }
      finally { setLoading(false); }
    };
    loadDoctor();
  }, [id]);

  useEffect(() => {
    const loadSlots = async () => {
      if (!doctor?._id || !bookingDate) return;
      setSlotLoading(true);
      try {
        const response = await slotApi.getByDoctor(doctor._id, bookingDate);
        setAvailableSlots(response?.availableSlots || []);
        setAllSlots(response?.allSlots || response?.availableSlots || []);
        setBookedSlots(response?.bookedSlots || []);
      } catch (err) {
        setAvailableSlots([]);
        setAllSlots([]);
        setBookedSlots([]);
      } finally {
        setSlotLoading(false);
      }
    };
    loadSlots();
  }, [doctor?._id, bookingDate]);

  const resolveFee = () => {
    if (!doctor) return 0;
    let fee = doctor.consultationFee || 0;
    if (bookingMode === 'video' && doctor.consultationFeeVideo != null) {
      fee = doctor.consultationFeeVideo;
    }
    if (bookingMode === 'phone' && doctor.consultationFeePhone != null) {
      fee = doctor.consultationFeePhone;
    }
    if (bookingMode === 'in-person' && bookingLocationId) {
      const match = (doctor.locationFees || []).find((item) => item.locationId === bookingLocationId || item.locationId?._id === bookingLocationId);
      if (match?.fee != null) fee = match.fee;
    }
    return fee;
  };

  const slotsVisible = !(
    bookingMode === 'in-person' &&
    (doctor?.hospitalLocations || []).length > 0 &&
    !bookingLocationId
  );

  const handleBook = async () => {
    if (!selectedSlot) {
      toast.error('Select a slot to continue.');
      return;
    }
    setBookingSaving(true);
    try {
      await appointmentApi.book({
        doctorId: doctor._id,
        date: bookingDate,
        slot: selectedSlot,
        visitType: 'newConsultation',
        consultationMode: bookingMode,
        hospitalLocationId: bookingMode === 'in-person' ? bookingLocationId || undefined : undefined,
      });
      toast.success('Appointment booked successfully.');
      setSelectedSlot('');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Unable to book appointment.');
    } finally {
      setBookingSaving(false);
    }
  };

  if (loading) {
    return (
      <section className="px-4 py-14 sm:px-6">
        <div className="mx-auto max-w-6xl grid gap-8 lg:grid-cols-[280px,1fr]">
          <SkeletonCard className="h-80" />
          <div className="space-y-4"><SkeletonCard /><SkeletonCard /><SkeletonCard /></div>
        </div>
      </section>
    );
  }

  if (!doctor) {
    return (
      <section className="px-4 py-14 sm:px-6">
        <div className="mx-auto max-w-6xl rounded-2xl border border-border bg-card p-12 text-center shadow-sm">
          <h1 className="text-3xl font-bold text-foreground">Profile unavailable</h1>
          <p className="mt-3 text-muted-foreground">{error || 'This doctor could not be loaded.'}</p>
          <Link to="/find-doctors" className="mt-6 inline-flex items-center gap-2 rounded-full bg-primary px-5 py-2.5 text-sm font-semibold text-primary-foreground">
            <ArrowLeft className="h-4 w-4" /> Back to doctors
          </Link>
        </div>
      </section>
    );
  }

  const specializationList = (doctor.specializationIds || []).map((item) => item.name);
  const expertiseList = doctor.expertise || [];

  return (
    <section className="px-4 py-10 sm:px-6">
      <div className="mx-auto max-w-6xl space-y-6">
        <motion.div {...fadeInUp}>
          <Link to="/find-doctors" className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2 text-sm font-medium text-foreground shadow-sm transition-colors hover:bg-muted">
            <ArrowLeft className="h-3.5 w-3.5" /> Back to Doctor Discovery
          </Link>
        </motion.div>

        <div className="grid gap-6 lg:grid-cols-[1.1fr,0.9fr]">
          <div className="rounded-3xl border border-border bg-card p-6 shadow-sm sm:p-8">
            <motion.div {...fadeInLeft} className="grid gap-6 lg:grid-cols-[240px,1fr]">
              <div className="flex flex-col items-center gap-4">
                <div className="relative">
                  <img
                    src={doctor.profileImage || `https://api.dicebear.com/7.x/initials/svg?seed=${encodeURIComponent(doctor.userId?.name || 'Doctor')}`}
                    alt={doctor.userId?.name || 'Doctor'}
                    className="h-56 w-56 rounded-full object-cover ring-4 ring-border shadow-lg"
                  />
                </div>
                <div className="rounded-2xl bg-muted/50 px-4 py-3 text-center">
                  <p className="text-sm text-muted-foreground">Consultation Fee</p>
                  <p className="mt-1 text-2xl font-bold text-foreground">Γé╣{Number(doctor.consultationFee || 0).toLocaleString()}</p>
                </div>
              </div>

              <div className="space-y-4">
                <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Doctor Profile</p>
                <h1 className="text-3xl font-bold text-foreground sm:text-4xl">{doctor.title} {doctor.userId?.name}</h1>
                <p className="text-lg text-muted-foreground">{doctor.departmentId?.name || 'Clinical Department'}</p>
                <p className="text-sm text-muted-foreground">{doctor.qualifications?.join(' | ') || 'Qualifications to be updated'}</p>
                <p className="text-sm text-muted-foreground">Experience: {doctor.experienceYears || 0}+ years</p>

                <div className="flex flex-wrap gap-2 pt-2">
                  {isPatient ? (
                    <>
                      <button
                        type="button"
                        onClick={() => {
                          setBookingMode('in-person');
                          bookingRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }}
                        className="inline-flex items-center gap-2 rounded-full bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-sm hover:brightness-110 transition-all active:scale-[0.98]"
                      >
                        <Calendar className="h-4 w-4" /> Book in-hospital
                      </button>
                      <button
                        type="button"
                        onClick={() => {
                          setBookingMode('video');
                          bookingRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
                        }}
                        className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm hover:bg-muted"
                      >
                        <Video className="h-4 w-4" /> Video consult
                      </button>
                    </>
                  ) : (
                    <>
                      <Link
                        to="/patient/register"
                        className="inline-flex items-center gap-2 rounded-full bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground shadow-sm hover:brightness-110 transition-all active:scale-[0.98]"
                      >
                        <Calendar className="h-4 w-4" /> Register to book
                      </Link>
                      <Link
                        to="/patient/login"
                        className="inline-flex items-center gap-2 rounded-full border border-border bg-card px-4 py-2.5 text-sm font-semibold text-foreground shadow-sm hover:bg-muted"
                      >
                        <Video className="h-4 w-4" /> Patient login
                      </Link>
                    </>
                  )}
                </div>

                <motion.div variants={staggerContainer} initial="initial" animate="animate" className="grid gap-3 sm:grid-cols-3">
                  <QuickStat icon={BriefcaseMedical} label="Experience" value={`${doctor.experienceYears || 0} years`} />
                  <QuickStat icon={GraduationCap} label="Qualifications" value={(doctor.qualifications || []).length || 0} />
                  <QuickStat icon={IndianRupee} label="Fee" value={`Γé╣${Number(doctor.consultationFee || 0).toLocaleString()}`} />
                </motion.div>
              </div>
            </motion.div>
          </div>

          <motion.div {...fadeInRight} className="rounded-3xl border border-border bg-card p-6 shadow-sm sm:p-8" ref={bookingRef}>
            <Tabs defaultValue="inHospital">
              <TabsList>
                <TabsTrigger value="inHospital">In-Hospital</TabsTrigger>
                <TabsTrigger value="video">Video</TabsTrigger>
              </TabsList>

              <TabsContent value="inHospital">
                <div className="space-y-4">
                  {(doctor.hospitalLocations || []).map((item) => (
                    <button
                      key={item._id}
                      type="button"
                      onClick={() => {
                        setBookingMode('in-person');
                        setBookingLocationId(item._id);
                        bookingRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
                      }}
                      className={`w-full rounded-2xl border p-4 text-left transition-colors ${
                        bookingLocationId === item._id
                          ? 'border-primary bg-primary/10'
                          : 'border-border hover:bg-muted/30'
                      }`}
                    >
                      <p className="font-semibold text-foreground">{item.name}</p>
                      <p className="mt-1 text-sm text-muted-foreground">
                        {availableSlots.length} slots available ΓÇó Γé╣{Number(doctor.consultationFee || 0).toLocaleString()}
                      </p>
                      <p className="mt-1 flex items-center gap-2 text-xs text-muted-foreground">
                        <MapPin className="h-3.5 w-3.5 text-primary" />
                        {[item.city, item.state].filter(Boolean).join(', ')}
                      </p>
                    </button>
                  ))}
                  {(doctor.hospitalLocations || []).length === 0 && (
                    <p className="text-sm text-muted-foreground">Hospital availability will be updated soon.</p>
                  )}
                </div>
              </TabsContent>

              <TabsContent value="video">
                <div className="rounded-2xl border border-dashed border-border p-6 text-center text-sm text-muted-foreground">
                  Video consultation slots will appear here when they are published by the hospital team.
                </div>
              </TabsContent>
            </Tabs>

            <div className="mt-6 rounded-2xl border border-border p-4">
              <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Book an appointment</p>
              {!isPatient && (
                <p className="mt-2 text-sm text-muted-foreground">
                  Sign in as a patient to select a slot and confirm an appointment.
                </p>
              )}
              {isPatient && (
                <div className="mt-4 space-y-4">
                  <div>
                    <label className="mb-2 block text-sm font-medium text-foreground">Select date</label>
                    <input
                      type="date"
                      value={bookingDate}
                      onChange={(e) => {
                        setBookingDate(e.target.value);
                        setSelectedSlot('');
                      }}
                      className="w-full rounded-xl border border-border bg-card px-4 py-2.5 text-sm text-foreground outline-none focus:border-primary dark:[color-scheme:dark]"
                    />
                  </div>
                  {bookingMode === 'in-person' && (doctor.hospitalLocations || []).length > 0 && (
                    <div>
                      <label className="mb-2 block text-sm font-medium text-foreground">Select location</label>
                      <select
                        value={bookingLocationId}
                        onChange={(e) => setBookingLocationId(e.target.value)}
                        className="w-full rounded-xl border border-border bg-card px-4 py-2.5 text-sm text-foreground outline-none focus:border-primary"
                      >
                        <option value="">Choose hospital location</option>
                        {(doctor.hospitalLocations || []).map((loc) => (
                          <option key={loc._id} value={loc._id}>
                            {loc.name}{loc.city ? ` ΓÇó ${loc.city}` : ''}
                          </option>
                        ))}
                      </select>
                    </div>
                  )}
                  <div>
                    <label className="mb-2 block text-sm font-medium text-foreground">Available slots</label>
                    <div className="flex flex-wrap gap-2">
                      {slotLoading && <span className="text-sm text-muted-foreground">Loading slots...</span>}
                      {!slotLoading &&
                        bookingMode === 'in-person' &&
                        (doctor.hospitalLocations || []).length > 0 &&
                        !bookingLocationId && (
                          <span className="text-sm text-muted-foreground">Select a hospital location to view slots.</span>
                        )}
                      {!slotLoading && slotsVisible && (allSlots.length ? allSlots : availableSlots).map((slot) => {
                        const isBooked = bookedSlots.includes(slot);
                        const isSelected = selectedSlot === slot;
                        return (
                          <button
                            key={slot}
                            type="button"
                            disabled={isBooked}
                            onClick={() => setSelectedSlot(slot)}
                            className={`rounded-full px-4 py-2 text-xs font-semibold transition ${
                              isBooked
                                ? 'bg-red-500/15 text-red-500 border border-red-500/30 cursor-not-allowed'
                                : isSelected
                                  ? 'bg-primary text-primary-foreground'
                                  : 'border border-border bg-card text-foreground hover:bg-muted'
                            }`}
                          >
                            {slot}
                          </button>
                        );
                      })}
                      {!slotLoading && slotsVisible && (allSlots.length ? allSlots : availableSlots).length === 0 && (
                        <span className="text-sm text-muted-foreground">No slots published for this date.</span>
                      )}
                    </div>
                  </div>
                  <div className="rounded-xl border border-border bg-muted/30 px-4 py-3 text-sm text-muted-foreground">
                    Estimated consultation fee: <span className="font-semibold text-foreground">Γé╣{Number(resolveFee() || 0).toLocaleString()}</span>
                  </div>
                  <button
                    type="button"
                    onClick={handleBook}
                    disabled={!selectedSlot || bookingSaving || (bookingMode === 'in-person' && (doctor.hospitalLocations || []).length > 0 && !bookingLocationId)}
                    className="w-full rounded-xl bg-primary px-4 py-2.5 text-sm font-semibold text-primary-foreground disabled:opacity-60"
                  >
                    {bookingSaving ? 'Booking...' : 'Confirm appointment'}
                  </button>
                </div>
              )}
            </div>
          </motion.div>
        </div>

        <div className="rounded-3xl border border-border bg-card p-6 shadow-sm sm:p-8 space-y-6">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Specialization and Expertise</p>
            <div className="mt-4 grid gap-3 sm:grid-cols-2">
              {[...specializationList, ...expertiseList].length === 0 && (
                <p className="text-sm text-muted-foreground">Specializations will be updated by the hospital team soon.</p>
              )}
              {[...specializationList, ...expertiseList].map((item) => (
                <div key={item} className="rounded-xl border border-border px-4 py-3 text-sm text-foreground">
                  {item}
                </div>
              ))}
            </div>
          </div>

          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">About</p>
            <p className="mt-3 text-muted-foreground leading-relaxed">{doctor.about || 'Profile details will be updated by the hospital team soon.'}</p>
          </div>

          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Articles</p>
            <div className="mt-3 space-y-3">
              {(doctor.articles || []).length === 0 && (
                <p className="text-sm text-muted-foreground">Articles will appear here when published.</p>
              )}
              {(doctor.articles || []).map((article, index) => (
                <a key={`article-${index}`} href={article.link || '#'} target="_blank" rel="noreferrer" className="flex items-center gap-4 rounded-2xl border border-border p-4 hover:bg-muted/30">
                  <img
                    src={article.image || `https://api.dicebear.com/7.x/initials/svg?seed=${encodeURIComponent(article.title || 'Article')}`}
                    alt={article.title || 'Article'}
                    className="h-12 w-12 rounded-xl object-cover"
                  />
                  <div>
                    <p className="text-sm text-muted-foreground">{article.date || 'Article'}</p>
                    <p className="text-base font-semibold text-foreground">{article.title || 'Article title'}</p>
                    <p className="text-xs text-muted-foreground">By {doctor.userId?.name || 'Doctor'}</p>
                  </div>
                </a>
              ))}
            </div>
          </div>

          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Media</p>
            <div className="mt-3 grid gap-4 md:grid-cols-2">
              {(doctor.media || []).length === 0 && (
                <p className="text-sm text-muted-foreground">Media will appear here when published.</p>
              )}
              {(doctor.media || []).map((item, index) => (
                <a key={`media-${index}`} href={item.url || '#'} target="_blank" rel="noreferrer" className="rounded-2xl border border-border p-4 hover:bg-muted/30">
                  <p className="text-xs text-muted-foreground uppercase">{item.type || 'Media'}</p>
                  <p className="mt-2 text-base font-semibold text-foreground">{item.title || 'Media item'}</p>
                  {item.thumbnail && (
                    <img src={item.thumbnail} alt={item.title || 'Media'} className="mt-3 w-full rounded-xl object-cover" />
                  )}
                </a>
              ))}
            </div>
          </div>
        </div>

        {(doctor.awards || []).length > 0 && (
          <div className="rounded-3xl border border-border bg-card p-6 shadow-sm sm:p-8">
            <p className="text-xs font-semibold uppercase tracking-[0.2em] text-muted-foreground">Awards</p>
            <div className="mt-4 grid gap-3 md:grid-cols-2">
              {doctor.awards.map((award) => (
                <article key={award._id} className="rounded-xl border border-border p-4">
                  <p className="flex items-center gap-2 text-sm font-semibold text-chart-5">
                    <Trophy className="h-4 w-4" /> {award.year || 'Recognition'}
                  </p>
                  <h3 className="mt-2 text-lg font-semibold text-foreground">{award.title}</h3>
                  <p className="mt-1 text-sm text-muted-foreground">{award.organization}</p>
                  {award.description && <p className="mt-2 text-xs text-muted-foreground">{award.description}</p>}
                </article>
              ))}
            </div>
          </div>
        )}
      </div>
    </section>
  );
}

function QuickStat({ icon: Icon, label, value }) {
  return (
    <motion.article variants={staggerItem} className="rounded-xl border border-border p-4 transition-colors hover:bg-muted/30">
      <div className="flex items-center gap-2 text-sm text-muted-foreground">
        <Icon className="h-4 w-4 text-primary" /> {label}
      </div>
      <p className="mt-2 text-lg font-bold text-foreground">{value}</p>
    </motion.article>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Button } from '../../components/ui/button';
import { appointmentApi, billingApi, receptionistApi, slotApi } from '../../services/apiServices.js';
import { toast } from 'sonner';
import { Calendar, RefreshCw, Search } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

const initialBooking = {
  patientId: '',
  doctorId: '',
  departmentId: '',
  date: new Date().toISOString().split('T')[0],
  slot: '',
  visitType: 'newConsultation',
  consultationMode: 'in-person',
  reasonForVisit: '',
};

const initialWalkIn = {
  name: '',
  email: '',
  phone: '',
  dateOfBirth: '',
  gender: 'unknown',
  address: '',
  bloodGroup: '',
  allergies: '',
  chronicDiseases: '',
  emergencyContactName: '',
  emergencyContactPhone: '',
  emergencyContactRelation: '',
};

export default function AppointmentDesk() {
  const [searchParams] = useSearchParams();
  const preselectedPatientId = searchParams.get('patientId') || '';
  const [patients, setPatients] = useState([]);
  const [patientQuery, setPatientQuery] = useState('');
  const [booking, setBooking] = useState({ ...initialBooking, patientId: preselectedPatientId });
  const [options, setOptions] = useState({ departments: [], doctors: [] });
  const [availableSlots, setAvailableSlots] = useState([]);
  const [allSlots, setAllSlots] = useState([]);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [slotLoading, setSlotLoading] = useState(false);
  const [queue, setQueue] = useState([]);
  const [queueSummary, setQueueSummary] = useState(null);
  const [filterDoctor, setFilterDoctor] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [queueDate, setQueueDate] = useState(new Date().toISOString().split('T')[0]);
  const [saving, setSaving] = useState(false);
  const [bookingMode, setBookingMode] = useState('existing');
  const [walkInForm, setWalkInForm] = useState(initialWalkIn);
  const [walkInCredential, setWalkInCredential] = useState(null);
  const [rescheduleTarget, setRescheduleTarget] = useState(null);
  const [rescheduleForm, setRescheduleForm] = useState({ date: '', slot: '' });

  const loadPatients = async (query = '') => {
    try {
      const response = await receptionistApi.searchPatients(query);
      setPatients(response.patients || []);
    } catch {
      setPatients([]);
    }
  };

  const loadOptions = async () => {
    try {
      const response = await receptionistApi.getBookingOptions({
        departmentId: booking.departmentId || undefined,
      });
      setOptions(response);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load booking options.');
    }
  };

  const loadQueue = async () => {
    try {
      const response = await appointmentApi.getQueueToday({
        date: queueDate,
        doctorId: filterDoctor || undefined,
        status: filterStatus || undefined,
      });
      setQueue(response.appointments || []);
      setQueueSummary(response.summary || null);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to load today queue.');
    }
  };

  useEffect(() => {
    loadPatients(preselectedPatientId || patientQuery);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (preselectedPatientId && !patientQuery.trim()) {
        return;
      }
      loadPatients(patientQuery);
    }, 250);
    return () => clearTimeout(timer);
  }, [patientQuery, preselectedPatientId]);

  useEffect(() => {
    loadOptions();
  }, [booking.departmentId]);

  useEffect(() => {
    loadQueue();
  }, [queueDate, filterDoctor, filterStatus]);

  useEffect(() => {
    const loadSlots = async () => {
      if (!booking.doctorId || !booking.date) {
        setAvailableSlots([]);
        setAllSlots([]);
        setBookedSlots([]);
        return;
      }

      setSlotLoading(true);
      try {
        const response = await slotApi.getByDoctor(booking.doctorId, booking.date);
        setAvailableSlots(response.availableSlots || []);
        setAllSlots(response?.allSlots || response?.availableSlots || []);
        setBookedSlots(response?.bookedSlots || []);
      } catch {
        setAvailableSlots([]);
        setAllSlots([]);
        setBookedSlots([]);
      } finally {
        setSlotLoading(false);
      }
    };

    loadSlots();
  }, [booking.doctorId, booking.date]);

  const selectedPatient = useMemo(
    () => patients.find((patient) => patient.id === booking.patientId),
    [patients, booking.patientId]
  );

  const handleBookAppointment = async (event) => {
    event.preventDefault();
    setSaving(true);
    try {
      let patientId = booking.patientId;
      if (bookingMode === 'walkIn') {
        const response = await receptionistApi.registerPatient({
          ...walkInForm,
          emergencyContact: {
            name: walkInForm.emergencyContactName,
            phone: walkInForm.emergencyContactPhone,
            relation: walkInForm.emergencyContactRelation,
          },
        });
        patientId = response.patient?.id;
        setWalkInCredential(response.temporaryCredential || null);
      }

      await appointmentApi.book({
        ...booking,
        patientId,
        visitType: bookingMode === 'walkIn' ? 'walkIn' : booking.visitType,
      });
      toast.success('Appointment booked successfully.');
      setBooking({ ...initialBooking, patientId: bookingMode === 'walkIn' ? '' : booking.patientId, date: booking.date });
      setAvailableSlots([]);
      if (bookingMode === 'walkIn') {
        setWalkInForm(initialWalkIn);
      }
      loadQueue();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to book appointment.');
    } finally {
      setSaving(false);
    }
  };

  const handleArrive = async (appointmentId) => {
    try {
      await appointmentApi.arrive(appointmentId);
      toast.success('Patient marked as arrived.');
      loadQueue();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update appointment.');
    }
  };

  const handleCancel = async (appointmentId) => {
    const reason = window.prompt('Cancellation reason (optional):', '');
    try {
      await appointmentApi.cancel(appointmentId, { reason });
      toast.success('Appointment cancelled.');
      loadQueue();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to cancel appointment.');
    }
  };

  const openReschedule = (appointment) => {
    setRescheduleTarget(appointment);
    setRescheduleForm({ date: appointment.date, slot: appointment.slot });
  };

  const handleReschedule = async (event) => {
    event.preventDefault();
    try {
      await appointmentApi.reschedule(rescheduleTarget._id, rescheduleForm);
      toast.success('Appointment rescheduled.');
      setRescheduleTarget(null);
      loadQueue();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to reschedule appointment.');
    }
  };

  const handleInitiateBilling = async (appointmentId) => {
    try {
      await billingApi.initiateForAppointment(appointmentId);
      toast.success('Consultation billing initiated.');
      loadQueue();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Unable to initiate billing.');
    }
  };

  const queueDoctors = useMemo(() => {
    const seen = new Map();
    queue.forEach((appointment) => {
      if (appointment.doctorId?._id && !seen.has(appointment.doctorId._id)) {
        seen.set(appointment.doctorId._id, appointment.doctorId.userId?.name || 'Doctor');
      }
    });
    return Array.from(seen.entries());
  }, [queue]);

  return (
    <motion.section variants={staggerContainer} initial="initial" animate="animate" className="space-y-6">
      <div className="rounded-2xl bg-card p-8 shadow-sm">
        <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Reception Desk</p>
        <h2 className="mt-2 text-3xl font-semibold text-foreground">Appointment Desk</h2>
        <p className="mt-2 max-w-3xl text-muted-foreground">
          Search existing patients, book new consultations or walk-ins, monitor today&apos;s queue, mark arrivals, reschedule visits, and initiate billing when needed.
        </p>
      </div>

      <div className="grid gap-6 xl:grid-cols-[0.95fr,1.05fr]">
        <form onSubmit={handleBookAppointment} className="rounded-2xl bg-card p-6 shadow-sm">
          <div className="flex items-center justify-between gap-3">
            <div>
              <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Book Appointment</p>
              <h3 className="mt-2 text-2xl font-semibold text-foreground">Patient-first booking flow</h3>
            </div>
            <Button type="button" variant="outline" onClick={loadOptions}>
              <RefreshCw className="mr-2 h-4 w-4" />
              Refresh
            </Button>
          </div>

          <div className="mt-5 space-y-4">
            <div className="flex flex-wrap gap-2">
              <button
                type="button"
                onClick={() => setBookingMode('existing')}
                className={`rounded-full px-4 py-2 text-xs font-semibold transition ${
                  bookingMode === 'existing'
                    ? 'bg-primary text-primary-foreground'
                    : 'border border-border bg-card text-foreground hover:bg-muted'
                }`}
              >
                Existing patient
              </button>
              <button
                type="button"
                onClick={() => setBookingMode('walkIn')}
                className={`rounded-full px-4 py-2 text-xs font-semibold transition ${
                  bookingMode === 'walkIn'
                    ? 'bg-primary text-primary-foreground'
                    : 'border border-border bg-card text-foreground hover:bg-muted'
                }`}
              >
                Walk-in patient
              </button>
            </div>

            {walkInCredential && bookingMode === 'walkIn' && (
              <div className="rounded-xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-800">
                <p className="font-semibold text-amber-900">Temporary patient credential generated</p>
                <p className="mt-1">Patient ID: <strong>{walkInCredential.patientId}</strong> | Password: <strong>{walkInCredential.temporaryPassword}</strong></p>
              </div>
            )}

            {bookingMode === 'existing' && (
              <>
                <div className="relative">
                  <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                  <input
                    type="text"
                    value={patientQuery}
                    onChange={(event) => setPatientQuery(event.target.value)}
                    placeholder="Search patient by name, patient ID, phone, or email"
                    className="w-full rounded-2xl border border-border py-3 pl-9 pr-4 text-sm outline-none focus:border-primary"
                  />
                </div>

                <Field label="Patient">
                  <select value={booking.patientId} onChange={(event) => setBooking((current) => ({ ...current, patientId: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required={bookingMode === 'existing'}>
                    <option value="">Select patient</option>
                    {patients.map((patient) => (
                      <option key={patient.id} value={patient.id}>{patient.name} ΓÇó {patient.patientId}</option>
                    ))}
                  </select>
                </Field>

                {selectedPatient && (
                  <div className="rounded-xl border border-border bg-muted/50 p-4">
                    <p className="font-semibold text-foreground">{selectedPatient.name}</p>
                    <p className="mt-1 text-sm text-muted-foreground">{selectedPatient.patientId} ΓÇó {selectedPatient.phone} ΓÇó {selectedPatient.email}</p>
                  </div>
                )}
              </>
            )}

            {bookingMode === 'walkIn' && (
              <div className="rounded-2xl border border-border p-4 space-y-4">
                <div className="grid gap-4 md:grid-cols-2">
                  <Field label="Full name">
                    <input type="text" value={walkInForm.name} onChange={(e) => setWalkInForm((c) => ({ ...c, name: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
                  </Field>
                  <Field label="Email">
                    <input type="email" value={walkInForm.email} onChange={(e) => setWalkInForm((c) => ({ ...c, email: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
                  </Field>
                  <Field label="Phone">
                    <input type="text" value={walkInForm.phone} onChange={(e) => setWalkInForm((c) => ({ ...c, phone: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
                  </Field>
                  <Field label="Date of birth">
                    <input type="date" value={walkInForm.dateOfBirth} onChange={(e) => setWalkInForm((c) => ({ ...c, dateOfBirth: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
                  </Field>
                </div>
                <Field label="Address">
                  <input type="text" value={walkInForm.address} onChange={(e) => setWalkInForm((c) => ({ ...c, address: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                </Field>
                <div className="grid gap-4 md:grid-cols-2">
                  <Field label="Emergency contact name (optional)">
                    <input type="text" value={walkInForm.emergencyContactName} onChange={(e) => setWalkInForm((c) => ({ ...c, emergencyContactName: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  </Field>
                  <Field label="Emergency contact phone (optional)">
                    <input type="text" value={walkInForm.emergencyContactPhone} onChange={(e) => setWalkInForm((c) => ({ ...c, emergencyContactPhone: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  </Field>
                  <Field label="Relation (optional)">
                    <input type="text" value={walkInForm.emergencyContactRelation} onChange={(e) => setWalkInForm((c) => ({ ...c, emergencyContactRelation: e.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
                  </Field>
                </div>
              </div>
            )}

            <div className="grid gap-4 md:grid-cols-2">
              <Field label="Department">
                <select value={booking.departmentId} onChange={(event) => setBooking((current) => ({ ...current, departmentId: event.target.value, doctorId: '', slot: '' }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required>
                  <option value="">Select department</option>
                  {(options.departments || []).map((item) => (
                    <option key={item._id} value={item._id}>{item.name}</option>
                  ))}
                </select>
              </Field>
              <Field label="Doctor">
                <select value={booking.doctorId} onChange={(event) => setBooking((current) => ({ ...current, doctorId: event.target.value, slot: '' }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required>
                  <option value="">Select doctor</option>
                  {(options.doctors || []).map((item) => (
                    <option key={item._id} value={item._id}>{item.userId?.name || 'Doctor'} ΓÇó {item.departmentId?.name || 'Department'}</option>
                  ))}
                </select>
              </Field>
              <Field label="Date">
                <input type="date" value={booking.date} onChange={(event) => setBooking((current) => ({ ...current, date: event.target.value, slot: '' }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
              </Field>
              <Field label="Visit Type">
                <select value={bookingMode === 'walkIn' ? 'walkIn' : booking.visitType} onChange={(event) => setBooking((current) => ({ ...current, visitType: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" disabled={bookingMode === 'walkIn'}>
                  <option value="newConsultation">New Consultation</option>
                  <option value="followUp">Follow-up</option>
                  <option value="walkIn">Walk-in</option>
                </select>
              </Field>
              <Field label="Consultation Mode">
                <select value={booking.consultationMode} onChange={(event) => setBooking((current) => ({ ...current, consultationMode: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary">
                  <option value="in-person">In-Person</option>
                  <option value="video">Video</option>
                  <option value="phone">Phone</option>
                </select>
              </Field>
            </div>

            <Field label="Reason for Visit">
              <textarea value={booking.reasonForVisit} onChange={(event) => setBooking((current) => ({ ...current, reasonForVisit: event.target.value }))} className="min-h-[100px] w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" />
            </Field>

            <Field label="Available Slots">
              <div className="flex flex-wrap gap-2">
                {slotLoading && <p className="text-sm text-muted-foreground">Loading slots...</p>}
                {!slotLoading && (allSlots.length ? allSlots : availableSlots).map((slot) => {
                  const isBooked = bookedSlots.includes(slot);
                  const isSelected = booking.slot === slot;
                  return (
                    <button
                      key={slot}
                      type="button"
                      disabled={isBooked}
                      onClick={() => setBooking((current) => ({ ...current, slot }))}
                      className={`rounded-full px-4 py-2 text-sm font-medium transition ${
                        isBooked
                          ? 'bg-red-500/15 text-red-500 border border-red-500/30 cursor-not-allowed'
                          : isSelected
                            ? 'bg-primary text-primary-foreground'
                            : 'border border-border bg-card text-foreground hover:bg-muted'
                      }`}
                    >
                      {slot}
                    </button>
                  );
                })}
                {!slotLoading && booking.doctorId && (allSlots.length ? allSlots : availableSlots).length === 0 && (
                  <p className="text-sm text-muted-foreground">No slots published for the selected date.</p>
                )}
              </div>
            </Field>

            <Button type="submit" disabled={saving}>
              {saving ? 'Booking...' : booking.visitType === 'walkIn' ? 'Create Walk-In' : 'Confirm Appointment'}
            </Button>
          </div>
        </form>

        <article className="rounded-2xl bg-card p-6 shadow-sm">
          <div className="flex flex-col gap-4 lg:flex-row lg:items-center lg:justify-between">
            <div>
              <p className="text-sm uppercase tracking-[0.24em] text-muted-foreground">Today&apos;s Queue</p>
              <h3 className="mt-2 text-2xl font-semibold text-foreground">Check-in and queue management</h3>
            </div>
            <div className="flex flex-wrap gap-3">
              <input type="date" value={queueDate} onChange={(event) => setQueueDate(event.target.value)} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary" />
              <select value={filterDoctor} onChange={(event) => setFilterDoctor(event.target.value)} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
                <option value="">All doctors</option>
                {queueDoctors.map(([id, name]) => (
                  <option key={id} value={id}>{name}</option>
                ))}
              </select>
              <select value={filterStatus} onChange={(event) => setFilterStatus(event.target.value)} className="rounded-2xl border border-border px-4 py-3 text-sm outline-none focus:border-primary">
                <option value="">All statuses</option>
                <option value="booked">Booked</option>
                <option value="arrived">Arrived</option>
                <option value="waiting">Waiting</option>
                <option value="completed">Completed</option>
                <option value="cancelled">Cancelled</option>
              </select>
            </div>
          </div>

          <div className="mt-5 grid gap-4 md:grid-cols-4">
            {[
              ['Total', queueSummary?.total ?? 0],
              ['Booked', queueSummary?.booked ?? 0],
              ['Arrived', queueSummary?.arrived ?? 0],
              ['Cancelled', queueSummary?.cancelled ?? 0],
            ].map(([label, value]) => (
              <article key={label} className="rounded-xl border border-border bg-muted/50 p-4">
                <p className="text-sm text-muted-foreground">{label}</p>
                <p className="mt-2 text-2xl font-semibold text-foreground">{value}</p>
              </article>
            ))}
          </div>

          <div className="mt-6 space-y-3">
            {queue.map((appointment) => (
              <article key={appointment._id} className="rounded-xl border border-border p-4">
                <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
                  <div>
                    <p className="font-semibold text-foreground">{appointment.patientId?.name}</p>
                    <p className="mt-1 text-sm text-muted-foreground">
                      {appointment.patientId?.patientId} ΓÇó {appointment.doctorId?.userId?.name || 'Doctor'} ΓÇó {appointment.slot}
                    </p>
                    <p className="mt-1 text-xs uppercase tracking-[0.16em] text-muted-foreground">{appointment.visitType}</p>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <span className="rounded-full bg-muted px-3 py-2 text-xs font-semibold uppercase tracking-[0.16em] text-foreground">
                      {appointment.status}
                    </span>
                    {appointment.status === 'booked' && (
                      <Button size="sm" onClick={() => handleArrive(appointment._id)}>Mark Arrived</Button>
                    )}
                    {appointment.status !== 'cancelled' && appointment.status !== 'completed' && (
                      <>
                        <Button size="sm" variant="outline" onClick={() => openReschedule(appointment)}>Reschedule</Button>
                        <Button size="sm" variant="destructive" onClick={() => handleCancel(appointment._id)}>Cancel</Button>
                      </>
                    )}
                    {['arrived', 'waiting', 'inConsultation', 'completed'].includes(appointment.status) && (
                      <Button size="sm" variant="outline" onClick={() => handleInitiateBilling(appointment._id)}>Initiate Bill</Button>
                    )}
                  </div>
                </div>
              </article>
            ))}
            {queue.length === 0 && <p className="text-sm text-muted-foreground">No appointments found for the selected filters.</p>}
          </div>
        </article>
      </div>

      {rescheduleTarget && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
          <form onSubmit={handleReschedule} className="w-full max-w-lg rounded-2xl bg-card p-6 shadow-2xl">
            <div className="flex items-center justify-between">
              <h3 className="text-xl font-semibold text-foreground">Reschedule Appointment</h3>
              <button type="button" onClick={() => setRescheduleTarget(null)} className="text-muted-foreground hover:text-foreground">Γ£ò</button>
            </div>
            <div className="mt-5 grid gap-4">
              <Field label="New date">
                <input type="date" value={rescheduleForm.date} onChange={(event) => setRescheduleForm((current) => ({ ...current, date: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" required />
              </Field>
              <Field label="New slot">
                <input type="text" value={rescheduleForm.slot} onChange={(event) => setRescheduleForm((current) => ({ ...current, slot: event.target.value }))} className="w-full rounded-2xl border border-border px-4 py-3 outline-none focus:border-primary" placeholder="Enter exact slot e.g. 10:00 AM" required />
              </Field>
            </div>
            <div className="mt-6 flex gap-3">
              <Button type="button" variant="outline" className="flex-1" onClick={() => setRescheduleTarget(null)}>Cancel</Button>
              <Button type="submit" className="flex-1">Save Reschedule</Button>
            </div>
          </form>
        </div>
      )}
    </motion.section>
  );
}

function Field({ children, className = '', label }) {
  return (
    <div className={className}>
      <label className="mb-2 block text-sm font-medium text-foreground">{label}</label>
      {children}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { DataTable, LoadingSkeleton, ErrorState, StatusBadge } from '../../components';
import { appointmentApi } from '../../services/apiServices';
import { toast } from 'sonner';
import { formatDate } from '../../utils/formatters';
import { Calendar, Clock, User, CheckCircle, XCircle } from 'lucide-react';
import { motion } from 'framer-motion';
import { staggerContainer, staggerItem } from '../../lib/animation-variants.js';

export default function ReceptionistAppointments() {
  const [appointments, setAppointments] = useState([]);
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState('today');

  useEffect(() => {
    fetchAppointments();
  }, []);

  const fetchAppointments = async () => {
    try {
      setLoading(true);
      setError(null);
      const allAppointments = await appointmentApi.getAll();
      const appointments = Array.isArray(allAppointments) ? allAppointments : [];
      setAppointments(appointments);
      
      // Filter today's appointments
      const today = new Date().toISOString().split('T')[0];
      const today_appointments = appointments.filter(
        (apt) => apt.date && apt.date.startsWith(today)
      );
      setTodayAppointments(today_appointments);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to fetch appointments');
      toast.error('Failed to load appointments');
    } finally {
      setLoading(false);
    }
  };

  const handleComplete = async (appointmentId) => {
    try {
      await appointmentApi.complete(appointmentId);
      toast.success('Appointment marked as completed');
      fetchAppointments();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to complete appointment');
    }
  };

  const handleCancel = async (appointmentId) => {
    try {
      await appointmentApi.cancel(appointmentId);
      toast.success('Appointment cancelled');
      fetchAppointments();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to cancel appointment');
    }
  };

  const displayAppointments = activeTab === 'today' ? todayAppointments : appointments;

  const columns = [
    {
      key: 'time',
      label: 'Time',
      sortable: true,
      render: (time) => <span className="font-mono">{time}</span>,
    },
    {
      key: 'patientId',
      label: 'Patient',
      sortable: true,
      render: (patient) => (
        <div>
          <p className="font-medium">{patient?.userId?.name || 'N/A'}</p>
          <p className="text-xs text-muted-foreground">{patient?.userId?.phone || 'N/A'}</p>
        </div>
      ),
    },
    {
      key: 'doctorId',
      label: 'Doctor',
      render: (doctor) => doctor?.userId?.name || 'N/A',
    },
    {
      key: 'date',
      label: 'Date',
      sortable: true,
      render: (date) => formatDate(date),
    },
    {
      key: 'status',
      label: 'Status',
      render: (status) => <StatusBadge status={status} />,
    },
    {
      key: '_id',
      label: 'Actions',
      render: (_, row) => (
        <div className="flex gap-2">
          {(row.status === 'Scheduled' || row.status === 'Confirmed') && (
            <>
              <Button
                size="sm"
                variant="default"
                onClick={() => handleComplete(row._id)}
                className="text-xs"
              >
                <CheckCircle className="h-4 w-4 mr-1" /> Check-in
              </Button>
              <Button
                size="sm"
                variant="destructive"
                onClick={() => handleCancel(row._id)}
                className="text-xs"
              >
                <XCircle className="h-4 w-4 mr-1" /> Cancel
              </Button>
            </>
          )}
        </div>
      ),
    },
  ];

  if (loading) return <LoadingSkeleton />;

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-3xl font-bold tracking-tight">Appointments Queue</h2>
        <p className="text-muted-foreground">Manage appointments and patient check-ins</p>
      </div>

      {error && <ErrorState error={error} />}

      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Calendar className="h-4 w-4" /> Today
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{todayAppointments.length}</div>
            <p className="text-xs text-muted-foreground mt-1">scheduled</p>
          </CardContent>
        </Card>

        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Clock className="h-4 w-4" /> Pending
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {todayAppointments.filter((a) => a.status === 'Scheduled').length}
            </div>
            <p className="text-xs text-muted-foreground mt-1">awaiting check-in</p>
          </CardContent>
        </Card>

        <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <CheckCircle className="h-4 w-4" /> Total
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{appointments.length}</div>
            <p className="text-xs text-muted-foreground mt-1">all appointments</p>
          </CardContent>
        </Card>
      </div>

      <div className="flex gap-2 border-b border-border/50">
        <Button
          variant={activeTab === 'today' ? 'default' : 'ghost'}
          onClick={() => setActiveTab('today')}
          className="rounded-none border-b-2"
        >
          <Calendar className="h-4 w-4 mr-2" /> Today ({todayAppointments.length})
        </Button>
        <Button
          variant={activeTab === 'all' ? 'default' : 'ghost'}
          onClick={() => setActiveTab('all')}
          className="rounded-none border-b-2"
        >
          All Appointments ({appointments.length})
        </Button>
      </div>

      {/* Appointments Table */}
      <Card className="border-border/50 bg-background/50 backdrop-blur-sm">
        <CardHeader>
          <CardTitle>
            {activeTab === 'today' ? "Today's Queue" : 'All Appointments'}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {displayAppointments.length === 0 ? (
            <p className="text-muted-foreground text-center py-8">
              No appointments found.
            </p>
          ) : (
            <DataTable
              data={displayAppointments}
              columns={columns}
              searchPlaceholder="Search appointments..."
              searchKey="patientId"
            />
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import { useEffect, useState } from 'react';
